import { useState, useEffect, useRef } from "react";
import { 
  X, 
  Send, 
  Sparkles, 
  Bot, 
  TrendingUp, 
  AlertCircle, 
  Users,
  BarChart3
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { useAI } from "@/hooks/useAI";
import type { ChatMessage } from "@/hooks/useAI";

interface AIChatPanelProps {
  isOpen: boolean;
  onClose: () => void;
}

const QUICK_COMMANDS = [
  { label: "📊 Riepilogo mese", icon: BarChart3, query: "Genera un riepilogo dell'ultimo mese" },
  { label: "⚠️ Alert critici", icon: AlertCircle, query: "Quali sono gli alert critici o i clienti a rischio?" },
  { label: "💰 Top clienti", icon: Users, query: "Mostrami i top 5 clienti per fatturato" },
  { label: "📈 Trend fatturato", icon: TrendingUp, query: "Come sta andando il trend del fatturato?" },
];

export function AIChatPanel({ isOpen, onClose }: AIChatPanelProps) {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState("");
  const scrollRef = useRef<HTMLDivElement>(null);
  const aiMutation = useAI();

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, aiMutation.isPending]);

  const handleSend = async (text: string = input) => {
    if (!text.trim() || aiMutation.isPending) return;

    const userMessage: ChatMessage = {
      role: "user",
      content: text,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput("");

    try {
      const response = await aiMutation.mutateAsync(text);
      const assistantMessage: ChatMessage = {
        role: "assistant",
        content: response,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, assistantMessage]);
    } catch (error) {
      const errorMessage: ChatMessage = {
        role: "assistant",
        content: "Scusa, ho riscontrato un errore nel connettermi al mio cervello AI. Riprova più tardi.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMessage]);
    }
  };

  if (!isOpen) return null;

  return (
    <div className={`
      fixed top-4 right-4 h-[calc(100vh-2rem)] w-[400px] bg-card/80 backdrop-blur-xl border border-white/5 
      shadow-[0_20px_50px_rgba(0,0,0,0.5)] z-[100] flex flex-col rounded-3xl animate-in slide-in-from-right duration-500 ease-out
    `}>
      {/* Header */}
      <div className="p-6 border-b border-border/30 flex items-center justify-between bg-white/5 backdrop-blur-md sticky top-0 z-10 rounded-t-3xl">
        <div className="flex items-center gap-3">
          <div className="h-10 w-10 rounded-xl bg-primary flex items-center justify-center shadow-[0_0_20px_hsl(var(--primary)/0.2)]">
            <Sparkles className="h-6 w-6 text-white" />
          </div>
          <div>
            <h3 className="text-sm font-black text-white uppercase tracking-tighter">Bite AI Assistant</h3>
            <div className="flex items-center gap-1.5">
              <span className="h-1.5 w-1.5 rounded-full bg-emerald-500 animate-pulse" />
              <span className="text-[10px] text-muted-foreground font-bold uppercase tracking-widest">Online</span>
            </div>
          </div>
        </div>
        <Button variant="ghost" size="icon" onClick={onClose} className="rounded-full hover:bg-muted text-[#475569] hover:text-white">
          <X className="h-5 w-5" />
        </Button>
      </div>

      {/* Messages Area */}
      <ScrollArea className="flex-1 p-4" ref={scrollRef}>
        <div className="space-y-6 pb-20">
          {messages.length === 0 && (
            <div className="flex flex-col items-center justify-center py-12 text-center space-y-4">
              <div className="h-16 w-16 rounded-3xl bg-background border border-border flex items-center justify-center text-[#1e293b]">
                <Bot className="h-10 w-10" />
              </div>
              <div className="space-y-1">
                <h4 className="text-sm font-bold text-white">Ciao! Sono Bite AI</h4>
                <p className="text-xs text-muted-foreground max-w-[250px]"> Chiedimi pure riepiloghi, analisi sui dati dell'agenzia o alert critici.</p>
              </div>
            </div>
          )}

          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`
                max-w-[85%] p-4 rounded-2xl text-xs leading-relaxed shadow-lg
                ${m.role === 'user' 
                  ? 'bg-primary text-white font-medium rounded-tr-none' 
                  : 'bg-muted text-foreground border border-border/30 rounded-tl-none font-medium'
                }
              `}>
                {m.content}
                <div className={`mt-2 text-[8px] opacity-40 uppercase font-black tracking-widest ${m.role === 'user' ? 'text-right' : 'text-left'}`}>
                  {m.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          ))}

          {aiMutation.isPending && (
            <div className="flex justify-start">
              <div className="bg-muted border border-border/30 p-4 rounded-2xl rounded-tl-none">
                <div className="flex gap-1">
                  <span className="h-1.5 w-1.5 bg-primary/40 rounded-full animate-bounce [animation-delay:-0.3s]" />
                  <span className="h-1.5 w-1.5 bg-primary/60 rounded-full animate-bounce [animation-delay:-0.15s]" />
                  <span className="h-1.5 w-1.5 bg-primary/80 rounded-full animate-bounce" />
                </div>
              </div>
            </div>
          )}
        </div>
      </ScrollArea>

      {/* Quick Commands & Input */}
      <div className="p-4 border-t border-border bg-background/50 space-y-4">
        {/* Quick Commands */}
        <div className="flex gap-2 overflow-x-auto pb-2 custom-scrollbar no-scrollbar">
          {QUICK_COMMANDS.map((cmd) => (
            <Button 
              key={cmd.label}
              variant="outline"
              size="sm"
              onClick={() => handleSend(cmd.query)}
              className="h-8 shrink-0 rounded-lg border-border bg-card px-3 text-[10px] font-black uppercase tracking-widest text-muted-foreground hover:bg-primary/10 hover:text-primary hover:border-primary/30 transition-all"
            >
              <cmd.icon className="h-3 w-3 mr-2" />
              {cmd.label}
            </Button>
          ))}
        </div>

        <div className="flex items-center gap-2 relative">
          <Input 
            placeholder="Chiedi all'AI..." 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={aiMutation.isPending}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            className="h-12 bg-background border-border rounded-xl pr-12 focus-visible:ring-primary/40 text-sm font-medium"
          />
          <Button 
            size="icon" 
            onClick={() => handleSend()}
            disabled={!input.trim() || aiMutation.isPending}
            className={`
              absolute right-1 w-10 h-10 rounded-lg shadow-xl transition-all
              ${input.trim() ? "bg-primary text-white scale-100" : "bg-transparent text-[#1e293b] scale-90"}
            `}
          >
            <Send className="h-4 w-4" />
          </Button>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useMemo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { 
  Calculator, 
  Users, 
  Clock, 
  TrendingUp, 
  DollarSign, 
  ArrowRight,
  Info,
  RefreshCcw,
  Percent
} from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { 
  Select, 
  SelectContent, 
  SelectItem, 
  SelectTrigger, 
  SelectValue 
} from "@/components/ui/select";
import { Button } from "@/components/ui/button";
import { useRisorse } from "@/hooks/useRisorse";
import { Slider } from "@/components/ui/slider";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import { Badge } from "@/components/ui/badge";

export function CollaboratorCostCalculator() {
  const { data: risorse, isLoading } = useRisorse();
  const [selectedRisorsaId, setSelectedRisorsaId] = useState<string>("");
  const [hours, setHours] = useState<number>(8);
  const [margin, setMargin] = useState<number>(30);
  const [customHourlyRate, setCustomHourlyRate] = useState<number>(50);

  const selectedRisorsa = useMemo(() => 
    risorse?.find(r => r.id === selectedRisorsaId), 
    [risorse, selectedRisorsaId]
  );

  const hourlyRate = selectedRisorsa ? selectedRisorsa.costo_orario_effettivo : customHourlyRate;
  
  const results = useMemo(() => {
    const cost = hourlyRate * hours;
    const price = cost / (1 - margin / 100);
    const profit = price - cost;
    
    return {
      totalCost: cost,
      suggestedPrice: price,
      profit: profit,
      hourlyRate
    };
  }, [hourlyRate, hours, margin]);

  const handleReset = () => {
    setSelectedRisorsaId("");
    setHours(8);
    setMargin(30);
    setCustomHourlyRate(50);
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat("it-IT", { style: "currency", currency: "EUR" }).format(val);

  return (
    <Card className="border-none bg-gradient-to-br from-background/40 to-background/10 backdrop-blur-xl shadow-2xl relative overflow-hidden group">
      {/* Decorative gradients */}
      <div className="absolute -top-24 -right-24 w-64 h-64 bg-primary/10 rounded-full blur-3xl group-hover:bg-primary/20 transition-colors duration-500" />
      <div className="absolute -bottom-24 -left-24 w-64 h-64 bg-blue-500/10 rounded-full blur-3xl group-hover:bg-blue-500/20 transition-colors duration-500" />
      
      <CardHeader className="relative z-10 border-b border-white/5">
        <div className="flex items-center justify-between">
          <div className="space-y-1">
            <div className="flex items-center gap-2">
              <div className="p-2 bg-primary/20 rounded-lg">
                <Calculator className="w-5 h-5 text-primary" />
              </div>
              <CardTitle className="text-2xl font-bold tracking-tight">Price & Margin Calculator</CardTitle>
            </div>
            <CardDescription className="text-muted-foreground/80">
              Calcola il preventivo ideale basato sul costo reale dei tuoi collaboratori.
            </CardDescription>
          </div>
          <Button variant="ghost" size="icon" onClick={handleReset} className="hover:bg-white/5">
            <RefreshCcw className="w-4 h-4" />
          </Button>
        </div>
      </CardHeader>

      <CardContent className="p-8 relative z-10">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
          {/* Input Section */}
          <div className="space-y-8">
            <div className="space-y-4">
              <Label className="text-sm font-semibold uppercase tracking-wider text-muted-foreground flex items-center gap-2">
                <Users className="w-4 h-4" /> Collaboratore
              </Label>
              <Select value={selectedRisorsaId} onValueChange={setSelectedRisorsaId}>
                <SelectTrigger className="h-12 bg-white/5 border-white/10 text-lg">
                  <SelectValue placeholder="Seleziona un collaboratore..." />
                </SelectTrigger>
                <SelectContent className="bg-slate-900 border-white/10 text-white">
                  <SelectItem value="manual" className="cursor-pointer">Rate Manuale</SelectItem>
                  {risorse?.filter(r => r.attivo).map(r => (
                    <SelectItem key={r.id} value={r.id} className="cursor-pointer">
                      {r.nome} {r.cognome} <span className="text-xs text-muted-foreground ml-2">({r.ruolo})</span>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {(!selectedRisorsaId || selectedRisorsaId === "manual") && (
              <motion.div 
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: "auto" }}
                className="space-y-4"
              >
                <Label className="text-sm font-semibold text-muted-foreground flex items-center gap-2">
                  <DollarSign className="w-4 h-4" /> Costo Orario Lordo (€/h)
                </Label>
                <div className="flex gap-4 items-center">
                  <Input 
                    type="number" 
                    value={customHourlyRate} 
                    onChange={(e) => setCustomHourlyRate(Number(e.target.value))}
                    className="h-12 bg-white/5 border-white/10 text-xl font-medium"
                  />
                  <span className="text-muted-foreground">€/ora</span>
                </div>
              </motion.div>
            )}

            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <Label className="text-sm font-semibold text-muted-foreground flex items-center gap-2">
                  <Clock className="w-4 h-4" /> Ore Stimate
                </Label>
                <span className="text-xl font-bold text-primary">{hours}h</span>
              </div>
              <Slider 
                value={[hours]} 
                onValueChange={([val]: number[]) => setHours(val)} 
                max={200} 
                step={0.5}
                className="py-4"
              />
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <Label className="text-sm font-semibold text-muted-foreground flex items-center gap-2">
                  <TrendingUp className="w-4 h-4" /> Margine Desiderato (%)
                </Label>
                <Badge variant={margin >= 30 ? "default" : "secondary"} className={`text-sm ${margin >= 30 ? 'bg-emerald-500 hover:bg-emerald-600' : ''}`}>
                  {margin >= 30 ? "Alta Redditività" : "Margine Standard"}
                </Badge>
              </div>
              <div className="flex gap-6 items-center">
                <Slider 
                  value={[margin]} 
                  onValueChange={([val]: number[]) => setMargin(val)} 
                  max={90} 
                  min={1} 
                  step={1}
                  className="flex-1 py-4"
                />
                <div className="w-20 relative">
                  <Input 
                    type="number" 
                    value={margin} 
                    onChange={(e) => setMargin(Number(e.target.value))}
                    className="h-10 bg-white/5 border-white/10 text-right pr-6 font-bold"
                  />
                  <Percent className="w-3 h-3 absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground" />
                </div>
              </div>
            </div>
          </div>

          {/* Results Section */}
          <div className="flex flex-col justify-center">
            <AnimatePresence mode="wait">
              <motion.div 
                key={`${selectedRisorsaId}-${hours}-${margin}`}
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                className="space-y-6"
              >
                <div className="p-8 rounded-3xl bg-white/5 border border-white/10 relative overflow-hidden group/result">
                  <div className="absolute top-0 right-0 p-4 opacity-10 group-hover/result:opacity-20 transition-opacity">
                    <TrendingUp className="w-24 h-24" />
                  </div>
                  
                  <div className="space-y-6 relative z-10">
                    <div>
                      <p className="text-sm text-muted-foreground font-medium uppercase tracking-widest mb-1">Prezzo Suggerito</p>
                      <h2 className="text-6xl font-black text-white tracking-tighter">
                        {formatCurrency(results.suggestedPrice)}
                      </h2>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-1 p-4 rounded-2xl bg-white/5 border border-white/5">
                        <p className="text-xs text-muted-foreground uppercase font-bold">Costo Totale</p>
                        <p className="text-xl font-bold text-rose-400">{formatCurrency(results.totalCost)}</p>
                      </div>
                      <div className="space-y-1 p-4 rounded-2xl bg-white/5 border border-white/5">
                        <p className="text-xs text-muted-foreground uppercase font-bold">Utile Previsto</p>
                        <p className="text-xl font-bold text-emerald-400">+{formatCurrency(results.profit)}</p>
                      </div>
                    </div>

                    <div className="flex items-center gap-2 pt-4 border-t border-white/5">
                      <TooltipProvider>
                        <Tooltip>
                          <TooltipTrigger className="flex items-center gap-2 text-sm text-muted-foreground hover:text-white transition-colors">
                            <Info className="w-4 h-4" /> 
                            <span>Logic Details</span>
                          </TooltipTrigger>
                          <TooltipContent className="max-w-xs space-y-2 p-4">
                            <p className="font-bold">Come calcoliamo i costi?</p>
                            <p className="text-xs opacity-80">
                              Il costo orario utilizzato ({formatCurrency(results.hourlyRate)}/h) include RAL, contributi INPS/INAIL, TFR e una quota overhead del 30% per i costi di struttura.
                            </p>
                            <p className="text-xs opacity-80 pt-2 border-t border-white/10">
                              Formula: <code className="bg-white/10 p-0.5 rounded">Costo / (1 - Margine%)</code>
                            </p>
                          </TooltipContent>
                        </Tooltip>
                      </TooltipProvider>
                    </div>
                  </div>
                </div>

                <div className="flex items-center gap-4 p-4 rounded-2xl bg-amber-500/10 border border-amber-500/20">
                  <Badge className="bg-amber-500/20 text-amber-500 border-none">Pro Tip</Badge>
                  <p className="text-sm text-amber-200/80 leading-relaxed italic">
                    Per questo tipo di {selectedRisorsa?.ruolo || "lavoro"}, un margine del 35% è consigliato per coprire imprevisti e variazioni di scope.
                  </p>
                </div>
              </motion.div>
            </AnimatePresence>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

import { useEffect, useRef, useState } from "react";
import { Area, AreaChart, CartesianGrid, Legend, Tooltip, XAxis, YAxis } from "recharts";
import { format, parseISO } from "date-fns";
import { it } from "date-fns/locale";
import { Target, Banknote, RefreshCw } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { useForecast } from "@/hooks/useForecast";

const formatEuro = (value: number) =>
  new Intl.NumberFormat("it-IT", {
    style: "currency",
    currency: "EUR",
    maximumFractionDigits: 0,
  }).format(value);

function useChartWidth() {
  const ref = useRef<HTMLDivElement>(null);
  const [width, setWidth] = useState(0);

  useEffect(() => {
    const element = ref.current;
    if (!element) return;

    const resizeObserver = new ResizeObserver(([entry]) => setWidth(entry.contentRect.width));
    resizeObserver.observe(element);
    return () => resizeObserver.disconnect();
  }, []);

  return [ref, width] as const;
}

const CustomTooltip = ({ active, payload, label }: any) => {
  if (!active || !payload?.length) return null;

  return (
    <div className="app-panel-strong space-y-1.5 rounded-xl p-3 text-xs">
      <p className="text-[10px] font-black uppercase tracking-widest text-foreground">{label}</p>
      {payload.map((entry: any) => (
        <div key={entry.dataKey} className="flex items-center justify-between gap-4">
          <div className="flex items-center gap-1.5">
            <div className="h-2 w-2 rounded-full" style={{ backgroundColor: entry.color }} />
            <span className="text-muted-strong">{entry.name}</span>
          </div>
          <span className="font-black text-foreground">{formatEuro(entry.value)}</span>
        </div>
      ))}
    </div>
  );
};

export function ForecastWidget() {
  const { data, isLoading, refetch } = useForecast(3);
  const [chartRef, chartWidth] = useChartWidth();

  const chartData = (data?.mesi || []).map((month) => ({
    mese: format(parseISO(month.mese), "MMM yy", { locale: it }),
    Certi: month.ricavo_certo,
    "Pipeline CRM": month.ricavo_pipeline_crm,
    Storico: month.ricavo_storico,
  }));

  const allTopLeads = (data?.mesi || [])
    .flatMap((month) => month.top_lead)
    .sort((a, b) => b.valore_pesato - a.valore_pesato)
    .slice(0, 3);

  return (
    <Card className="app-panel overflow-hidden">
      <CardHeader className="pb-2">
        <div className="flex items-center justify-between">
          <CardTitle className="text-sm font-black uppercase tracking-widest text-soft">
            Forecast Ricavi - 3 Mesi
          </CardTitle>
          <button
            onClick={() => refetch()}
            className="rounded-lg p-1.5 text-muted-strong transition-colors hover:bg-accent hover:text-foreground"
          >
            <RefreshCw className="h-3.5 w-3.5" />
          </button>
        </div>
      </CardHeader>

      <CardContent className="space-y-6">
        <div className="grid grid-cols-3 gap-3">
          <div className="rounded-xl border border-emerald-500/24 bg-emerald-500/8 p-3 text-center shadow-[inset_0_1px_0_hsl(var(--foreground)/0.03)]">
            <p className="mb-1 text-[9px] font-black uppercase tracking-widest text-faint">Certi</p>
            <p className="text-lg font-black text-emerald-400">
              {isLoading ? "--" : formatEuro(data?.kpi.ricavi_certi ?? 0)}
            </p>
          </div>
          <div className="rounded-xl border border-purple-500/24 bg-purple-500/8 p-3 text-center shadow-[inset_0_1px_0_hsl(var(--foreground)/0.03)]">
            <p className="mb-1 text-[9px] font-black uppercase tracking-widest text-faint">
              Pipeline CRM
            </p>
            <p className="text-lg font-black text-purple-400">
              {isLoading ? "--" : formatEuro(data?.kpi.pipeline_crm ?? 0)}
            </p>
          </div>
          <div className="rounded-xl border border-border/90 bg-muted/36 p-3 text-center shadow-[inset_0_1px_0_hsl(var(--foreground)/0.03)]">
            <p className="mb-1 text-[9px] font-black uppercase tracking-widest text-faint">
              Totale Previsto
            </p>
            <p className="text-lg font-black text-foreground">
              {isLoading ? "--" : formatEuro(data?.kpi.totale_previsto ?? 0)}
            </p>
          </div>
        </div>

        <div ref={chartRef} className="w-full">
          {chartWidth > 0 && !isLoading && chartData.length > 0 && (
            <AreaChart
              width={chartWidth}
              height={200}
              data={chartData}
              margin={{ top: 4, right: 4, left: 0, bottom: 0 }}
            >
              <defs>
                <linearGradient id="gradCerti" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#10b981" stopOpacity={0.3} />
                  <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
                </linearGradient>
                <linearGradient id="gradPipeline" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#7c3aed" stopOpacity={0.25} />
                  <stop offset="95%" stopColor="#7c3aed" stopOpacity={0} />
                </linearGradient>
                <linearGradient id="gradStorico" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#94a3b8" stopOpacity={0.22} />
                  <stop offset="95%" stopColor="#94a3b8" stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid
                strokeDasharray="3 3"
                stroke="hsl(var(--border) / 0.55)"
                vertical={false}
              />
              <XAxis
                dataKey="mese"
                tick={{ fill: "hsl(var(--foreground-faint))", fontSize: 10, fontWeight: 800 }}
                axisLine={false}
                tickLine={false}
              />
              <YAxis
                tick={{
                  fill: "hsl(var(--foreground-faint))",
                  fontSize: 10,
                  fontWeight: 700,
                }}
                axisLine={false}
                tickLine={false}
                tickFormatter={(value) => `EUR ${(value / 1000).toFixed(0)}k`}
                width={58}
              />
              <Tooltip content={<CustomTooltip />} />
              <Legend
                wrapperStyle={{ fontSize: 10, fontWeight: 800, paddingTop: 8 }}
