                      variant="outline"
                      className="border-purple-500/24 bg-purple-500/8 text-[9px] font-black text-purple-400"
                    >
                      {lead.probabilita}%
                    </Badge>
                    <span className="text-xs font-black text-foreground">
                      {formatEuro(lead.valore_pesato)}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

import { useState } from "react";
