import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import axios from "@/lib/api";
import { useAuth } from "@/hooks/useAuth";
import { useChat } from "@/hooks/useChat";
import { cn } from "@/lib/utils";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  X,
  Users,
  UserPlus,
  UserMinus,
  Shield,
  Crown,
  Info,
  Hash,
  Check,
  FileImage,
  FileIcon,
  Download
} from "lucide-react";

interface Member {
  user_id: string;
  ruolo: string;
  user?: { id: string; nome: string; cognome: string; ruolo: string; avatar_url?: string };
}

interface Channel {
  id: string;
  nome: string;
  tipo: string;
  descrizione?: string;
  logo_url?: string;
  membri?: Member[];
  created_at?: string;
}

interface ChatGroupInfoPanelProps {
  channel: Channel;
  isOpen: boolean;
  onClose: () => void;
}

export function ChatGroupInfoPanel({ channel, isOpen, onClose }: ChatGroupInfoPanelProps) {
  const { user } = useAuth();
  const { messages } = useChat();
  const isAdmin = (user as any)?.ruolo === "ADMIN";
  const queryClient = useQueryClient();
  const [addingMode, setAddingMode] = useState(false);
  const [selectedToAdd, setSelectedToAdd] = useState<Set<string>>(new Set());

  // Extract attachments from messages
  const attachments = (messages || []).filter(m => 
    m.contenuto.startsWith("/api/v1/uploads/") || m.contenuto.startsWith("/static/uploads/")
  );

  // All users available to add
  const { data: allUsers } = useQuery({
    queryKey: ["chat-users"],
    queryFn: async () => {
      const res = await axios.get("/chat/users");
      return res.data;
    },
    enabled: isOpen && addingMode,
  });

  const currentMemberIds = new Set(
    (channel.membri || []).map((m) => m.user_id)
  );

  const availableToAdd = (allUsers || []).filter(
    (u: any) => !currentMemberIds.has(u.id)
  );

  // Add members mutation
  const addMembersMutation = useMutation({
    mutationFn: async (userIds: string[]) => {
      await axios.post(
        `/chat/channels/${channel.id}/members?action=add`,
        userIds
      );
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["chat-channels"] });
      setAddingMode(false);
      setSelectedToAdd(new Set());
    },
  });

  // Remove member mutation
  const removeMemberMutation = useMutation({
    mutationFn: async (userId: string) => {
      await axios.post(
        `/chat/channels/${channel.id}/members?action=remove`,
        [userId]
      );
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["chat-channels"] });
    },
  });

  const toggleSelectAdd = (uid: string) => {
    setSelectedToAdd((prev) => {
      const next = new Set(prev);
      next.has(uid) ? next.delete(uid) : next.add(uid);
      return next;
    });
  };

  const tipoLabel: Record<string, string> = {
    GENERAL: "Chat Generale",
    PROJECT: "Chat Progetto",
    GROUP: "Gruppo",
    DIRECT: "Chat Diretta",
  };

  const downloadAttachment = async (path: string, filename: string) => {
    if (path.startsWith("/api/v1/uploads/")) {
      const response = await axios.get(path, { responseType: "blob" });
      const objectUrl = URL.createObjectURL(response.data);
      const anchor = document.createElement("a");
      anchor.href = objectUrl;
      anchor.download = filename;
      document.body.appendChild(anchor);
      anchor.click();
      document.body.removeChild(anchor);
      URL.revokeObjectURL(objectUrl);
    } else {
      window.open(path, "_blank");
    }
  };

  return (
    <div
      className={cn(
        "absolute right-0 top-0 bottom-0 z-30 flex flex-col bg-card border-l border-border/40 shadow-2xl backdrop-blur-xl transition-all duration-300 ease-in-out overflow-hidden",
        isOpen ? "w-80 opacity-100" : "w-0 opacity-0 pointer-events-none"
      )}
    >
      {/* Header */}
      <div className="px-5 py-4 border-b border-border/30 flex items-center justify-between bg-muted/20">
        <div className="flex items-center gap-2">
          <Info size={16} className="text-primary" />
          <span className="text-xs font-black uppercase tracking-[0.25em] text-foreground">
            Info Gruppo
          </span>
        </div>
        <Button
          variant="ghost"
          size="icon"
          className="h-8 w-8 rounded-xl hover:bg-muted text-muted-foreground"
          onClick={onClose}
        >
          <X size={16} />
        </Button>
      </div>

      <ScrollArea className="flex-1">
        <div className="p-5 space-y-8 pb-10">
          {/* Channel Identity */}
          <div className="flex flex-col items-center gap-3 py-2">
            <div className="w-20 h-20 rounded-2xl bg-primary/10 flex items-center justify-center shadow-inner border border-primary/20 text-3xl font-black text-primary">
              {channel.logo_url ? (
                <img
                  src={channel.logo_url}
                  alt=""
                  className="w-full h-full object-cover rounded-2xl"
                />
              ) : (
                channel.tipo === "DIRECT" ? (
                  <Users size={32} className="text-primary opacity-60" />
                ) : (
                  channel.nome?.[0]?.toUpperCase() || "#"
                )
              )}
            </div>
            <div className="text-center">
              <h3 className="font-black text-base uppercase tracking-widest text-foreground">
                {channel.nome}
              </h3>
              <span className="inline-flex items-center gap-1.5 text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground mt-1">
                <Hash size={10} />
                {tipoLabel[channel.tipo] || channel.tipo}
              </span>
            </div>
          </div>

          {channel.descrizione && (
            <div className="p-3 bg-muted/30 rounded-2xl border border-border/30">
              <p className="text-xs text-muted-foreground leading-relaxed">
                {channel.descrizione}
              </p>
            </div>
          )}

          {/* Members Section */}
          {channel.tipo !== "DIRECT" && (
            <div>
              <div className="flex items-center justify-between mb-3 border-b border-border/20 pb-2">
                <div className="flex items-center gap-2">
                  <Users size={14} className="text-primary" />
                  <span className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground">
                    Membri · {(channel.membri || []).length}
                  </span>
                </div>
                {isAdmin && !addingMode && (
                  <Button
                    variant="ghost"
                    size="sm"
                    className="h-7 px-2 text-[10px] font-black uppercase tracking-widest text-primary hover:bg-primary/10 rounded-xl"
                    onClick={() => setAddingMode(true)}
                  >
                    <UserPlus size={12} className="mr-1" />
                    Aggiungi
                  </Button>
                )}
              </div>

              {/* Add members mode */}
              {addingMode && isAdmin && (
                <div className="mb-4 bg-muted/20 border border-border/30 rounded-2xl overflow-hidden mt-3">
                  <div className="p-3 border-b border-border/20 flex items-center justify-between">
                    <span className="text-[10px] font-black uppercase tracking-widest text-primary">
                      Seleziona utenti
                    </span>
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-6 w-6 rounded-lg"
                      onClick={() => {
                        setAddingMode(false);
                        setSelectedToAdd(new Set());
                      }}
                    >
                      <X size={12} />
                    </Button>
                  </div>

                  <div className="max-h-48 overflow-y-auto">
                    {availableToAdd.length === 0 ? (
                      <p className="text-[10px] text-muted-foreground text-center py-4 uppercase font-black tracking-widest">
                        Tutti gli utenti sono già nel gruppo
                      </p>
                    ) : (
                      availableToAdd.map((u: any) => (
                        <button
                          key={u.id}
                          onClick={() => toggleSelectAdd(u.id)}
                          className={cn(
                            "w-full flex items-center gap-3 px-3 py-2.5 text-sm transition-all hover:bg-primary/5",
                            selectedToAdd.has(u.id) && "bg-primary/10"
                          )}
                        >
                          <Avatar className="w-7 h-7 shrink-0">
                            <AvatarFallback className="text-[10px] font-black bg-primary/10 text-primary">
                              {u.nome?.[0]}{u.cognome?.[0]}
                            </AvatarFallback>
                          </Avatar>
                          <span className="flex-1 text-left text-xs font-bold truncate">
                            {u.nome} {u.cognome}
                          </span>
                          {selectedToAdd.has(u.id) && (
                            <Check size={14} className="text-primary shrink-0" />
                          )}
                        </button>
                      ))
                    )}
                  </div>

                  {selectedToAdd.size > 0 && (
                    <div className="p-3 border-t border-border/20">
                      <Button
                        className="w-full h-9 text-xs font-black uppercase tracking-widest rounded-xl bg-primary hover:bg-primary/90 text-white"
                        onClick={() =>
                          addMembersMutation.mutate(Array.from(selectedToAdd))
                        }
                        disabled={addMembersMutation.isPending}
                      >
                        <UserPlus size={13} className="mr-1.5" />
                        Aggiungi {selectedToAdd.size} utent{selectedToAdd.size === 1 ? "e" : "i"}
                      </Button>
                    </div>
                  )}
                </div>
              )}

              {/* Members list */}
              <div className="space-y-1 mt-3">
                {(channel.membri || []).map((member) => {
                  const u = member.user;
                  const isOwner = member.ruolo === "ADMIN";
                  const isSelf = u?.id === (user as any)?.id;

                  return (
                    <div
                      key={member.user_id}
                      className="flex items-center gap-3 p-2.5 rounded-xl hover:bg-muted/30 group/member transition-all"
                    >
                      <div className="relative shrink-0">
                        <Avatar className="w-8 h-8">
                          {u?.avatar_url ? (
                            <img
                              src={u.avatar_url}
                              alt=""
                              className="w-full h-full object-cover rounded-full"
                            />
                          ) : (
                            <AvatarFallback className="text-[10px] font-black bg-primary/10 text-primary">
                              {u?.nome?.[0]}{u?.cognome?.[0]}
                            </AvatarFallback>
                          )}
                        </Avatar>
                        {isOwner && (
                          <Crown
                            size={10}
                            className="absolute -top-1 -right-1 text-yellow-400 fill-yellow-400"
                          />
                        )}
                      </div>

                      <div className="flex-1 min-w-0">
                        <p className="text-xs font-bold truncate">
                          {u?.nome} {u?.cognome}
                          {isSelf && (
                            <span className="ml-1 text-[9px] text-primary font-black uppercase">
                              (Tu)
                            </span>
                          )}
                        </p>
                        <p className="text-[9px] font-black uppercase tracking-widest text-muted-foreground/60 flex items-center gap-1">
                          {u?.ruolo === "ADMIN" ? (
                            <>
                              <Shield size={8} className="text-violet-400" />
                              Admin
                            </>
                          ) : (
                            u?.ruolo?.toLowerCase()
                          )}
                        </p>
                      </div>

                      {/* Remove button (admin only, can't remove self from general) */}
                      {isAdmin && !isSelf && channel.tipo !== "GENERAL" && (
                        <Button
                          variant="ghost"
                          size="icon"
                          className="h-7 w-7 rounded-xl opacity-0 group-hover/member:opacity-100 text-muted-foreground hover:text-destructive hover:bg-destructive/10 transition-all"
                          onClick={() => removeMemberMutation.mutate(member.user_id)}
                          disabled={removeMemberMutation.isPending}
                          title="Rimuovi dal gruppo"
                        >
                          <UserMinus size={12} />
                        </Button>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Media & Attachments Section */}
          <div>
            <div className="flex items-center gap-2 mb-3 border-b border-border/20 pb-2">
              <FileImage size={14} className="text-primary" />
              <span className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground">
                Media & Allegati · {attachments.length}
              </span>
            </div>
            {attachments.length === 0 ? (
              <p className="text-[10px] text-muted-foreground text-center py-4 uppercase font-black tracking-widest">
                Nessun allegato
              </p>
            ) : (
              <div className="space-y-2 mt-3">
                {attachments.map((m) => {
                  const filename = m.contenuto.split("/").pop() || "File allegato";
                  const isImage = /\.(jpg|jpeg|png|gif|webp)$/i.test(m.contenuto);
                  
                  return (
                    <button
                      key={m.id}
                      onClick={() => downloadAttachment(m.contenuto, filename)}
                      className="w-full flex items-center gap-3 p-2.5 rounded-xl border border-border/30 bg-muted/10 hover:bg-muted/40 transition-colors text-left group"
                    >
                      <div className="h-10 w-10 shrink-0 rounded-lg bg-primary/10 flex items-center justify-center text-primary">
                        {isImage ? <FileImage size={18} /> : <FileIcon size={18} />}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="text-xs font-bold truncate group-hover:text-primary transition-colors">{filename}</p>
                        <p className="text-[9px] font-black uppercase tracking-widest text-muted-foreground/60 mt-0.5 flex items-center gap-1">
                          Scarica file <Download size={8} />
                        </p>
                      </div>
                    </button>
                  );
                })}
              </div>
            )}
          </div>

          {/* Channel type for DIRECT chats */}
          {channel.tipo === "DIRECT" && (
            <div className="text-center py-4 opacity-40">
              <p className="text-[10px] font-black uppercase tracking-[0.25em]">
                Chat privata diretta
              </p>
            </div>
          )}
        </div>
      </ScrollArea>
    </div>
  );
}

import { useEffect, useState } from "react";
import { ChatSidebar } from "./ChatSidebar";
import { ChatConversation } from "./ChatConversation";
import { useChat } from "@/hooks/useChat";
import { useSearchParams } from "react-router-dom";
import { useStudio } from "@/hooks/useStudio";
import { Loader2 } from "lucide-react";

export function ChatHub() {
  const {
    channels,
    users,
    activeChannelId,
    setActiveChannelId,
    isLoading,
    onlineUsers,
    unreadCounts,
    startDirectChat,
    markAsSeen
  } = useChat();
  const { setView } = useStudio();
  const [searchParams, setSearchParams] = useSearchParams();
  const [category, setCategory] = useState<'all' | 'projects' | 'team'>('all');
  
  // Set global view to 'chat' for breadcrumbs
  useEffect(() => {
    setView("chat");
  }, [setView]);

  // Sync URL with global active channel state
  useEffect(() => {
    const channelFromUrl = searchParams.get("channel");
    
    // Priority 1: URL has a channel -> update global state
    if (channelFromUrl && channelFromUrl !== activeChannelId) {
      setActiveChannelId(channelFromUrl);
    } 
    // Priority 2: Global state has a channel but URL doesn't -> update URL
    else if (!channelFromUrl && activeChannelId) {
      setSearchParams({ channel: activeChannelId }, { replace: true });
    }
    // Priority 3: Neither has a channel -> default to General
    else if (!channelFromUrl && !activeChannelId && channels && channels.length > 0) {
      const general = channels.find((c: any) => c.tipo === 'GENERAL') || channels[0];
      setActiveChannelId(general.id);
      setSearchParams({ channel: general.id }, { replace: true });
    }
  }, [channels, activeChannelId, setActiveChannelId, searchParams, setSearchParams]);

  const handleSelectChannel = (id: string) => {
    setActiveChannelId(id);
    setSearchParams({ channel: id });
    markAsSeen(id);
  };

  const handleStartDirectChat = async (userId: string) => {
    const channel = await startDirectChat(userId);
    if (channel) {
      setSearchParams({ channel: channel.id });
    }
  };

  if (isLoading) {
    return (
      <div className="h-full flex items-center justify-center bg-background/20 backdrop-blur-sm">
        <div className="flex flex-col items-center gap-4">
          <Loader2 className="h-10 w-10 animate-spin text-primary opacity-50" />
          <p className="text-[10px] font-black uppercase tracking-[0.3em] opacity-40 animate-pulse italic">Sincronizzazione Hub...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-full w-full overflow-hidden bg-background/50 backdrop-blur-xl border-t border-border/20 shadow-inner relative">
      {/* Chat List Sidebar (LEFT - WhatsApp Style) */}
      <ChatSidebar
        channels={channels || []}
        users={users || []}
        activeChannelId={activeChannelId}
        onSelectChannel={handleSelectChannel}
        onStartDirectChat={handleStartDirectChat}
        onlineUsers={onlineUsers}
        unreadCounts={unreadCounts}
        category={category}
        onCategoryChange={setCategory}
        className="w-80 shrink-0 border-r border-border/10"
      />

      {/* Main Conversation Area (RIGHT) */}
      <div className="flex-1 flex flex-col min-w-0 relative">
        <ChatConversation 
          channelId={activeChannelId} 
          className="h-full"
        />
      </div>
    </div>
  );
}

export default ChatHub;

import { useState, useRef, useEffect, useCallback } from "react";
import { Send, X, AtSign, Paperclip, FileIcon, Loader2, Mic, Square } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import type { ChatMessage } from "@/types/chat";
import { cn } from "@/lib/utils";

interface ChatInputProps {
  onSend: (content: string, replyToId?: string) => void;
  replyTo?: ChatMessage;
  onCancelReply: () => void;
  teamMembers: { id: string; nome: string; cognome: string }[];
  onTyping?: (isTyping: boolean) => void;
  onUpload?: (file: File) => Promise<any>;
}

interface SelectedUpload {
  url: string;
  previewUrl: string | null;
  name: string;
  type: string;
  size: number;
}

export function ChatInput({ onSend, replyTo, onCancelReply, teamMembers, onTyping, onUpload }: ChatInputProps) {
  const [content, setContent] = useState("");
  const [selectedFile, setSelectedFile] = useState<SelectedUpload | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [showMentions, setShowMentions] = useState(false);
  const [mentionFilter, setMentionFilter] = useState("");
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const clearSelectedFile = useCallback(() => {
    setSelectedFile((prev) => {
      if (prev?.previewUrl?.startsWith("blob:")) {
        URL.revokeObjectURL(prev.previewUrl);
      }
      return null;
    });
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  }, []);

  // ─── Voice Recording State ─────────────────────────────────────
  const [isRecording, setIsRecording] = useState(false);
  const [recordingSeconds, setRecordingSeconds] = useState(0);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const recordingTimerRef = useRef<any>(null);

  const startRecording = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream, { mimeType: "audio/webm" });
      audioChunksRef.current = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) audioChunksRef.current.push(e.data);
      };

      recorder.onstop = async () => {
        stream.getTracks().forEach((t) => t.stop());
        const blob = new Blob(audioChunksRef.current, { type: "audio/webm" });
        const file = new File([blob], `vocale_${Date.now()}.webm`, { type: "audio/webm" });

        if (onUpload) {
          setIsUploading(true);
          try {
            const res = await onUpload(file);
            // Send immediately as voice message
            onSend(res.url, replyTo?.id);
            onCancelReply();
          } catch (err) {
            console.error("Voice upload failed", err);
          } finally {
            setIsUploading(false);
          }
        }

        setRecordingSeconds(0);
      };

      recorder.start();
      mediaRecorderRef.current = recorder;
      setIsRecording(true);

      // Live timer
      recordingTimerRef.current = setInterval(() => {
        setRecordingSeconds((s) => s + 1);
      }, 1000);
    } catch (err) {
      console.error("Microphone access denied", err);
      alert("Accesso al microfono negato. Controlla le autorizzazioni del browser.");
    }
  }, [onUpload, onSend, replyTo, onCancelReply]);

  const stopRecording = useCallback(() => {
    clearInterval(recordingTimerRef.current);
    mediaRecorderRef.current?.stop();
    setIsRecording(false);
  }, []);

  const cancelRecording = useCallback(() => {
    clearInterval(recordingTimerRef.current);
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.ondataavailable = null;
      mediaRecorderRef.current.onstop = null;
      mediaRecorderRef.current.stop();
      mediaRecorderRef.current.stream?.getTracks().forEach((t) => t.stop());
    }
    audioChunksRef.current = [];
    setIsRecording(false);
    setRecordingSeconds(0);
  }, []);

  const formatTime = (s: number) => {
    const m = Math.floor(s / 60);
    const sec = s % 60;
    return `${m}:${sec.toString().padStart(2, "0")}`;
  };
  // ──────────────────────────────────────────────────────────────

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    try {
      if (onUpload) {
        const res = await onUpload(file);
        const previewUrl = file.type?.startsWith("image/") ? URL.createObjectURL(file) : null;
        setSelectedFile({
          url: res.url,
          previewUrl,
          name: res.filename,
          type: res.content_type,
          size: res.size,
        });
      }
    } catch (err) {
      console.error("Upload failed", err);
    } finally {
      setIsUploading(false);
    }
  };

  const handleSend = () => {
    if ((!content.trim() && !selectedFile) || isUploading) return;

    if (selectedFile) {
      onSend(selectedFile.url, replyTo?.id);
    } else {
      onSend(content, replyTo?.id);
    }

    setContent("");
    clearSelectedFile();
    onCancelReply();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    // Se il menu mention è aperto, ignora Enter (non inviare)
    if (e.key === "Enter" && showMentions) {
      e.preventDefault();
      return;
    }
    if (e.key === "Escape" && showMentions) {
      e.preventDefault();
      setShowMentions(false);
      return;
    }
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const insertMention = (member: { nome: string; cognome: string }) => {
    const cursor = textareaRef.current?.selectionStart || content.length;
    const textBeforeCursor = content.substring(0, cursor);
    const lastAtPos = textBeforeCursor.lastIndexOf("@");
    
    if (lastAtPos !== -1) {
      const newContent =
        content.substring(0, lastAtPos) +
        `@${member.nome} ${member.cognome} ` +
        content.substring(cursor);
      setContent(newContent);
    }
    setShowMentions(false);
    textareaRef.current?.focus();
  };

  const typingTimeoutRef = useRef<any>(null);

  useEffect(() => {
    return () => {
      clearInterval(recordingTimerRef.current);
      if (typingTimeoutRef.current) {
        clearTimeout(typingTimeoutRef.current);
      }
      mediaRecorderRef.current?.stream?.getTracks().forEach((track) => track.stop());
      if (selectedFile?.previewUrl?.startsWith("blob:")) {
        URL.revokeObjectURL(selectedFile.previewUrl);
      }
    };
  }, [selectedFile?.previewUrl]);

  useEffect(() => {
    const cursor = textareaRef.current?.selectionStart || content.length;
    const textBeforeCursor = content.substring(0, cursor);
    const match = textBeforeCursor.match(/@([^ \n\r\t]*)$/);
    
    if (match) {
      setShowMentions(true);
      setMentionFilter(match[1].toLowerCase());
    } else {
      setShowMentions(false);
      setMentionFilter("");
    }

    if (content.length > 0) {
      onTyping?.(true);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = setTimeout(() => {
        onTyping?.(false);
      }, 2000);
    } else {
      onTyping?.(false);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    }
  }, [content, onTyping]);

  const filteredMembers = teamMembers.filter((m) =>
    `${m.nome} ${m.cognome}`.toLowerCase().includes(mentionFilter)
  );

  const showMicButton = !content.trim() && !selectedFile && !isUploading;

  return (
    <div className="p-4 pr-20 bg-card/50 border-t border-border/50 backdrop-blur-md relative">

      {/* Reply Preview */}
      {replyTo && (
        <div className="flex items-center justify-between gap-3 px-4 py-2 mb-3 bg-primary/5 border border-primary/20 rounded-xl animate-in slide-in-from-bottom-2 duration-300">
          <div className="flex-1 truncate">
            <p className="text-[10px] font-black uppercase tracking-widest text-primary">Rispondendo a {replyTo.autore_nome}</p>
            <p className="text-xs text-muted-foreground truncate italic">"{replyTo.contenuto}"</p>
          </div>
          <Button variant="ghost" size="icon" className="h-6 w-6 rounded-full hover:bg-primary/10 text-primary" onClick={onCancelReply}>
            <X size={12} />
          </Button>
        </div>
      )}

      {/* Mention Auto-complete */}
      {showMentions && filteredMembers.length > 0 && (
        <div className="absolute bottom-[calc(100%+8px)] left-4 w-64 bg-card border border-border rounded-2xl shadow-2xl overflow-hidden z-50 animate-in fade-in zoom-in-95">
          <div className="p-3 border-b border-border bg-muted/30 flex items-center gap-2">
            <AtSign size={14} className="text-primary" />
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground">Menziona qualcuno...</span>
          </div>
          <div className="max-h-48 overflow-y-auto custom-scrollbar">
            {filteredMembers.map((m) => (
              <button
                key={m.id}
                type="button"
                onMouseDown={(e) => {
                  // Previene il blur del textarea che scatenerebbe un invio spurio
                  e.preventDefault();
                  insertMention(m);
                }}
                className="w-full text-left px-4 py-2.5 hover:bg-primary/10 hover:text-primary transition-all text-sm font-bold flex items-center gap-3 border-b border-border/30 last:border-0"
              >
                <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center text-[10px] shrink-0">
                  {m.nome[0]}{m.cognome[0]}
                </div>
                <span>{m.nome} {m.cognome}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Attachment Preview */}
      {selectedFile && (
        <div className="mx-4 mb-3 p-2.5 bg-muted/50 rounded-2xl border border-border/50 flex items-center justify-between group animate-in slide-in-from-bottom-2">
          <div className="flex items-center gap-3 truncate">
            <div className="w-12 h-12 rounded-xl bg-background flex items-center justify-center border border-border/50 overflow-hidden shadow-sm">
              {selectedFile.type?.startsWith("image/") && selectedFile.previewUrl ? (
                <img src={selectedFile.previewUrl} alt="preview" className="w-full h-full object-cover" />
              ) : (
                <FileIcon className="w-6 h-6 text-primary" />
              )}
            </div>
            <div className="flex flex-col truncate">
              <span className="text-xs font-bold line-clamp-1">{selectedFile.name}</span>
              <span className="text-[10px] text-muted-foreground uppercase font-black tracking-tighter">
                {(selectedFile.size / 1024 / 1024).toFixed(2)} MB
              </span>
            </div>
          </div>
          <Button
            variant="ghost"
            size="icon"
            className="h-8 w-8 rounded-full hover:bg-destructive/10 text-destructive opacity-0 group-hover:opacity-100 transition-opacity"
            onClick={clearSelectedFile}
          >
            <X size={14} />
          </Button>
        </div>
      )}

      {/* ── Recording UI ── */}
      {isRecording && (
        <div className="flex items-center gap-3 mb-3 px-4 py-3 bg-red-500/10 border border-red-500/30 rounded-2xl animate-in slide-in-from-bottom-2">
          {/* Pulsing dot */}
          <span className="w-3 h-3 rounded-full bg-red-500 animate-pulse shadow-[0_0_8px_rgba(239,68,68,0.7)]" />

          {/* Waveform bars */}
          <div className="flex items-center gap-0.5 h-5">
            {[...Array(8)].map((_, i) => (
              <span
                key={i}
                className="w-1 rounded-full bg-red-400"
                style={{
                  height: `${30 + Math.sin(i * 1.2) * 60}%`,
                  animation: `soundWave 0.8s ease-in-out ${i * 0.1}s infinite alternate`,
                }}
              />
            ))}
          </div>

          <span className="text-sm font-black text-red-400 tabular-nums flex-1">
            {formatTime(recordingSeconds)}
          </span>

          {/* Cancel */}
          <Button
            variant="ghost"
            size="icon"
            className="h-8 w-8 rounded-full text-muted-foreground hover:text-destructive hover:bg-destructive/10"
            onClick={cancelRecording}
          >
            <X size={16} />
          </Button>

          {/* Stop & Send */}
          <Button
            size="icon"
            className="h-9 w-9 rounded-xl bg-red-500 hover:bg-red-600 text-white shadow-lg shadow-red-500/30 hover:scale-110 active:scale-95 transition-all"
            onClick={stopRecording}
          >
            {isUploading ? <Loader2 size={18} className="animate-spin" /> : <Square size={18} fill="white" />}
          </Button>
        </div>
      )}

      {/* ── Main Input Row ── */}
      {!isRecording && (
        <div className="flex items-end gap-3">
          <div className="flex-1 relative flex items-end bg-background/50 border border-border/60 rounded-2xl focus-within:border-primary/50 transition-all shadow-inner">
            <button
              className="p-3.5 text-muted-foreground hover:text-primary transition-colors disabled:opacity-50"
              onClick={() => fileInputRef.current?.click()}
              disabled={isUploading}
            >
              {isUploading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Paperclip size={20} />}
            </button>
            <input
              type="file"
              className="hidden"
              ref={fileInputRef}
              onChange={handleFileSelect}
            />

            <Textarea
              ref={textareaRef}
              value={content}
              onChange={(e) => setContent(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder={selectedFile ? "Aggiungi un commento..." : "Scrivi un messaggio..."}
              className="min-h-[50px] max-h-[150px] bg-transparent border-0 focus-visible:ring-0 rounded-2xl py-3.5 px-0 text-sm font-medium resize-none shadow-none"
            />
          </div>

          {/* Mic button (when empty) or Send button (when has text) */}
          {showMicButton ? (
            <Button
              onClick={startRecording}
              className="h-12 w-12 rounded-2xl bg-muted text-muted-foreground hover:bg-primary/10 hover:text-primary shadow-sm hover:scale-110 active:scale-95 transition-all shrink-0"
              variant="ghost"
              title="Tieni premuto o clicca per registrare un vocale"
            >
              <Mic size={22} />
            </Button>
          ) : (
            <Button
              onClick={handleSend}
              disabled={!content.trim() && !selectedFile}
              className="h-12 w-12 rounded-2xl bg-primary text-white shadow-lg shadow-primary/20 hover:scale-110 active:scale-95 transition-all shrink-0"
            >
              <Send size={20} className={cn("transition-transform", content.trim() && "translate-x-0.5 -translate-y-0.5")} />
            </Button>
          )}
        </div>
      )}

      <p className="text-[9px] font-black uppercase tracking-[0.3em] text-muted-foreground/30 mt-2 text-center">
        Enter per inviare &bull; Shift+Enter per andare a capo
        {showMicButton && " · Microfono per vocale"}
      </p>

      {/* Keyframes for waveform */}
      <style>{`
        @keyframes soundWave {
          from { opacity: 0.4; transform: scaleY(0.4); }
          to   { opacity: 1;   transform: scaleY(1);   }
        }
      `}</style>
    </div>
  );
}

import { useState, useRef, useEffect } from "react";
import { useChat } from "@/hooks/useChat";
import { useAuth } from "@/hooks/useAuth";
import { ChatMessageBubble } from "./ChatMessageBubble";
import { ChatInput } from "./ChatInput";
import type { ChatMessage } from "@/types/chat";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Loader2, MessageSquareOff, Search, X, MessageSquare, History, ArrowUpCircle } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import api from "@/lib/api";
import { cn } from "@/lib/utils";
import { format } from "date-fns";

interface ChatProgettoProps {
  progettoId: string;
  teamMembers?: any[];
}

export function ChatProgetto({ progettoId, teamMembers = [] }: ChatProgettoProps) {
  const { user } = useAuth();
  const { 
    messages, 
    sendMessage, 
    typingUsers, 
    onlineUsers, 
    addReaction,
    removeReaction,
    deleteMessage,
    editMessage,
    uploadFile,
    channelSeenStatus,
    isLoading,
    hasMore,
    loadMoreMessages,
    setTypingStatus, 
    markAsSeen,
    setActiveChannelId 
  } = useChat();

  const [searchTerm, setSearchTerm] = useState("");
  const [searchResults, setSearchResults] = useState<ChatMessage[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showSearch, setShowSearch] = useState(false);

  useEffect(() => {
    setActiveChannelId(progettoId);
    markAsSeen(progettoId);
  }, [progettoId, setActiveChannelId, markAsSeen]);

  const allMessages: ChatMessage[] = messages || [];
  const messagesById = new Map(allMessages.map((message) => [message.id, message]));
  const [replyTo, setReplyTo] = useState<ChatMessage | undefined>();
  const scrollRef = useRef<HTMLDivElement>(null);
  const [isInitialLoading, setIsInitialLoading] = useState(true);
  const onlineMembersCount = teamMembers.filter((member) => onlineUsers.has(member.user_id)).length;

  const team = teamMembers.map(m => ({
    id: m.user_id,
    nome: m.user?.nome || "User",
    cognome: m.user?.cognome || ""
  }));

  useEffect(() => {
    if (!isLoading && isInitialLoading) {
       setIsInitialLoading(false);
    }
  }, [isLoading, isInitialLoading]);

  // Auto-scroll to bottom only on first load or when sending message
  useEffect(() => {
    if (scrollRef.current && !isLoading) {
      const scrollContainer = scrollRef.current.querySelector('[data-radix-scroll-area-viewport]');
      if (scrollContainer) {
        // Se siamo gia vicino al fondo o è il primo caricamento
        const isNearBottom = scrollContainer.scrollHeight - scrollContainer.scrollTop - scrollContainer.clientHeight < 200;
        if (isNearBottom || allMessages.length <= 50) {
          scrollContainer.scrollTop = scrollContainer.scrollHeight;
        }
      }
    }
  }, [allMessages.length, isLoading]);

  const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
    const target = e.currentTarget;
    if (target.scrollTop === 0 && hasMore && !isLoading) {
      // Memorizziamo l'altezza prima del caricamento per mantenere la posizione
      const oldScrollHeight = target.scrollHeight;
      loadMoreMessages().then(() => {
        setTimeout(() => {
          const newScrollHeight = target.scrollHeight;
          target.scrollTop = newScrollHeight - oldScrollHeight;
        }, 0);
      });
    }
  };

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchTerm.trim()) return;
    setIsSearching(true);
    try {
      const res = await api.get(`/chat/search?q=${searchTerm}`);
      setSearchResults(res.data);
    } catch (err) {
      console.error("Search failed", err);
    } finally {
      setIsSearching(false);
    }
  };

  if (isInitialLoading) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center gap-4 text-muted-foreground">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
        <p className="text-xs font-black uppercase tracking-widest">Caricamento messaggi...</p>
      </div>
    );
  }

  return (
    <div className="flex-1 flex overflow-hidden bg-background/20 rounded-3xl border border-white/5 backdrop-blur-xl shadow-2xl relative">
      
      <div className="flex-1 flex flex-col h-[calc(100vh-250px)]">
        {/* Header */}
        <div className="px-6 py-4 border-b border-white/5 flex items-center justify-between bg-white/[0.02]">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-2xl bg-primary/10 flex items-center justify-center text-primary">
                <MessageSquare size={20} />
             </div>
             <div>
                <h3 className="text-sm font-black uppercase tracking-widest text-white">Team Chat</h3>
                <p className="text-[10px] font-bold text-muted-foreground/60 uppercase tracking-tight">{allMessages.length} messaggi &bull; {onlineMembersCount} online</p>
             </div>
          </div>
          <div className="flex items-center gap-2">
             <Button 
                variant="ghost" 
                size="icon" 
                className={cn("rounded-xl transition-all", showSearch ? "bg-primary text-white" : "hover:bg-white/5")}
                onClick={() => setShowSearch(!showSearch)}
             >
                <Search size={18} />
             </Button>
          </div>
        </div>
      
        <ScrollArea 
          ref={scrollRef} 
          className="flex-1 p-4"
          onScrollCapture={handleScroll}
        >
          {hasMore && (
            <div className="flex justify-center py-4">
               <Button variant="ghost" size="sm" className="text-[10px] font-black uppercase tracking-widest text-primary hover:bg-primary/10" onClick={loadMoreMessages}>
                  <History size={12} className="mr-2" /> Carica messaggi precedenti
               </Button>
            </div>
          )}
        {allMessages.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center opacity-20 py-20">
            <MessageSquareOff size={64} className="mb-4" />
            <p className="text-sm font-black uppercase tracking-[0.2em]">Inizia la conversazione</p>
          </div>
        ) : (
          <div className="flex flex-col min-h-full">
            {allMessages.map((m: any, i: number) => {
              const prev = allMessages[i - 1];
              const isFirstInGroup = !prev || prev.autore_id !== m.autore_id || 
                (new Date(m.created_at).getTime() - new Date(prev.created_at).getTime() > 300000); // 5 min group
              
              const replyToMsg = m.risposta_a ? messagesById.get(m.risposta_a) : undefined;

              // Calcola chi ha visto questo messaggio come ultimo
              const seenBy = teamMembers.filter(member => {
                if (member.user_id === user?.id) return false; // Non mostrare se stesso
                const lastSeenAt = channelSeenStatus[progettoId]?.[member.user_id];
                if (!lastSeenAt) return false;
                
                const msgTime = new Date(m.created_at).getTime();
                const seenTime = new Date(lastSeenAt).getTime();
                
                // Mostra avatar solo se questo è l'ultimo messaggio visto (o uno dei più recenti)
                const nextMsg = allMessages[i + 1];
                const nextMsgTime = nextMsg ? new Date(nextMsg.created_at).getTime() : Infinity;
                
                return seenTime >= msgTime && seenTime < nextMsgTime;
              }).map(member => ({
                id: member.user_id,
                nome: member.user?.nome || "User",
                avatar: member.user?.avatar_url
              }));

              return (
                <ChatMessageBubble
                  key={m.id}
                  message={m}
                  isMe={m.autore_id === user?.id}
                  isFirstInGroup={isFirstInGroup}
                  replyTo={replyToMsg}
                  isOnline={onlineUsers.has(m.autore_id)}
                  seenBy={seenBy}
                    onReply={(msg) => setReplyTo(msg)}
                    onDelete={(id) => deleteMessage(id)}
                    onEdit={(id, content) => editMessage(id, content)}
                    onReact={(id, emoji) => addReaction(id, emoji)}
                    onRemoveReact={(id, emoji) => removeReaction(id, emoji)}
                  />
              );
            })}
          </div>
        )}
      </ScrollArea>

      {/* Typing Indicator */}
      {typingUsers.length > 0 && (
        <div className="px-6 py-2 flex items-center gap-2 animate-in fade-in slide-in-from-bottom-1">
          <div className="flex gap-1">
            <span className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce [animation-delay:-0.3s]"></span>
            <span className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce [animation-delay:-0.15s]"></span>
            <span className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce"></span>
          </div>
          <span className="text-[10px] font-black uppercase tracking-widest text-primary/70">
            {typingUsers.join(", ")} {typingUsers.length > 1 ? "stanno scrivendo..." : "sta scrivendo..."}
          </span>
        </div>
      )}

        <ChatInput
          teamMembers={team}
          replyTo={replyTo}
          onCancelReply={() => setReplyTo(undefined)}
          onTyping={(isTyping) => setTypingStatus(isTyping)}
          onUpload={(file) => uploadFile(file)}
          onSend={(content, replyId) => {
            sendMessage(content, 'testo', replyId);
          }}
        />
      </div>

      {/* Search Sidebar */}
      {showSearch && (
        <div className="w-80 border-l border-white/5 bg-black/20 backdrop-blur-2xl flex flex-col animate-in slide-in-from-right duration-300">
           <div className="p-4 border-b border-white/5 flex items-center justify-between">
              <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-white">Ricerca</h3>
              <Button variant="ghost" size="icon" className="h-8 w-8 rounded-full" onClick={() => setShowSearch(false)}>
                 <X size={14} />
              </Button>
           </div>
           <form onSubmit={handleSearch} className="p-4">
              <div className="relative">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                 <Input 
                   value={searchTerm} 
                   onChange={(e) => setSearchTerm(e.target.value)}
                   placeholder="Cerca nei messaggi..." 
                   className="pl-10 bg-white/5 border-white/10 rounded-xl"
                 />
              </div>
           </form>
           
           <ScrollArea className="flex-1 px-4">
              {isSearching ? (
                <div className="py-20 flex flex-col items-center justify-center gap-4 text-muted-foreground">
                   <Loader2 className="w-6 h-6 animate-spin" />
                   <span className="text-[10px] font-black uppercase tracking-widest">Ricerca in corso...</span>
                </div>
              ) : searchResults.length > 0 ? (
                <div className="flex flex-col gap-4 pb-10">
                   {searchResults.map(msg => (
                     <div key={msg.id} className="p-3 rounded-2xl bg-white/5 border border-white/5 hover:border-primary/50 transition-all cursor-pointer group">
                        <div className="flex items-center justify-between mb-1">
                           <span className="text-[10px] font-black text-primary uppercase">{msg.autore_nome}</span>
                           <span className="text-[8px] text-muted-foreground">{format(new Date(msg.created_at), "dd MMM HH:mm")}</span>
                        </div>
                        <p className="text-xs text-white/80 line-clamp-3 leading-relaxed">{msg.contenuto}</p>
                     </div>
                   ))}
                </div>
              ) : searchTerm ? (
                <div className="py-20 text-center opacity-20">
                   <Search size={48} className="mx-auto mb-4" />
                   <p className="text-xs font-black uppercase tracking-widest">Nessun risultato</p>
                </div>
              ) : (
                <div className="py-20 text-center opacity-20">
                   <History size={48} className="mx-auto mb-4" />
                   <p className="text-xs font-black uppercase tracking-widest">Digita per cercare</p>
                </div>
              )}
           </ScrollArea>
        </div>
      )}
    </div>
  );
}

export default ChatProgetto;

import { useState, useMemo } from "react";
import { Search, Plus, MoreVertical, Users, X } from "lucide-react";
import { cn } from "@/lib/utils";
import { format } from "date-fns";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";

interface ChatSidebarProps {
  channels: any[];
  users: any[];
  activeChannelId: string | null;
  onSelectChannel: (id: string) => void;
  onStartDirectChat: (userId: string) => void;
  onlineUsers?: Set<string>;
  unreadCounts?: Record<string, number>;
  category: 'all' | 'projects' | 'team';
  onCategoryChange: (cat: 'all' | 'projects' | 'team') => void;
  className?: string;
}

export function ChatSidebar({
  channels,
  users,
  activeChannelId,
  onSelectChannel,
  onStartDirectChat,
  onlineUsers = new Set(),
  unreadCounts = {},
  category,
  onCategoryChange,
  className
}: ChatSidebarProps) {
  const [searchQuery, setSearchQuery] = useState("");

  const filteredChannels = useMemo(() => {
    let list = channels;
    if (category === 'all') list = channels.filter(c => c.tipo === 'GENERAL' || c.tipo === 'GROUP' || c.tipo === 'DIRECT' || !c.tipo);
    if (category === 'projects') list = channels.filter(c => c.tipo === 'PROJECT');
    if (category === 'team') return []; // team tab shows users list instead

    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      list = list.filter(c => c.nome?.toLowerCase().includes(q) || c.last_message?.toLowerCase().includes(q));
    }
    return list;
  }, [channels, category, searchQuery]);

  const filteredUsers = useMemo(() => {
    if (!searchQuery.trim()) return users;
    const q = searchQuery.toLowerCase();
    return users.filter((u: any) =>
      `${u.nome} ${u.cognome}`.toLowerCase().includes(q) || u.ruolo?.toLowerCase().includes(q)
    );
  }, [users, searchQuery]);

  return (
    <div className={cn("flex flex-col h-full bg-card/10 border-l border-border/10", className)}>
      {/* Header */}
      <div className="p-4 border-b border-border/10 bg-muted/5 shrink-0">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-black tracking-tighter uppercase italic opacity-80">Chat Hub</h2>
          <Button variant="ghost" size="icon" className="h-8 w-8 rounded-full">
            <MoreVertical size={18} />
          </Button>
        </div>
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground/50" />
          <Input
            placeholder="Cerca chat..."
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            className="pl-9 pr-8 h-10 bg-background/30 border-border/10 rounded-xl focus-visible:ring-primary/20"
          />
          {searchQuery && (
            <button
              className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground/50 hover:text-foreground transition-colors"
              onClick={() => setSearchQuery("")}
            >
              <X size={14} />
            </button>
          )}
        </div>
      </div>

      {/* Category tabs */}
      <div className="flex gap-2 p-3 bg-muted/20 shrink-0 border-b border-border/10 relative z-10">
        {[
          { id: 'all', label: 'Tutti' },
          { id: 'projects', label: 'Progetti' },
          { id: 'team', label: 'Team' }
        ].map(tab => {
          // Count total unread for tab badge
          const tabUnread = tab.id === 'all'
            ? Object.entries(unreadCounts).reduce((sum, [, n]) => sum + n, 0)
            : 0;

          return (
            <button
              key={tab.id}
              type="button"
              onClick={e => { e.preventDefault(); e.stopPropagation(); onCategoryChange(tab.id as any); }}
              className={cn(
                "flex-1 py-2 text-[11px] font-black uppercase tracking-widest rounded-xl transition-all cursor-pointer relative",
                category === tab.id
                  ? "bg-primary text-primary-foreground shadow-[0_4px_12px_hsl(var(--primary)/0.3)] scale-[1.02]"
                  : "bg-background/40 hover:bg-white/10 text-muted-foreground hover:text-foreground border border-border/5"
              )}
            >
              {tab.label}
              {tabUnread > 0 && tab.id === 'all' && (
                <span className="absolute -top-1 -right-1 w-4 h-4 rounded-full bg-primary text-[9px] font-black text-white flex items-center justify-center shadow-lg">
                  {tabUnread > 9 ? '9+' : tabUnread}
                </span>
              )}
            </button>
          );
        })}
      </div>

      {/* List Area */}
      <div className="flex-1 overflow-y-auto custom-scrollbar">
        {category === 'team' ? (
          /* Collaborators list */
          <div className="animate-in fade-in duration-300">
            <p className="px-4 py-3 text-[9px] font-black uppercase tracking-[0.2em] text-muted-foreground/40">
              Collaboratori {searchQuery ? `(${filteredUsers.length})` : ''}
            </p>
            {filteredUsers.length === 0 ? (
              <p className="px-4 py-6 text-[10px] font-black uppercase tracking-widest text-muted-foreground/40 italic text-center">
                Nessun collaboratore trovato.
              </p>
            ) : (
              filteredUsers.map((user: any) => {
                // Check if this user has an active direct chat
                const activeChan = channels?.find(c => c.id === activeChannelId);
                const isUserActive = activeChan?.tipo === 'DIRECT' && 
                  activeChan.membri?.some((m: any) => m.user_id === user.id);
                const isOnline = onlineUsers.has(user.id);

                return (
                  <button
                    key={user.id}
                    onClick={() => onStartDirectChat(user.id)}
                    className={cn(
                      "w-full flex items-center gap-3 p-4 border-b border-border/5 transition-all group relative",
                      isUserActive ? "bg-primary/5 border-r-2 border-r-primary" : "hover:bg-white/[0.02]"
                    )}
                  >
                    <div className="relative">
                      <Avatar className="h-10 w-10 rounded-xl border border-border/20 group-hover:scale-105 transition-transform">
                        <AvatarImage src={user.avatar_url} />
                        <AvatarFallback className="bg-muted text-[10px] font-black uppercase">
                          {user.nome[0]}{user.cognome[0]}
                        </AvatarFallback>
                      </Avatar>
                      <span className={cn(
                        "absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-card",
                        isOnline ? "bg-emerald-500 shadow-[0_0_6px_rgba(16,185,129,0.6)]" : "bg-muted-foreground/30"
                      )} />
                    </div>
                    <div className="flex-1 text-left">
                      <p className="text-[11px] font-black uppercase text-foreground/80 tracking-tight leading-none mb-1">
                        {user.nome} {user.cognome}
                      </p>
                      <p className={cn(
                        "text-[9px] font-bold uppercase tracking-widest",
                        isOnline ? "text-emerald-400" : "text-muted-foreground/50"
                      )}>
                        {isOnline ? "Online" : user.ruolo}
                      </p>
                    </div>
                  </button>
                );
              })
            )}
          </div>
        ) : (
          /* Channels list */
          <div className="animate-in fade-in duration-300">
            {searchQuery && (
              <p className="px-4 py-2 text-[9px] font-black uppercase tracking-[0.2em] text-muted-foreground/40">
                {filteredChannels.length} risultat{filteredChannels.length === 1 ? 'o' : 'i'}
              </p>
            )}
            {filteredChannels.length === 0 && (
              <div className="p-8 text-center">
                <p className="text-[10px] font-black uppercase tracking-widest text-muted-foreground/40 italic">
                  {searchQuery ? 'Nessun risultato trovato.' : 'Nessun canale trovato.'}
                </p>
              </div>
            )}

            {filteredChannels.map((channel) => {
              const isActive = activeChannelId === channel.id;
              const unread = unreadCounts[channel.id] || 0;

              return (
                <button
                  key={channel.id}
                  onClick={() => onSelectChannel(channel.id)}
                  className={cn(
                    "w-full flex items-center gap-3 p-4 transition-all duration-300 border-b border-border/5 relative group",
                    isActive ? "bg-primary/5 border-r-2 border-r-primary shadow-inner" : "hover:bg-white/[0.02]"
                  )}
                >
                  <Avatar className="h-10 w-10 rounded-xl border border-border/20 shadow-sm group-hover:scale-105 transition-transform shrink-0">
                    <AvatarImage src={channel.logo_url} />
                    <AvatarFallback className="bg-primary/5 text-primary text-[10px] font-black">
                      {channel.tipo === 'GENERAL' ? <Users size={16} /> : (channel.nome[0] + (channel.nome[1] || ''))}
                    </AvatarFallback>
                  </Avatar>

                  <div className="flex-1 text-left min-w-0">
                    <div className="flex items-center justify-between mb-0.5">
                      <span className={cn(
                        "text-[11px] font-black truncate tracking-tight transition-colors uppercase",
                        isActive ? "text-primary" : unread > 0 ? "text-foreground" : "text-foreground/70"
                      )}>
                        {channel.nome}
                      </span>
                      {channel.last_message_at && (
                        <span className="text-[9px] text-muted-foreground/50 font-medium shrink-0 ml-1">
                          {format(new Date(channel.last_message_at), 'HH:mm')}
                        </span>
                      )}
                    </div>
                    <div className="flex items-center justify-between gap-2">
                      <p className={cn(
                        "text-[10px] truncate italic leading-tight",
                        unread > 0 ? "text-foreground/70 font-bold not-italic" : "text-muted-foreground/60 opacity-80"
                      )}>
                        {channel.last_message || (channel.tipo === 'GENERAL' ? 'Benvenuto nel team!' : 'Inizia la conversazione...')}
                      </p>
                      {unread > 0 && (
                        <span className="shrink-0 min-w-[18px] h-[18px] rounded-full bg-primary text-[9px] font-black text-white flex items-center justify-center px-1 shadow-lg shadow-primary/30">
                          {unread > 99 ? '99+' : unread}
                        </span>
                      )}
                    </div>
                  </div>
                </button>
              );
            })}
          </div>
        )}
      </div>

      {/* Footer */}
      <div className="p-4 border-t border-border/10 bg-muted/10 shrink-0 sticky bottom-0 z-10 backdrop-blur-md">
        <Button className="w-full h-10 bg-primary/90 text-white rounded-xl shadow-lg shadow-primary/30 font-black text-[10px] uppercase tracking-widest flex items-center gap-2 hover:bg-primary hover:scale-[1.02] active:scale-95 transition-all">
          <Plus size={16} />
          <span>Nuovo Gruppo</span>
        </Button>
      </div>
    </div>
  );
}

