// ... existing imports

function HealthIndicator({ id }: { id: string }) {
  const { data: health, isLoading } = useClientHealthScore(id);

  if (isLoading) return <div className="h-4 w-12 bg-muted animate-pulse rounded mx-auto" />;
  if (!health) return <span className="text-muted-foreground text-xs">--</span>;

  const score = health.score;
  let color = "bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.4)]";
  if (score < 40) color = "bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.4)]";
  else if (score < 70) color = "bg-amber-500 shadow-[0_0_10px_rgba(245,158,11,0.4)]";

  return (
    <div className="flex flex-col items-center gap-1">
      <div className="text-xs font-black text-foreground">{score}%</div>
      <div className="w-12 h-1.5 bg-muted rounded-full overflow-hidden p-[1px] border border-white/5">
        <div 
          className={`h-full rounded-full transition-all duration-1000 ${color}`}
          style={{ width: `${score}%` }}
        />
      </div>
    </div>
  );
}

// ... existing ClienteTable component
import { ClientAvatar } from "../common/ClientAvatar";
import { EmptyState } from "../common/EmptyState";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";

interface ClienteTableProps {
  clienti: Cliente[];
  isLoading: boolean;
  onEdit: (cliente: Cliente) => void;
  onNew: () => void;
}

// Variants defined outside component — not recreated on every render
const container = {
  hidden: { opacity: 0 },
  show: { opacity: 1, transition: { staggerChildren: 0.04 } },
};
const item = {
  hidden: { opacity: 0, x: -8 },
  show: { opacity: 1, x: 0, transition: { duration: 0.12 } },
};

export function ClienteTable({ clienti, isLoading, onEdit, onNew }: ClienteTableProps) {
  const navigate = useNavigate();
  const [searchTerm, setSearchTerm] = React.useState("");
  const [deleteId, setDeleteId] = React.useState<string | null>(null);
  const deleteCliente = useDeleteCliente();

  const filteredClienti = useMemo(
    () =>
      clienti.filter(
        (c) =>
          c.ragione_sociale.toLowerCase().includes(searchTerm.toLowerCase()) ||
          c.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
          c.piva?.includes(searchTerm)
      ),
    [clienti, searchTerm]
  );

  const handleDelete = async () => {
    if (deleteId) {
      await deleteCliente.mutateAsync(deleteId);
      setDeleteId(null);
    }
  };

  if (isLoading) {
    return (
      <div className="space-y-4">
        <div className="flex items-center justify-between gap-4">
          <Skeleton className="h-10 w-[300px] bg-muted" />
          <Skeleton className="h-10 w-[120px] bg-primary/20" />
        </div>
        <div className="rounded-xl border border-border overflow-hidden">
          {[1, 2, 3, 4, 5].map((i) => (
            <Skeleton key={i} className="h-16 w-full mb-[1px] bg-card" />
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="flex flex-col md:flex-row items-center justify-between gap-4 bg-card p-4 rounded-xl border border-border shadow-xl">
        <div className="relative w-full md:w-96">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Cerca per ragione sociale, email o P.IVA..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 bg-muted border-border text-foreground focus:ring-primary w-full"
          />
        </div>
        <Button 
          onClick={onNew} 
          className="bg-primary hover:bg-primary/90 text-[10px] font-black uppercase italic tracking-widest text-primary-foreground shadow-xl shadow-[0_0_20px_hsl(var(--primary)/0.2)] w-full md:w-auto h-10 px-6 rounded-xl"
        >
          <UserPlus className="mr-2 h-4 w-4" /> Nuovo Cliente
        </Button>
      </div>

      <div className="rounded-xl border border-border bg-card shadow-2xl overflow-hidden">
        <Table>
          <TableHeader className="bg-muted/50">
            <TableRow className="hover:bg-transparent border-border">
              <TableHead className="text-muted-foreground font-bold py-4 pl-6 font-black uppercase text-[10px] tracking-widest">Ragione Sociale</TableHead>
              <TableHead className="text-muted-foreground font-bold font-black uppercase text-[10px] tracking-widest">Email / Tel</TableHead>
              <TableHead className="text-muted-foreground font-bold text-center font-black uppercase text-[10px] tracking-widest">Health</TableHead>
              <TableHead className="text-muted-foreground font-bold text-center font-black uppercase text-[10px] tracking-widest">Stato</TableHead>
              <TableHead className="text-right text-muted-foreground font-bold pr-6 font-black uppercase text-[10px] tracking-widest">Azioni</TableHead>
            </TableRow>
          </TableHeader>
          <motion.tbody
            variants={container}
            initial="hidden"
            animate="show"
          >
            {filteredClienti.length === 0 ? (
              <TableRow>
                <TableCell colSpan={5} className="py-20">
                  <EmptyState 
                    icon={Building2}
                    title="Nessun Cliente"
                    description="Inizia a popolare il tuo database aggiungendo il tuo primo cliente aziendale."
                    actionLabel="Aggiungi Cliente"
                    onAction={onNew}
                  />
                </TableCell>
              </TableRow>
            ) : (
              filteredClienti.map((cliente) => (
                <TableRow 
                  key={cliente.id} 
                  className="group hover:bg-muted/30 border-border transition-colors cursor-pointer"
                  onClick={() => navigate(`/clienti/${cliente.id}`)}
                >
                  <TableCell className="py-4">
                    <div className="flex items-center gap-3">
                      <ClientAvatar 
                        name={cliente.ragione_sociale} 
                        logoUrl={cliente.logo_url} 
                        size="sm" 
                        className="rounded-lg border-border"
                      />
                      <div className="flex flex-col">
                        <span className="font-bold text-foreground group-hover:text-primary transition-colors">
                          {cliente.ragione_sociale}
                        </span>
                        <span className="text-[11px] text-muted-foreground">P.IVA: {cliente.piva || "---"}</span>
                      </div>
                    </div>
                  </TableCell>
                  <TableCell>
                    <div className="flex flex-col gap-1">
                      {cliente.email && (
                        <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                          <Mail className="h-3 w-3" /> {cliente.email}
                        </div>
                      )}
                      {cliente.telefono && (
                        <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                          <Phone className="h-3 w-3" /> {cliente.telefono}
                        </div>
                      )}
                    </div>
                  </TableCell>
                  <TableCell className="text-center">
                    <HealthIndicator id={cliente.id} />
                  </TableCell>
                  <TableCell className="text-center">
                    <div className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                      cliente.attivo 
                        ? "bg-green-500/10 text-green-500 border border-green-500/20" 
                        : "bg-red-500/10 text-red-500 border border-red-500/20"
                    }`}>
                      {cliente.attivo ? "Attivo" : "Inattivo"}
                    </div>
                  </TableCell>
                  <TableCell className="text-right pr-6" onClick={(e: React.MouseEvent) => e.stopPropagation()}>
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button variant="ghost" className="h-8 w-8 p-0 text-muted-foreground hover:text-white hover:bg-muted">
                          <MoreHorizontal className="h-4 w-4" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end" className="bg-card border-border text-foreground">
                        <DropdownMenuLabel>Azioni</DropdownMenuLabel>
                        <DropdownMenuSeparator className="bg-muted" />
                        <DropdownMenuItem onClick={() => onEdit(cliente)} className="focus:bg-primary/10 focus:text-primary">
                          <Pencil className="mr-2 h-4 w-4" /> Modifica
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => navigate(`/clienti/${cliente.id}`)} className="focus:bg-primary/10 focus:text-primary">
                          <ExternalLink className="mr-2 h-4 w-4" /> Vedi Dettagli
                        </DropdownMenuItem>
                        <DropdownMenuSeparator className="bg-muted" />
                        <DropdownMenuItem 
                          onClick={() => setDeleteId(cliente.id)}
                          className="text-red-500 focus:bg-red-500/10 focus:text-red-500"
                        >
                          <Trash2 className="mr-2 h-4 w-4" /> Elimina
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </TableCell>
                </TableRow>
              ))
            )}
          </motion.tbody>
        </Table>
      </div>

      <Dialog open={!!deleteId} onOpenChange={() => setDeleteId(null)}>
        <DialogContent className="bg-card border-border text-white">
          <DialogHeader>
            <DialogTitle>Conferma Eliminazione</DialogTitle>
            <DialogDescription className="text-muted-foreground">
              Sei sicuro di voler eliminare questo cliente? L'azione è irreversibile e potrebbe influire su progetti e commesse collegati.
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="ghost" onClick={() => setDeleteId(null)} className="text-muted-foreground">Annulla</Button>
            <Button 
              variant="destructive" 
              onClick={handleDelete}
              disabled={deleteCliente.isPending}
            >
              {deleteCliente.isPending ? "Eliminazione..." : "Elimina Cliente"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import React, { useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { 
  Users, 
  Mail, 
  Phone, 
  MapPin, 
  CreditCard, 
  Building, 
  Clock, 
  Euro,
  Loader2,
  X
} from "lucide-react";
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogFooter,
  DialogDescription,
  DialogClose
} from "@/components/ui/dialog";
import { 
  Form, 
  FormControl, 
  FormField, 
  FormItem, 
  FormLabel, 
  FormMessage 
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { ScrollArea } from "@/components/ui/scroll-area";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import api from "@/lib/api";
import { toast } from "sonner";

const collaboratorSchema = z.object({
  nome: z.string().min(2, "Il nome è obbligatorio"),
  cognome: z.string().min(2, "Il cognome è obbligatorio"),
  email: z.string().email("Email non valida").optional().or(z.literal("")),
  telefono: z.string().optional(),
  ruolo: z.string().optional(),
  tipo_contratto: z.string().default("DIPENDENTE"),
  ore_settimanali: z.coerce.number().min(0).default(40),
  costo_orario_override: z.coerce.number().optional(),
  piva: z.string().optional(),
  codice_fiscale: z.string().optional(),
  indirizzo: z.string().optional(),
  iban: z.string().optional(),
  banca: z.string().optional(),
  bic_swift: z.string().optional(),
  note: z.string().optional(),
});

type CollaboratorFormValues = z.infer<typeof collaboratorSchema>;

interface CollaboratorFormProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  collaborator?: any; // Risorsa
}

export function CollaboratorForm({ open, onOpenChange, collaborator }: CollaboratorFormProps) {
  const queryClient = useQueryClient();
  const isEdit = !!collaborator;

  const form = useForm<CollaboratorFormValues>({
    resolver: zodResolver(collaboratorSchema) as any,
    defaultValues: {
      nome: "",
      cognome: "",
      email: "",
      telefono: "",
      ruolo: "",
      tipo_contratto: "DIPENDENTE",
      ore_settimanali: 40,
      piva: "",
      codice_fiscale: "",
      indirizzo: "",
      iban: "",
      banca: "",
      bic_swift: "",
      note: "",
    },
  });

  useEffect(() => {
    if (collaborator && open) {
      form.reset({
        nome: collaborator.nome || "",
        cognome: collaborator.cognome || "",
        email: collaborator.email || "",
        telefono: collaborator.telefono || "",
        ruolo: collaborator.ruolo || "",
        tipo_contratto: collaborator.tipo_contratto || "DIPENDENTE",
        ore_settimanali: collaborator.ore_settimanali || 40,
        costo_orario_override: collaborator.costo_orario_override || undefined,
        piva: collaborator.piva || "",
        codice_fiscale: collaborator.codice_fiscale || "",
        indirizzo: collaborator.indirizzo || "",
        iban: collaborator.iban || "",
        banca: collaborator.banca || "",
        bic_swift: collaborator.bic_swift || "",
        note: collaborator.note || "",
      });
    } else if (!collaborator && open) {
      form.reset({
        nome: "",
        cognome: "",
        email: "",
        telefono: "",
        ruolo: "",
        tipo_contratto: "DIPENDENTE",
        ore_settimanali: 40,
        piva: "",
        codice_fiscale: "",
        indirizzo: "",
        iban: "",
        banca: "",
        bic_swift: "",
        note: "",
      });
    }
  }, [collaborator, open, form]);

  const mutation = useMutation({
    mutationFn: async (values: CollaboratorFormValues) => {
      if (isEdit) {
        return api.patch(`/risorse/${collaborator.id}`, values);
      } else {
        return api.post("/risorse", values);
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["risorse-full"] });
      toast.success(isEdit ? "Collaboratore aggiornato" : "Collaboratore creato");
      onOpenChange(false);
    },
    onError: (error: any) => {
      const msg = error.response?.data?.detail || "Errore durante il salvataggio";
      toast.error(msg);
    },
  });

  const onSubmit = (values: CollaboratorFormValues) => {
    mutation.mutate(values);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl bg-card border-border text-white">
        <DialogHeader className="flex flex-row items-center justify-between">
          <div>
            <DialogTitle className="text-2xl font-black uppercase tracking-tight flex items-center gap-2">
              <Users className="h-6 w-6 text-primary" />
              {isEdit ? "Modifica Collaboratore" : "Nuovo Collaboratore"}
            </DialogTitle>
            <DialogDescription className="text-slate-400">
              {isEdit ? "Aggiorna le informazioni professionali e bancarie." : "Aggiungi un nuovo membro al team."}
            </DialogDescription>
          </div>
        </DialogHeader>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6 pt-4">
            <ScrollArea className="max-h-[70vh] pr-4">
              <div className="space-y-8">
                {/* Basic Info */}
                <div className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-primary">Informazioni di Base</h4>
                  <div className="grid grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="nome"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Nome</FormLabel>
                          <FormControl>
                            <Input {...field} className="bg-background border-border" />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="cognome"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Cognome</FormLabel>
                          <FormControl>
                            <Input {...field} className="bg-background border-border" />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="email"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Email</FormLabel>
                          <FormControl>
                            <div className="relative">
                              <Mail className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-500" />
                              <Input {...field} className="pl-10 bg-background border-border" placeholder="email@esempio.it" />
                            </div>
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="telefono"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Telefono</FormLabel>
                          <FormControl>
                            <div className="relative">
                              <Phone className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-500" />
                              <Input {...field} className="pl-10 bg-background border-border" />
                            </div>
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="ruolo"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Ruolo</FormLabel>
                          <FormControl>
                            <Input {...field} className="bg-background border-border" placeholder="es. Senior Designer" />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="tipo_contratto"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Tipo Contratto</FormLabel>
                          <FormControl>
                            <Input {...field} className="bg-background border-border" placeholder="DIPENDENTE, P.IVA, etc." />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>
                </div>

                {/* Professional Info */}
                <div className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-primary">Informazioni Professionali</h4>
                  <div className="grid grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="piva"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Partita IVA</FormLabel>
                          <FormControl>
                            <Input {...field} className="bg-background border-border" />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="codice_fiscale"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Codice Fiscale</FormLabel>
                          <FormControl>
                            <Input {...field} className="bg-background border-border" />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>
                  <FormField
                    control={form.control}
                    name="indirizzo"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Indirizzo</FormLabel>
                        <FormControl>
                          <div className="relative">
                            <MapPin className="absolute left-3 top-3 h-4 w-4 text-slate-500" />
                            <Textarea {...field} className="pl-10 bg-background border-border min-h-[80px]" />
                          </div>
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                {/* Capacity & Costs */}
                <div className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-primary">Capacità & Costi</h4>
                  <div className="grid grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="ore_settimanali"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Ore Settimanali</FormLabel>
                          <FormControl>
                            <div className="relative">
                              <Clock className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-500" />
                              <Input type="number" {...field} className="pl-10 bg-background border-border" />
                            </div>
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="costo_orario_override"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Costo Orario (€)</FormLabel>
                          <FormControl>
                            <div className="relative">
                              <Euro className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-500" />
                              <Input type="number" step="0.01" {...field} className="pl-10 bg-background border-border" />
                            </div>
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>
                </div>

                {/* Banking */}
                <div className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-primary">Informazioni Bancarie</h4>
                  <div className="grid grid-cols-1 gap-4">
                    <FormField
                      control={form.control}
                      name="iban"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">IBAN</FormLabel>
                          <FormControl>
                            <div className="relative">
                              <CreditCard className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-500" />
                              <Input {...field} className="pl-10 bg-background border-border" />
                            </div>
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="banca"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Banca</FormLabel>
                          <FormControl>
                            <div className="relative">
                              <Building className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-500" />
                              <Input {...field} className="pl-10 bg-background border-border" />
                            </div>
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="bic_swift"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">BIC/SWIFT</FormLabel>
                          <FormControl>
                            <Input {...field} className="bg-background border-border" />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>
                </div>

                {/* Notes */}
                <div className="space-y-4">
                   <FormField
                    control={form.control}
                    name="note"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Note</FormLabel>
                        <FormControl>
                          <Textarea {...field} className="bg-background border-border" />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>
              </div>
            </ScrollArea>

            <DialogFooter className="pt-4 border-t border-border gap-2">
              <Button type="button" variant="ghost" onClick={() => onOpenChange(false)} className="text-slate-400">
                Annulla
              </Button>
              <Button type="submit" disabled={mutation.isPending} className="bg-primary hover:bg-primary/90 text-white font-black uppercase tracking-widest text-[10px] min-w-[120px]">
                {mutation.isPending ? <Loader2 className="h-4 w-4 animate-spin" /> : (isEdit ? "Salva Modifiche" : "Crea Collaboratore")}
              </Button>
            </DialogFooter>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

