const ROUTE_HELP_MAP: Record<string, string[]> = {
  "/": ["dashboard"],
  "/analytics": ["dashboard"],
  "/clienti": ["clienti"],
  "/crm": ["clienti"],
  "/progetti": ["progetti"],
  "/commesse": ["progetti"],
