import { useState, useEffect, useRef, useCallback } from "react";
import DOMPurify from "dompurify";
import {
  Bold,
  Italic,
  Heading1,
  Heading2,
  List,
  ListOrdered,
  Code,
  Minus,
  Eye,
  EyeOff,
  Save,
  CheckCircle2,
  Clock,
  FileText,
  Folder,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useDocuments } from "@/hooks/useDocuments";
import type { DocumentNode } from "@/types/document";
import { format } from "date-fns";
import { it } from "date-fns/locale";

interface DocumentEditorProps {
  node: DocumentNode | null;
  className?: string;
}

type SaveStatus = "idle" | "saving" | "saved";

function markdownToHtml(md: string): string {
  // 1. ESCAPE RAW HTML (Prevention of XSS)
  const escaped = md
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");

  return escaped
    // Headings
    .replace(/^### (.+)$/gm, '<h3 class="text-lg font-black mt-6 mb-2 text-foreground">$1</h3>')
    .replace(/^## (.+)$/gm, '<h2 class="text-xl font-black mt-8 mb-3 text-foreground">$1</h2>')
    .replace(/^# (.+)$/gm, '<h1 class="text-2xl font-black mt-8 mb-4 text-foreground">$1</h1>')
    // Bold & Italic
    .replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    // Inline code
    .replace(/`([^`]+)`/g, '<code class="bg-muted/50 px-1.5 py-0.5 rounded text-[0.9em] font-mono text-primary/80">$1</code>')
    // HR
    .replace(/^---$/gm, '<hr class="border-border/30 my-6" />')
    // Unordered list items
    .replace(/^- (.+)$/gm, '<li class="ml-4 list-disc">$1</li>')
    // Ordered list items
    .replace(/^\d+\. (.+)$/gm, '<li class="ml-4 list-decimal">$1</li>')
    // Checkboxes
    .replace(/^- \[x\] (.+)$/gm, '<li class="ml-4 flex items-center gap-2"><input type="checkbox" checked disabled class="rounded" /><span class="line-through opacity-50">$1</span></li>')
    .replace(/^- \[ \] (.+)$/gm, '<li class="ml-4 flex items-center gap-2"><input type="checkbox" disabled class="rounded" /><span>$1</span></li>')
    // Paragraphs (blank lines)
    .replace(/\n\n/g, '</p><p class="mb-3">')
    // Line breaks
    .replace(/\n/g, '<br />');
}

export function DocumentEditor({ node, className }: DocumentEditorProps) {
  const { updateNode, fetchNode } = useDocuments();
  const [content, setContent] = useState("");
  const [saveStatus, setSaveStatus] = useState<SaveStatus>("idle");
  const [preview, setPreview] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const saveTimeout = useRef<ReturnType<typeof setTimeout> | null>(null);
  const lastSavedRef = useRef<string>("");

  // Load node content when selection changes
  useEffect(() => {
    if (!node || node.tipo === "FOLDER") {
      setContent("");
      setLoaded(false);
      return;
    }
    setLoaded(false);
    fetchNode(node.id).then((full) => {
      const c = full.contenuto ?? "";
      setContent(c);
      lastSavedRef.current = c;
      setLoaded(true);
    });
  }, [node?.id]);

  // Auto-save with 1.5s debounce
  const save = useCallback(
    async (text: string) => {
      if (!node || node.tipo === "FOLDER") return;
      if (text === lastSavedRef.current) return;
      setSaveStatus("saving");
      try {
        await updateNode.mutateAsync({ id: node.id, data: { contenuto: text } });
        lastSavedRef.current = text;
        setSaveStatus("saved");
        setTimeout(() => setSaveStatus("idle"), 2000);
      } catch {
        setSaveStatus("idle");
      }
    },
    [node, updateNode]
  );

  const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const v = e.target.value;
    setContent(v);
    if (saveTimeout.current) clearTimeout(saveTimeout.current);
    saveTimeout.current = setTimeout(() => save(v), 1500);
  };

  // Toolbar action: wrap selection or insert at cursor
  const insertMarkdown = (before: string, after: string = "") => {
    const ta = textareaRef.current;
    if (!ta) return;
    const { selectionStart: s, selectionEnd: e, value } = ta;
    const selected = value.slice(s, e);
    const newVal = value.slice(0, s) + before + selected + after + value.slice(e);
    setContent(newVal);
    // Restore cursor
    setTimeout(() => {
      ta.focus();
      ta.setSelectionRange(s + before.length, e + before.length);
    }, 0);
    if (saveTimeout.current) clearTimeout(saveTimeout.current);
    saveTimeout.current = setTimeout(() => save(newVal), 1500);
  };

  const insertLine = (prefix: string) => {
    const ta = textareaRef.current;
    if (!ta) return;
    const { selectionStart: s, value } = ta;
    const lineStart = value.lastIndexOf("\n", s - 1) + 1;
    const newVal = value.slice(0, lineStart) + prefix + value.slice(lineStart);
    setContent(newVal);
    setTimeout(() => {
      ta.focus();
      ta.setSelectionRange(s + prefix.length, s + prefix.length);
    }, 0);
    if (saveTimeout.current) clearTimeout(saveTimeout.current);
    saveTimeout.current = setTimeout(() => save(newVal), 1500);
  };

  // Keyboard shortcuts
  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.ctrlKey || e.metaKey) {
      if (e.key === "b") { e.preventDefault(); insertMarkdown("**", "**"); }
      if (e.key === "i") { e.preventDefault(); insertMarkdown("*", "*"); }
      if (e.key === "s") { e.preventDefault(); save(content); }
      if (e.key === "p") { e.preventDefault(); setPreview((v) => !v); }
    }
    // Tab = 2 spaces
    if (e.key === "Tab") {
      e.preventDefault();
      insertMarkdown("  ");
    }
  };

  const wordCount = content.trim() ? content.trim().split(/\s+/).length : 0;
  const charCount = content.length;

  // Empty state
  if (!node) {
    return (
      <div className={cn("flex flex-col items-center justify-center h-full opacity-20 gap-4", className)}>
        <FileText size={64} strokeWidth={1} />
        <p className="text-sm font-black uppercase tracking-[0.3em]">Seleziona un file</p>
        <p className="text-xs font-medium tracking-widest uppercase">per iniziare a scrivere</p>
      </div>
    );
  }

  // Folder state
  if (node.tipo === "FOLDER") {
    return (
      <div className={cn("flex flex-col items-center justify-center h-full opacity-20 gap-4", className)}>
        <Folder size={64} strokeWidth={1} />
        <p className="text-sm font-black uppercase tracking-[0.3em]">{node.nome}</p>
        <p className="text-xs font-medium tracking-widest uppercase">Seleziona un file nella cartella</p>
      </div>
    );
  }

  return (
    <div className={cn("flex flex-col h-full", className)}>
      {/* Header bar */}
      <div className="flex items-center justify-between px-6 py-3 border-b border-border/20 bg-card/30 shrink-0">
        <div className="flex items-center gap-3">
          <span className="text-lg">{node.icona || "📄"}</span>
          <div>
            <h2 className="text-sm font-black uppercase tracking-tight text-foreground leading-none mb-0.5">
              {node.nome}
            </h2>
            <p className="text-[10px] text-muted-foreground/50 font-medium">
              Modificato {format(new Date(node.updated_at), "d MMM yyyy, HH:mm", { locale: it })}
            </p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          {/* Save status */}
          <div className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest">
            {saveStatus === "saving" && (
              <span className="flex items-center gap-1 text-muted-foreground/50">
                <Clock size={10} className="animate-spin" /> Salvataggio...
              </span>
            )}
            {saveStatus === "saved" && (
              <span className="flex items-center gap-1 text-emerald-400/80">
                <CheckCircle2 size={10} /> Salvato
              </span>
            )}
          </div>

          {/* Preview toggle */}
          <button
            onClick={() => setPreview((v) => !v)}
            className={cn(
              "flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all",
              preview
                ? "bg-primary/10 text-primary border border-primary/20"
                : "bg-muted/30 text-muted-foreground hover:bg-muted/50"
            )}
            title="Ctrl+P"
          >
            {preview ? <EyeOff size={12} /> : <Eye size={12} />}
            {preview ? "Editor" : "Preview"}
          </button>

          {/* Manual save */}
          <button
            onClick={() => save(content)}
            className="flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg bg-primary/90 text-white hover:bg-primary text-[10px] font-black uppercase tracking-widest transition-all hover:scale-[1.02] active:scale-95 shadow-lg shadow-primary/20"
            title="Ctrl+S"
          >
            <Save size={12} /> Salva
          </button>
        </div>
      </div>

      {/* Formatting toolbar */}
      {!preview && (
        <div className="flex items-center gap-0.5 px-4 py-1.5 border-b border-border/10 bg-muted/5 shrink-0 flex-wrap">
          {[
            { icon: <Heading1 size={14} />, title: "Titolo H1 (# )", action: () => insertLine("# ") },
            { icon: <Heading2 size={14} />, title: "Titolo H2 (## )", action: () => insertLine("## ") },
            { icon: <Bold size={14} />, title: "Grassetto (Ctrl+B)", action: () => insertMarkdown("**", "**") },
            { icon: <Italic size={14} />, title: "Corsivo (Ctrl+I)", action: () => insertMarkdown("*", "*") },
            { icon: <Code size={14} />, title: "Codice inline", action: () => insertMarkdown("`", "`") },
            { icon: <List size={14} />, title: "Lista puntata", action: () => insertLine("- ") },
            { icon: <ListOrdered size={14} />, title: "Lista numerata", action: () => insertLine("1. ") },
            { icon: <Minus size={14} />, title: "Separatore (---)", action: () => insertLine("---") },
          ].map((btn, i) => (
            <button
              key={i}
              title={btn.title}
              onClick={btn.action}
              className="p-1.5 rounded-md text-muted-foreground/60 hover:text-foreground hover:bg-white/[0.06] transition-colors"
            >
              {btn.icon}
            </button>
          ))}
        </div>
      )}

      {/* Content area */}
      <div className="flex-1 overflow-hidden relative">
        {!loaded ? (
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="w-8 h-8 border-2 border-primary/30 border-t-primary rounded-full animate-spin" />
          </div>
        ) : preview ? (
          <div
            className="h-full overflow-y-auto px-8 py-8 prose prose-invert prose-sm max-w-none custom-scrollbar text-foreground/90 leading-relaxed text-[14px]"
            dangerouslySetInnerHTML={{
              __html: DOMPurify.sanitize(
                content
                  ? `<p class="mb-3">${markdownToHtml(content)}</p>`
                  : '<p class="text-muted-foreground/30 italic text-sm">Nessun contenuto da visualizzare. Inizia a scrivere nell\'editor.</p>',
                { USE_PROFILES: { html: true } }
              ),
            }}
          />
        ) : (
          <textarea
            ref={textareaRef}
            value={content}
            onChange={handleChange}
            onKeyDown={handleKeyDown}
            placeholder="Inizia a scrivere... (supporta Markdown)"
            className={cn(
              "w-full h-full resize-none bg-transparent border-0 outline-none px-8 py-6",
              "text-[14px] leading-7 font-mono text-foreground/90 placeholder:text-muted-foreground/20",
              "focus:outline-none focus:ring-0 custom-scrollbar"
            )}
            spellCheck={false}
          />
        )}
      </div>

      {/* Status bar */}
      <div className="flex items-center justify-between px-6 py-1.5 border-t border-border/10 bg-muted/5 shrink-0">
        <div className="flex items-center gap-3 text-[9px] font-black uppercase tracking-[0.2em] text-muted-foreground/30">
          <span>{wordCount} parole</span>
          <span>{charCount} caratteri</span>
        </div>
        <div className="text-[9px] font-black uppercase tracking-[0.2em] text-muted-foreground/25">
          Markdown · Enter per invio · Ctrl+S per salvare
        </div>
      </div>
    </div>
  );
}

import { useState, useRef, useEffect, useCallback } from "react";
import {
  FilePlus,
  FolderPlus,
  Search,
  X,
  FileText,
  Folder,
  ChevronDown,
  ChevronUp,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useDocuments } from "@/hooks/useDocuments";
import { DocumentTreeNode } from "./DocumentTreeNode";
import type { DocumentNode } from "@/types/document";

// Inline "new item" creation row
interface NewItemRowProps {
  parentId: string | null;
  tipo: "FOLDER" | "FILE";
  depth: number;
  onConfirm: (name: string) => void;
  onCancel: () => void;
}

function NewItemRow({ parentId: _parentId, tipo, depth, onConfirm, onCancel }: NewItemRowProps) {
  const [name, setName] = useState("");
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const commit = () => {
    const trimmed = name.trim();
    if (trimmed) onConfirm(trimmed);
    else onCancel();
  };

  return (
    <div
      className="flex items-center gap-1.5 h-[28px] px-1"
      style={{ paddingLeft: `${depth * 12 + 24}px` }}
    >
      {tipo === "FOLDER" ? (
        <Folder size={14} className="shrink-0 text-primary" />
      ) : (
        <FileText size={14} className="shrink-0 text-muted-foreground/70" />
      )}
      <input
        ref={inputRef}
        value={name}
        onChange={(e) => setName(e.target.value)}
        onBlur={commit}
        onKeyDown={(e) => {
          if (e.key === "Enter") commit();
          if (e.key === "Escape") onCancel();
        }}
        placeholder={tipo === "FOLDER" ? "Nome cartella..." : "Nome file..."}
        className="flex-1 bg-background border border-primary/60 rounded px-1.5 py-0.5 text-[12px] font-medium outline-none focus:ring-1 focus:ring-primary/50 min-w-0"
      />
    </div>
  );
}

// Flatten tree for search
function flattenTree(nodes: DocumentNode[]): DocumentNode[] {
  const result: DocumentNode[] = [];
  const walk = (ns: DocumentNode[]) => {
    for (const n of ns) {
      result.push(n);
      if (n.children?.length) walk(n.children);
    }
  };
  walk(nodes);
  return result;
}

interface DocumentExplorerProps {
  selectedId: string | null;
  onSelect: (node: DocumentNode) => void;
  className?: string;
}

interface PendingCreate {
  parentId: string | null;
  tipo: "FOLDER" | "FILE";
  depth: number;
}

export function DocumentExplorer({ selectedId, onSelect, className }: DocumentExplorerProps) {
  const { tree, isLoading, createNode, updateNode, deleteNode } = useDocuments();
  const [searchQuery, setSearchQuery] = useState("");
  const [pendingCreate, setPendingCreate] = useState<PendingCreate | null>(null);

  // === SEARCH ===
  const allNodes = flattenTree(tree);
  const searchResults = searchQuery.trim()
    ? allNodes.filter((n) =>
        n.nome.toLowerCase().includes(searchQuery.toLowerCase())
      )
    : null;

  // === CREATE ===
  const handleCreate = useCallback(
    (parentId: string | null, tipo: "FOLDER" | "FILE") => {
      // Calculate depth
      const findDepth = (nodes: DocumentNode[], targetId: string | null, d = 0): number => {
        if (!targetId) return 0;
        for (const n of nodes) {
          if (n.id === targetId) return d + 1;
          const found = findDepth(n.children, targetId, d + 1);
          if (found > 0) return found;
        }
        return 0;
      };
      const depth = findDepth(tree, parentId);
      setPendingCreate({ parentId, tipo, depth });
    },
    [tree]
  );

  const confirmCreate = async (name: string) => {
    if (!pendingCreate) return;
    await createNode.mutateAsync({
      nome: name,
      tipo: pendingCreate.tipo,
      parent_id: pendingCreate.parentId,
    });
    setPendingCreate(null);
  };

  // === RENAME ===
  const handleRename = (id: string, newName: string) => {
    updateNode.mutate({ id, data: { nome: newName } });
  };

  // === DELETE ===
  const handleDelete = (id: string) => {
    if (window.confirm("Eliminare questo elemento e tutto il suo contenuto?")) {
      deleteNode.mutate(id);
      if (selectedId === id) onSelect(null as any);
    }
  };

  return (
    <div className={cn("flex flex-col h-full bg-card/5", className)}>
      {/* Header */}
      <div className="px-3 py-3 border-b border-border/20 shrink-0">
        <div className="flex items-center justify-between mb-2">
          <span className="text-[10px] font-black uppercase tracking-[0.25em] text-muted-foreground/50">
            File
          </span>
          <div className="flex items-center gap-0.5">
            <button
              title="Nuovo file"
              onClick={() => handleCreate(null, "FILE")}
              className="p-1 rounded hover:bg-white/10 text-muted-foreground hover:text-primary transition-colors"
            >
              <FilePlus size={14} />
            </button>
            <button
              title="Nuova cartella"
              onClick={() => handleCreate(null, "FOLDER")}
              className="p-1 rounded hover:bg-white/10 text-muted-foreground hover:text-primary transition-colors"
            >
              <FolderPlus size={14} />
            </button>
          </div>
        </div>

        {/* Search */}
        <div className="relative">
          <Search className="absolute left-2 top-1/2 -translate-y-1/2 w-3 h-3 text-muted-foreground/40" />
          <input
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Cerca file..."
            className="w-full bg-background/40 border border-border/20 rounded-lg pl-7 pr-7 py-1.5 text-[11px] font-medium placeholder:text-muted-foreground/30 focus:outline-none focus:border-primary/40 transition-colors"
          />
          {searchQuery && (
            <button
              onClick={() => setSearchQuery("")}
              className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground/40 hover:text-foreground transition-colors"
            >
              <X size={10} />
            </button>
          )}
        </div>
      </div>

      {/* Tree Area */}
      <div className="flex-1 overflow-y-auto py-1 pr-1 custom-scrollbar">
        {isLoading ? (
          <div className="px-3 py-4 space-y-2">
            {[1, 2, 3, 4].map((i) => (
              <div key={i} className="h-[22px] bg-muted/20 rounded animate-pulse" style={{ width: `${60 + i * 8}%` }} />
            ))}
          </div>
        ) : searchResults ? (
          /* Search results */
          <div className="px-1 py-1">
            {searchResults.length === 0 ? (
              <p className="text-[10px] text-muted-foreground/40 font-medium italic px-3 py-4 text-center">
                Nessun risultato trovato.
              </p>
            ) : (
              searchResults.map((node) => (
                <button
                  key={node.id}
                  onClick={() => onSelect(node)}
                  className={cn(
                    "w-full flex items-center gap-2 h-[28px] px-3 rounded-md text-[12px] font-medium transition-colors",
                    selectedId === node.id
                      ? "bg-primary/10 text-primary"
                      : "hover:bg-white/[0.04] text-foreground/70"
                  )}
                >
                  {node.tipo === "FOLDER" ? (
                    <Folder size={13} className="shrink-0 text-primary/70" />
                  ) : (
                    <FileText size={13} className="shrink-0 text-muted-foreground/60" />
                  )}
                  <span className="truncate">{node.nome}</span>
                </button>
              ))
            )}
          </div>
        ) : tree.length === 0 ? (
          /* Empty state */
          <div className="flex flex-col items-center justify-center py-16 px-4 text-center gap-4">
            <div className="w-16 h-16 rounded-2xl bg-primary/5 border border-primary/10 flex items-center justify-center">
              <Folder size={28} className="text-primary/30" />
            </div>
            <div>
              <p className="text-[11px] font-black uppercase tracking-[0.2em] text-muted-foreground/40 mb-1">
                Nessun file ancora
              </p>
              <p className="text-[10px] text-muted-foreground/30 font-medium">
                Crea una cartella o un file per iniziare
              </p>
            </div>
            <div className="flex gap-2">
              <button
                onClick={() => handleCreate(null, "FOLDER")}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-primary/10 hover:bg-primary/20 text-primary rounded-lg text-[10px] font-black uppercase tracking-widest transition-colors"
              >
                <FolderPlus size={12} /> Cartella
              </button>
              <button
                onClick={() => handleCreate(null, "FILE")}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-muted/30 hover:bg-muted/50 text-muted-foreground rounded-lg text-[10px] font-black uppercase tracking-widest transition-colors"
              >
                <FilePlus size={12} /> File
              </button>
            </div>
          </div>
        ) : (
          <>
            {/* Root-level pending create */}
            {pendingCreate && pendingCreate.parentId === null && (
              <NewItemRow
                parentId={null}
                tipo={pendingCreate.tipo}
                depth={0}
                onConfirm={confirmCreate}
                onCancel={() => setPendingCreate(null)}
              />
            )}

            {tree.map((node) => (
              <DocumentTreeNode
                key={node.id}
                node={node}
                depth={0}
                selectedId={selectedId}
                onSelect={onSelect}
                onCreate={(parentId, tipo) => {
                  // Show inline create row inside this folder
                  handleCreate(parentId, tipo);
                }}
                onRename={handleRename}
                onDelete={handleDelete}
              />
            ))}

            {/* Nested pending create (shown after the target folder's children) */}
            {pendingCreate && pendingCreate.parentId !== null && (
              <NewItemRow
                parentId={pendingCreate.parentId}
                tipo={pendingCreate.tipo}
                depth={pendingCreate.depth}
                onConfirm={confirmCreate}
                onCancel={() => setPendingCreate(null)}
              />
            )}
          </>
        )}
      </div>
    </div>
  );
}

import { useState, useRef, useEffect, useCallback } from "react";
import {
  ChevronRight,
  Folder,
  FolderOpen,
  FileText,
  Plus,
  Trash2,
  Pencil,
  FolderPlus,
  FilePlus,
  MoreHorizontal,
} from "lucide-react";
import { cn } from "@/lib/utils";
import type { DocumentNode } from "@/types/document";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

interface DocumentTreeNodeProps {
  node: DocumentNode;
  depth?: number;
  selectedId: string | null;
  onSelect: (node: DocumentNode) => void;
  onCreate: (parentId: string, tipo: "FOLDER" | "FILE") => void;
  onRename: (id: string, newName: string) => void;
  onDelete: (id: string) => void;
}

export function DocumentTreeNode({
  node,
  depth = 0,
  selectedId,
  onSelect,
  onCreate,
  onRename,
  onDelete,
}: DocumentTreeNodeProps) {
  const [isOpen, setIsOpen] = useState(depth === 0);
  const [isRenaming, setIsRenaming] = useState(false);
  const [renameValue, setRenameValue] = useState(node.nome);
  const [showActions, setShowActions] = useState(false);
  const renameRef = useRef<HTMLInputElement>(null);

  const isFolder = node.tipo === "FOLDER";
  const isSelected = selectedId === node.id;

  // Auto-focus rename input
  useEffect(() => {
    if (isRenaming && renameRef.current) {
      renameRef.current.focus();
      renameRef.current.select();
    }
  }, [isRenaming]);

  const commitRename = useCallback(() => {
    const trimmed = renameValue.trim();
    if (trimmed && trimmed !== node.nome) {
      onRename(node.id, trimmed);
    } else {
      setRenameValue(node.nome);
    }
    setIsRenaming(false);
  }, [renameValue, node.nome, node.id, onRename]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Enter") commitRename();
    if (e.key === "Escape") {
      setRenameValue(node.nome);
      setIsRenaming(false);
    }
    e.stopPropagation();
  };

  const handleRowClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (isFolder) setIsOpen((v) => !v);
    onSelect(node);
  };

  const handleRowDoubleClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsRenaming(true);
    setRenameValue(node.nome);
  };

  // File/folder icon with emoji override
  const renderIcon = () => {
    if (node.icona) {
      return <span className="text-base leading-none">{node.icona}</span>;
    }
    if (isFolder) {
      return isOpen ? (
        <FolderOpen
          size={15}
          className="shrink-0"
          style={{ color: node.colore || "hsl(var(--primary))" }}
        />
      ) : (
        <Folder
          size={15}
          className="shrink-0"
          style={{ color: node.colore || "hsl(var(--primary))" }}
        />
      );
    }
    return <FileText size={14} className="shrink-0 text-muted-foreground/70" />;
  };

  return (
    <div className="select-none">
      <div
        className={cn(
          "group/row flex items-center gap-0.5 h-[28px] px-1 rounded-md cursor-pointer transition-colors relative",
          isSelected
            ? "bg-primary/10 text-primary"
            : "hover:bg-white/[0.04] text-foreground/75 hover:text-foreground"
        )}
        style={{ paddingLeft: `${depth * 12 + 4}px` }}
        onClick={handleRowClick}
        onDoubleClick={handleRowDoubleClick}
        onMouseEnter={() => setShowActions(true)}
        onMouseLeave={() => setShowActions(false)}
      >
        {/* Chevron (folders only) */}
        <span className="w-4 h-4 flex items-center justify-center shrink-0">
          {isFolder && (
            <ChevronRight
              size={12}
              className={cn(
                "transition-transform duration-150 text-muted-foreground/50",
                isOpen && "rotate-90"
              )}
            />
          )}
        </span>

        {/* Icon */}
        <span className="flex items-center justify-center w-5 shrink-0">
          {renderIcon()}
        </span>

        {/* Name or rename input */}
        {isRenaming ? (
          <input
            ref={renameRef}
            value={renameValue}
            onChange={(e) => setRenameValue(e.target.value)}
            onBlur={commitRename}
            onKeyDown={handleKeyDown}
            onClick={(e) => e.stopPropagation()}
            className="flex-1 bg-background border border-primary/60 rounded px-1.5 py-0.5 text-[12px] font-medium outline-none focus:ring-1 focus:ring-primary/50 min-w-0"
          />
        ) : (
          <span className="flex-1 text-[12px] font-medium truncate leading-none">
            {node.nome}
          </span>
        )}

        {/* Action buttons (appear on hover) */}
        {!isRenaming && (showActions || isSelected) && (
          <div
            className="flex items-center gap-0.5 ml-auto shrink-0"
            onClick={(e) => e.stopPropagation()}
          >
            {isFolder && (
              <>
                <button
                  title="Nuovo file"
                  className="p-1 rounded hover:bg-white/10 text-muted-foreground hover:text-foreground transition-colors"
                  onClick={(e) => {
                    e.stopPropagation();
                    setIsOpen(true);
                    onCreate(node.id, "FILE");
                  }}
                >
                  <FilePlus size={12} />
                </button>
                <button
                  title="Nuova cartella"
                  className="p-1 rounded hover:bg-white/10 text-muted-foreground hover:text-foreground transition-colors"
                  onClick={(e) => {
                    e.stopPropagation();
                    setIsOpen(true);
                    onCreate(node.id, "FOLDER");
                  }}
                >
                  <FolderPlus size={12} />
                </button>
              </>
            )}

            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <button
                  title="Altro"
                  className="p-1 rounded hover:bg-white/10 text-muted-foreground hover:text-foreground transition-colors"
                >
                  <MoreHorizontal size={12} />
                </button>
              </DropdownMenuTrigger>
              <DropdownMenuContent
                className="bg-card border-border rounded-xl shadow-2xl w-44"
                align="start"
              >
                <DropdownMenuItem
                  className="text-[11px] font-bold cursor-pointer gap-2"
                  onClick={() => { setIsRenaming(true); setRenameValue(node.nome); }}
                >
                  <Pencil size={12} /> Rinomina
                </DropdownMenuItem>
                {isFolder && (
                  <>
                    <DropdownMenuItem
                      className="text-[11px] font-bold cursor-pointer gap-2"
                      onClick={() => { setIsOpen(true); onCreate(node.id, "FILE"); }}
                    >
                      <FilePlus size={12} /> Nuovo File
                    </DropdownMenuItem>
                    <DropdownMenuItem
                      className="text-[11px] font-bold cursor-pointer gap-2"
                      onClick={() => { setIsOpen(true); onCreate(node.id, "FOLDER"); }}
                    >
                      <FolderPlus size={12} /> Nuova Cartella
                    </DropdownMenuItem>
                  </>
                )}
                <DropdownMenuSeparator />
                <DropdownMenuItem
                  className="text-[11px] font-bold cursor-pointer gap-2 text-destructive focus:text-destructive"
                  onClick={() => onDelete(node.id)}
                >
                  <Trash2 size={12} /> Elimina
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        )}
      </div>

      {/* Children */}
      {isFolder && isOpen && node.children.length > 0 && (
        <div>
          {node.children.map((child) => (
            <DocumentTreeNode
              key={child.id}
              node={child}
              depth={depth + 1}
              selectedId={selectedId}
              onSelect={onSelect}
              onCreate={onCreate}
              onRename={onRename}
              onDelete={onDelete}
            />
          ))}
        </div>
      )}

      {/* Empty folder hint */}
      {isFolder && isOpen && node.children.length === 0 && (
        <div
          className="text-[10px] text-muted-foreground/30 font-medium italic px-2 py-1"
          style={{ paddingLeft: `${(depth + 1) * 12 + 20}px` }}
        >
          Cartella vuota
        </div>
      )}
    </div>
  );
}

import React, { useRef, useState, useEffect } from "react";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  PieChart,
  Pie,
  Cell
} from "recharts";

function useChartSize(height: number): [React.RefObject<HTMLDivElement>, number, number] {
  const ref = useRef<HTMLDivElement>(null);
  const [width, setWidth] = useState(0);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const ro = new ResizeObserver(([entry]) => setWidth(entry.contentRect.width));
    ro.observe(el);
    return () => ro.disconnect();
  }, []);
  return [ref, width, height];
}
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Wallet, ArrowUpRight, ArrowDownLeft } from "lucide-react";

interface CassaDashboardProps {
  movimenti: any[];
}

const COLORS = ["hsl(var(--primary))", "#10b981", "#3b82f6", "#f59e0b", "#ef4444", "#ec4899"];

export function CassaDashboard({ movimenti }: CassaDashboardProps) {
  const [chart1Ref, chart1W, chart1H] = useChartSize(280);
  const [chart2Ref, chart2W, chart2H] = useChartSize(230);
  const chartData = React.useMemo(() => {
    // Raggruppa per data e calcola saldo progressivo
    const daily = movimenti.reduce((acc: any, m) => {
      const date = m.data_valuta;
      if (!acc[date]) acc[date] = 0;
      acc[date] += Number(m.importo);
      return acc;
    }, {});

    return Object.keys(daily)
      .sort()
      .reduce<{ date: string; balance: number; amount: number }[]>((items, date) => {
        const previousBalance = items[items.length - 1]?.balance ?? 0;
        const amount = daily[date];
        return [...items, { date, balance: previousBalance + amount, amount }];
      }, []);
  }, [movimenti]);

  const categoryData = React.useMemo(() => {
    const cats = movimenti.reduce((acc: any, m) => {
      const cat = m.categoria || "Altro";
      if (!acc[cat]) acc[cat] = 0;
      acc[cat] += Math.abs(Number(m.importo));
      return acc;
    }, {});

    return Object.entries(cats).map(([name, value]) => ({ name, value }));
  }, [movimenti]);

  const totalIn = movimenti.filter(m => Number(m.importo) > 0).reduce((acc, m) => acc + Number(m.importo), 0);
  const totalOut = movimenti.filter(m => Number(m.importo) < 0).reduce((acc, m) => acc + Math.abs(Number(m.importo)), 0);

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <Card className="bg-card/30 border-border/50 rounded-[2rem] overflow-hidden backdrop-blur-xl">
          <CardHeader className="pb-2">
            <CardTitle className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground/60 flex items-center gap-2">
              <Wallet className="h-3.5 w-3.5 text-primary" />
              Saldo Attuale
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-black text-white tabular-nums tracking-tighter">
              {new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(totalIn - totalOut)}
            </div>
            <p className="text-[10px] font-bold text-[#475569] uppercase mt-1">Disponibilità liquida totale</p>
          </CardContent>
        </Card>

        <Card className="bg-card/30 border-border/50 rounded-[2rem] overflow-hidden backdrop-blur-xl transition-all hover:border-emerald-500/30">
          <CardHeader className="pb-2">
            <CardTitle className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground/60 flex items-center gap-2">
              <ArrowUpRight className="h-3.5 w-3.5 text-emerald-500" />
              Entrate (Mese)
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-black text-emerald-500 tabular-nums tracking-tighter">
              {new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(totalIn)}
            </div>
          </CardContent>
        </Card>

        <Card className="bg-card/30 border-border/50 rounded-[2rem] overflow-hidden backdrop-blur-xl transition-all hover:border-red-500/30">
          <CardHeader className="pb-2">
            <CardTitle className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground/60 flex items-center gap-2">
              <ArrowDownLeft className="h-3.5 w-3.5 text-red-500" />
              Uscite (Mese)
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-black text-red-500 tabular-nums tracking-tighter">
              {new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(totalOut)}
            </div>
          </CardContent>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <Card className="lg:col-span-2 bg-card/30 border-border/50 rounded-[2rem] p-8 backdrop-blur-xl overflow-hidden relative">
          <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground/60 mb-8 px-1">Andamento Cashflow</h3>
          <div ref={chart1Ref} style={{ width: '100%', height: '280px' }}>
            {chart1W > 0 && (
              <AreaChart width={chart1W} height={chart1H} data={chartData}>
                <defs>
                  <linearGradient id="colorBalance" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#7c3aed" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#7c3aed" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                <XAxis
                  dataKey="date"
                  stroke="#475569"
                  fontSize={10}
                  tickFormatter={(val) => new Date(val).toLocaleDateString('it-IT', { day: '2-digit', month: 'short' })}
                />
                <YAxis stroke="#475569" fontSize={10} tickFormatter={(val) => `${val/1000}k`} />
                <Tooltip
                  contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '12px' }}
                  itemStyle={{ color: '#fff', fontSize: '10px', fontWeight: 'bold' }}
                />
                <Area type="monotone" dataKey="balance" stroke="#7c3aed" strokeWidth={3} fillOpacity={1} fill="url(#colorBalance)" />
              </AreaChart>
            )}
          </div>
        </Card>

        <Card className="bg-card/30 border-border/50 rounded-[2rem] p-8 backdrop-blur-xl overflow-hidden">
          <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground/60 mb-8 px-1">Analisi Categorie</h3>
          <div ref={chart2Ref} style={{ width: '100%', height: '230px' }}>
            {chart2W > 0 && (
              <PieChart width={chart2W} height={chart2H}>
                <Pie
                  data={categoryData}
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((_, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            )}
          </div>
          <div className="mt-4 space-y-2">
             {categoryData.slice(0, 4).map((c, i) => (
               <div key={c.name} className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <div className="h-2 w-2 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }} />
                    <span className="text-[10px] font-bold text-muted-foreground uppercase">{c.name}</span>
                  </div>
                  <span className="text-[10px] font-black text-white tabular-nums">{new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(Number(c.value))}</span>
               </div>
             ))}
          </div>
        </Card>
      </div>
    </div>
  );
}

import React from "react";
