interface FatturaDetailDialogProps {
  fattura: any | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  type: "attive" | "passive";
}

export function FatturaDetailDialog({
  fattura,
  open,
  onOpenChange,
  type
}: FatturaDetailDialogProps) {
  const navigate = useNavigate();
  const incassaMutation = useIncassaFattura();
  const updateMutation = useUpdateFattura();

  if (!fattura) return null;

  const isAttiva = type === "attive";
  const entity = isAttiva ? fattura.cliente : fattura.fornitore;
  
  // Extract items from fic_raw_data if available
  const items = fattura.fic_raw_data?.items || fattura.fic_raw_data?.details || [];

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(val);
  };

  const getStatusBadge = (status: string) => {
    const s = status.toLowerCase();
    if (s === "paid" || s === "incassata" || s === "pagata") {
      return (
        <Badge className="bg-emerald-500/10 text-emerald-500 border-emerald-500/20 gap-1.5 font-bold px-3 py-1 uppercase text-[10px] tracking-widest">
          <CheckCircle2 className="h-3.5 w-3.5" />
          Pagata
        </Badge>
      );
    }
    if (s === "overdue" || s === "scaduta") {
      return (
        <Badge className="bg-red-500/10 text-red-500 border-red-500/20 gap-1.5 font-bold px-3 py-1 uppercase text-[10px] tracking-widest">
          <AlertCircle className="h-3.5 w-3.5" />
          Scaduta
        </Badge>
      );
    }
    return (
      <Badge className="bg-amber-500/10 text-amber-500 border-amber-500/20 gap-1.5 font-bold px-3 py-1 uppercase text-[10px] tracking-widest">
        <Clock className="h-3.5 w-3.5" />
        In Attesa
      </Badge>
    );
  };

  const handleMarkAsPaid = async () => {
    try {
      if (isAttiva) {
        await incassaMutation.mutateAsync({ id: fattura.id, data_incasso: new Date().toISOString() });
      } else {
        await updateMutation.mutateAsync({ id: fattura.id, type: "passive", data: { stato_pagamento: "PAGATA", importo_pagato: fattura.importo_totale, importo_residuo: 0 } });
      }
      toast.success("Fattura segnata come pagata");
    } catch (err) {
      toast.error("Errore durante l'aggiornamento");
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl bg-card/95 backdrop-blur-2xl border-border/50 text-white rounded-[32px] overflow-hidden p-0 shadow-2xl">
        <div className="absolute top-0 left-0 w-full h-[6px] bg-gradient-to-r from-primary via-purple-500 to-blue-500" />
        
        <div className="p-8 space-y-8">
          {/* Header */}
          <div className="flex flex-col md:flex-row justify-between items-start gap-6">
            <div className="space-y-2">
              <div className="flex items-center gap-3">
                <div className="p-2.5 rounded-2xl bg-primary/10 border border-primary/20">
                  <FileText className="h-6 w-6 text-primary" />
                </div>
                <div>
                  <h2 className="text-2xl font-black tracking-tighter uppercase italic">
                    Fattura <span className="text-primary not-italic">#{fattura.numero || "N/A"}</span>
                  </h2>
                  <p className="text-[10px] font-bold text-[#475569] uppercase tracking-widest">
                    ID Interno: {fattura.id.split('-')[0]} • FIC ID: {fattura.fic_id}
                  </p>
                </div>
              </div>
            </div>
            
            <div className="flex flex-col items-end gap-3">
              {getStatusBadge(fattura.stato_pagamento)}
              <div className="flex items-center gap-2">
                 <Button variant="outline" size="sm" className="bg-white/5 border-border/50 text-xs font-bold rounded-xl h-9 hover:bg-white/10">
                    <Download className="h-3.5 w-3.5 mr-2" />
                    Scarica PDF
                 </Button>
                 <Button size="sm" className="bg-primary text-white text-xs font-bold rounded-xl h-9">
                    Vai su FIC
                    <ExternalLink className="h-3.5 w-3.5 ml-2" />
                 </Button>
              </div>
            </div>
          </div>

          <Separator className="bg-border/30" />

          {/* Info Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
            {/* Info Mittente/Destinatario */}
            <div className="space-y-6">
              <div className="space-y-3">
                <h3 className="text-[10px] font-black text-primary uppercase tracking-[0.2em]">
                  {isAttiva ? "Cliente / Destinatario" : "Fornitore / Mittente"}
                </h3>
                <div className="bg-white/5 border border-border/50 rounded-2xl p-5 space-y-4">
                  <div className="flex items-start gap-4">
                    <div className="h-12 w-12 rounded-xl bg-primary/10 flex items-center justify-center border border-primary/20 shrink-0">
                      <Building2 className="h-6 w-6 text-primary" />
                    </div>
                    <div 
                      className="cursor-pointer group/entity hover:bg-white/10 transition-all"
                      onClick={() => navigate(isAttiva ? `/clienti/${entity?.id}` : `/fornitori/${entity?.id}`)}
                    >
                      <h4 className="font-black text-white text-lg leading-tight uppercase group-hover/entity:text-primary transition-colors">
                        {entity?.ragione_sociale || fattura.fornitore_nome || "Dati non disponibili"}
                      </h4>
                      <p className="text-xs font-bold text-[#475569] mt-1 flex items-center gap-2">
                        P.IVA/CF: {entity?.piva || "N/A"}
                        <ExternalLink className="h-3 w-3 opacity-0 group-hover/entity:opacity-100 transition-opacity" />
                      </p>
                    </div>
                  </div>
                  
                  <div className="grid grid-cols-1 gap-3 pt-2">
                    <div className="flex items-center gap-3 text-sm text-muted-foreground">
                      <MapPin className="h-4 w-4 text-primary" />
                      <span className="font-medium">{entity?.indirizzo || "Indirizzo non specificato"}</span>
                    </div>
                    <div className="flex items-center gap-3 text-sm text-muted-foreground">
                      <Mail className="h-4 w-4 text-primary" />
                      <span className="font-medium">{entity?.email || "Email non presente"}</span>
                    </div>
                    {entity?.pec && (
                      <div className="flex items-center gap-3 text-sm text-muted-foreground">
                        <Receipt className="h-4 w-4 text-primary" />
                        <span className="font-bold text-[10px] uppercase">PEC: {entity.pec}</span>
                      </div>
                    )}
                    {entity?.sdi && (
                      <div className="flex items-center gap-3 text-sm text-muted-foreground">
                        <Info className="h-4 w-4 text-primary" />
                        <span className="font-bold text-[10px] uppercase text-primary/80">SDI: {entity.sdi}</span>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>

            {/* Dettagli Fattura */}
            <div className="space-y-6">
              <div className="space-y-3">
                <h3 className="text-[10px] font-black text-primary uppercase tracking-[0.2em]">Dettagli Documento</h3>
                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-white/5 border border-border/50 rounded-2xl p-4">
                    <div className="flex items-center gap-2 mb-2">
                      <Calendar className="h-3.5 w-3.5 text-primary" />
                      <span className="text-[9px] font-black uppercase text-[#475569]">Data Emissione</span>
                    </div>
                    <div className="text-lg font-black text-white tabular-nums">
                      {fattura.data_emissione ? format(new Date(fattura.data_emissione), "dd/MM/yyyy") : "—"}
                    </div>
                  </div>
                  <div className="bg-white/5 border border-border/50 rounded-2xl p-4">
                    <div className="flex items-center gap-2 mb-2">
                      <CreditCard className="h-3.5 w-3.5 text-primary" />
                      <span className="text-[9px] font-black uppercase text-[#475569]">Scadenza</span>
                    </div>
                    <div className="text-lg font-black text-white tabular-nums">
                      {fattura.data_scadenza ? format(new Date(fattura.data_scadenza), "dd/MM/yyyy") : "—"}
                    </div>
                  </div>
                </div>
                
                <div className="bg-primary/5 border border-primary/20 rounded-2xl p-6">
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-[10px] font-black uppercase text-primary tracking-widest">Totale Fattura</span>
                    <Badge className="bg-primary/20 text-primary border-primary/30 text-[9px] font-black uppercase tracking-widest">
                      {fattura.valuta || "EUR"}
                    </Badge>
                  </div>
                  <div className="text-4xl font-black text-white tracking-tighter tabular-nums drop-shadow-lg">
                    {formatCurrency(fattura.importo_totale)}
                  </div>
                  <div className="flex items-center justify-between mt-4 pt-4 border-t border-primary/10">
                    <div>
                      <span className="text-[9px] font-bold text-[#475569] uppercase block mb-1">Imponibile</span>
                      <span className="text-sm font-black text-white tabular-nums">{formatCurrency(fattura.importo_netto || 0)}</span>
                    </div>
                    <div className="text-right">
                      <span className="text-[9px] font-bold text-[#475569] uppercase block mb-1">IVA</span>
                      <span className="text-sm font-black text-white tabular-nums">{formatCurrency(fattura.importo_iva || 0)}</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Righe Fattura */}
          <div className="space-y-4">
            <h3 className="text-[10px] font-black text-primary uppercase tracking-[0.2em]">Elenco Prestazioni / Prodotti</h3>
            <div className="rounded-2xl border border-border/50 bg-white/5 overflow-hidden">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-white/5 border-b border-border/50">
                    <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest text-[#475569]">Descrizione</th>
                    <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest text-[#475569] text-center w-24">Quantità</th>
                    <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest text-[#475569] text-right w-32">Prezzo Unit.</th>
                    <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest text-[#475569] text-right w-32">Totale Riga</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/5">
                  {items.length > 0 ? (
                    items.map((item: any, idx: number) => (
                      <tr key={idx} className="hover:bg-white/5 transition-colors">
                        <td className="px-6 py-4">
                          <span className="text-xs font-bold text-white leading-relaxed block max-w-md">
                            {item.description || item.name || "N/A"}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-center">
                          <span className="text-xs font-mono font-bold text-[#475569]">
                            {item.qty || item.quantity || 1}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-right">
                          <span className="text-xs font-mono font-bold text-[#475569]">
                            {formatCurrency(item.net_price || item.price || 0)}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-right">
                          <span className="text-xs font-mono font-black text-white">
                            {formatCurrency(item.gross_amount || item.amount || 0)}
                          </span>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan={4} className="px-6 py-12 text-center text-xs font-bold text-[#475569] uppercase tracking-widest">
                        Dettaglio righe non disponibile per questo documento
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>

          {/* Footer stats */}
          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 bg-emerald-500/5 border border-emerald-500/20 rounded-2xl p-5 flex items-center justify-between">
              <div>
                <span className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Importo Pagato</span>
                <div className="text-xl font-black text-white tabular-nums mt-1">{formatCurrency(fattura.importo_pagato || 0)}</div>
              </div>
              <div className="h-10 w-10 rounded-full bg-emerald-500/10 flex items-center justify-center">
                <CheckCircle2 className="h-5 w-5 text-emerald-500" />
              </div>
            </div>
            <div className="flex-1 bg-rose-500/5 border border-rose-500/20 rounded-2xl p-5 flex items-center justify-between">
              <div>
                <span className="text-[9px] font-black text-rose-500 uppercase tracking-widest">Residuo da Pagare</span>
                <div className="text-xl font-black text-white tabular-nums mt-1">{formatCurrency(fattura.importo_residuo || 0)}</div>
              </div>
              <div className="h-10 w-10 rounded-full bg-rose-500/10 flex items-center justify-center">
                <Clock className="h-5 w-5 text-rose-500" />
              </div>
            </div>
          </div>

          {fattura.importo_residuo > 0 && (
            <div className="pt-4 flex gap-4">
              <Button 
                onClick={handleMarkAsPaid}
                className="flex-1 bg-emerald-500 hover:bg-emerald-600 text-white font-black uppercase text-[10px] h-12 rounded-2xl gap-2 shadow-lg shadow-emerald-500/20"
              >
                <CheckCircle2 className="h-4 w-4" />
                Segna come Pagata oggi
              </Button>
              {isAttiva && (
                <Button 
                  variant="outline"
                  onClick={() => toast.info("Sollecito inviato via email (Simulato)")}
                  className="flex-1 border-border bg-white/5 text-white font-black uppercase text-[10px] h-12 rounded-2xl gap-2 hover:bg-white/10"
                >
                  <Mail className="h-4 w-4" />
                  Invia Sollecito
                </Button>
              )}
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import React, { useState } from "react";
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogFooter 
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { 
  Select, 
  SelectContent, 
  SelectItem, 
  SelectTrigger, 
  SelectValue 
} from "@/components/ui/select";
import { useClienti } from "@/hooks/useClienti";
import { useFornitori } from "@/hooks/useFornitori";
import { useCreateFattura, useUpdateFattura } from "@/hooks/useFatture";
import { toast } from "sonner";
import { 
  Plus, 
  Trash2, 
  FileText, 
  Calendar,
  Building2,
  Receipt
} from "lucide-react";
import { Separator } from "@/components/ui/separator";

interface FatturaModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  type: "attive" | "passive";
  fattura?: any; // If provided, we are in edit mode
}

type FatturaItem = {
  description: string;
  qty: number;
  price: number;
  amount: number;
};

type FatturaFormData = {
  numero: string;
  data_emissione: string;
  data_scadenza: string;
  cliente_id: string;
  fornitore_id: string;
  importo_netto: number;
  importo_iva: number;
  importo_totale: number;
  stato_pagamento: string;
  valuta: string;
  items: FatturaItem[];
};

function getEmptyFatturaFormData(): FatturaFormData {
  return {
    numero: "",
    data_emissione: new Date().toISOString().split('T')[0],
    data_scadenza: "",
    cliente_id: "",
    fornitore_id: "",
    importo_netto: 0,
    importo_iva: 0,
    importo_totale: 0,
    stato_pagamento: "ATTESA",
    valuta: "EUR",
    items: [],
  };
}

function getInitialFatturaFormData(fattura?: any): FatturaFormData {
  if (!fattura) {
    return getEmptyFatturaFormData();
  }

  return {
    ...getEmptyFatturaFormData(),
    ...fattura,
    data_emissione: fattura.data_emissione ? fattura.data_emissione.split('T')[0] : "",
    data_scadenza: fattura.data_scadenza ? fattura.data_scadenza.split('T')[0] : "",
    items: (fattura.items || fattura.fic_raw_data?.items || []).map((item: any) => ({
      description: item.description || "",
      qty: Number(item.qty || 0),
      price: Number(item.price || 0),
      amount: Number(item.amount || 0),
    })),
  };
}

export function FatturaModal({ open, onOpenChange, type, fattura }: FatturaModalProps) {
  const formKey = fattura?.id ? `edit-${fattura.id}` : `new-${type}`;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      {open ? (
        <FatturaModalForm
          key={formKey}
          onOpenChange={onOpenChange}
          type={type}
          fattura={fattura}
        />
      ) : null}
    </Dialog>
  );
}

function FatturaModalForm({ onOpenChange, type, fattura }: Omit<FatturaModalProps, "open">) {
  const isEdit = !!fattura;
  const isAttiva = type === "attive";

  const { data: clienti = [] } = useClienti();
  const { data: fornitori = [] } = useFornitori();
  const createMutation = useCreateFattura();
  const updateMutation = useUpdateFattura();

  const [formData, setFormData] = useState<FatturaFormData>(() => getInitialFatturaFormData(fattura));

  const handleAddItem = () => {
    const newItems = [...formData.items, { description: "", qty: 1, price: 0, amount: 0 }];
    setFormData({ ...formData, items: newItems });
  };

  const handleRemoveItem = (index: number) => {
    const newItems = formData.items.filter((_, i) => i !== index);
    setFormData({ ...formData, items: newItems });
    recalculateTotals(newItems);
  };

  const handleItemChange = (index: number, field: keyof FatturaItem, value: number | string) => {
    const newItems = [...formData.items];
    newItems[index] = { ...newItems[index], [field]: value };
    
    if (field === "qty" || field === "price") {
      newItems[index].amount = Number(newItems[index].qty || 0) * Number(newItems[index].price || 0);
    }
    
    setFormData({ ...formData, items: newItems });
    recalculateTotals(newItems);
  };

  const recalculateTotals = (items: FatturaItem[]) => {
    const netto = items.reduce((acc, item) => acc + (item.amount || 0), 0);
    const iva = netto * 0.22; // Default 22% VAT for simulation
    setFormData((prev) => ({
      ...prev,
      importo_netto: netto,
      importo_iva: iva,
      importo_totale: netto + iva
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const payload = {
        ...formData,
        importo_totale: Number(formData.importo_totale),
        importo_netto: Number(formData.importo_netto),
        importo_iva: Number(formData.importo_iva),
      };

      if (isEdit) {
        await updateMutation.mutateAsync({ id: fattura.id, type, data: payload });
        toast.success("Fattura aggiornata con successo");
      } else {
        await createMutation.mutateAsync({ type, data: payload });
        toast.success("Fattura creata con successo");
      }
      onOpenChange(false);
    } catch (err) {
      toast.error("Errore durante il salvataggio");
    }
  };

  return (
    <DialogContent className="max-w-4xl bg-card border-border text-white rounded-[32px] overflow-hidden p-0 shadow-2xl">
        <div className="absolute top-0 left-0 w-full h-[6px] bg-gradient-to-r from-primary via-purple-500 to-blue-500" />
        
        <form onSubmit={handleSubmit}>
          <div className="p-8 space-y-8 max-h-[85vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle className="text-2xl font-black uppercase italic tracking-tighter">
                {isEdit ? "Modifica" : "Nuova"} Fattura <span className="text-primary not-italic">{isAttiva ? "Attiva" : "Passiva"}</span>
              </DialogTitle>
            </DialogHeader>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {/* Main Info */}
              <div className="space-y-6">
                <div className="space-y-4 bg-white/5 p-6 rounded-2xl border border-border/50">
                   <div className="space-y-2">
                      <Label className="text-[10px] font-black uppercase tracking-widest text-primary flex items-center gap-2">
                        <FileText className="h-3 w-3" /> Numero Documento
                      </Label>
                      <Input 
                        value={formData.numero} 
                        onChange={(e) => setFormData({...formData, numero: e.target.value})}
                        placeholder="es: 2024/001"
                        className="bg-background/50 border-border focus:ring-primary h-11 font-bold"
                        required
                      />
                   </div>

                   <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <Label className="text-[10px] font-black uppercase tracking-widest text-[#475569] flex items-center gap-2">
                          <Calendar className="h-3 w-3" /> Data Emissione
                        </Label>
                        <Input 
                          type="date"
                          value={formData.data_emissione} 
                          onChange={(e) => setFormData({...formData, data_emissione: e.target.value})}
                          className="bg-background/50 border-border h-11"
                          required
                        />
                      </div>
                      <div className="space-y-2">
                        <Label className="text-[10px] font-black uppercase tracking-widest text-[#475569] flex items-center gap-2">
                          <Calendar className="h-3 w-3" /> Data Scadenza
                        </Label>
                        <Input 
                          type="date"
                          value={formData.data_scadenza} 
                          onChange={(e) => setFormData({...formData, data_scadenza: e.target.value})}
                          className="bg-background/50 border-border h-11"
                        />
                      </div>
                   </div>
                </div>

                <div className="space-y-4 bg-white/5 p-6 rounded-2xl border border-border/50">
                  <div className="space-y-2">
                    <Label className="text-[10px] font-black uppercase tracking-widest text-primary flex items-center gap-2">
                      <Building2 className="h-3 w-3" /> {isAttiva ? "Cliente" : "Fornitore"}
                    </Label>
                    <Select 
                      value={isAttiva ? formData.cliente_id : formData.fornitore_id} 
                      onValueChange={(v) => setFormData({...formData, [isAttiva ? "cliente_id" : "fornitore_id"]: v})}
                    >
                      <SelectTrigger className="bg-background/50 border-border h-11 font-bold">
                        <SelectValue placeholder={`Seleziona ${isAttiva ? "cliente" : "fornitore"}`} />
                      </SelectTrigger>
                      <SelectContent className="bg-card border-border text-white">
                        {isAttiva ? (
                          clienti.map((c: any) => (
                            <SelectItem key={c.id} value={c.id}>{c.ragione_sociale}</SelectItem>
                          ))
                        ) : (
                          fornitori.map((f: any) => (
                            <SelectItem key={f.id} value={f.id}>{f.ragione_sociale}</SelectItem>
                          ))
                        )}
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              </div>

              {/* Totals & Status */}
              <div className="space-y-6">
                <div className="bg-primary/10 border border-primary/20 p-8 rounded-[2rem] flex flex-col justify-center items-center text-center">
                   <p className="text-[10px] font-black uppercase tracking-[0.2em] text-primary mb-2">Totale Documento</p>
                   <p className="text-5xl font-black text-white tracking-tighter tabular-nums mb-4">
                     {new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(formData.importo_totale)}
                   </p>
                   <div className="flex gap-4 w-full">
                      <div className="flex-1 bg-background/30 p-3 rounded-xl">
                        <span className="text-[8px] font-black uppercase text-[#475569] block">Imponibile</span>
                        <span className="text-sm font-bold text-white">{new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(formData.importo_netto)}</span>
                      </div>
                      <div className="flex-1 bg-background/30 p-3 rounded-xl">
                        <span className="text-[8px] font-black uppercase text-[#475569] block">IVA (22%)</span>
                        <span className="text-sm font-bold text-white">{new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(formData.importo_iva)}</span>
                      </div>
                   </div>
                </div>

                <div className="space-y-4">
                   <Label className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Stato Pagamento</Label>
                   <div className="flex gap-2">
                      {["ATTESA", "PAGATA", "SCADUTA"].map(s => (
                        <Button 
                          key={s}
                          type="button"
                          variant={formData.stato_pagamento === s ? "default" : "outline"}
                          className={`flex-1 text-[10px] font-black rounded-xl h-10 ${formData.stato_pagamento === s ? "bg-primary text-white" : "text-[#475569]"}`}
                          onClick={() => setFormData({...formData, stato_pagamento: s})}
                        >
                          {s}
                        </Button>
                      ))}
                   </div>
                </div>
              </div>
            </div>

            <Separator className="bg-border/30" />

            {/* Line Items */}
            <div className="space-y-4">
               <div className="flex items-center justify-between">
                  <h3 className="text-sm font-black uppercase italic tracking-tighter text-white">Line Items</h3>
                  <Button type="button" size="sm" onClick={handleAddItem} className="bg-white/5 border-border/50 text-[10px] font-black uppercase gap-2 rounded-xl">
                    <Plus className="h-4 w-4" /> Aggiungi Riga
                  </Button>
               </div>
               
               <div className="space-y-3">
                  {formData.items.map((item: any, idx: number) => (
                    <div key={idx} className="flex items-center gap-4 bg-white/5 p-4 rounded-2xl border border-border/30 group">
                      <div className="flex-[4] space-y-1">
                        <Input 
                          placeholder="Descrizione..." 
                          value={item.description} 
                          onChange={(e) => handleItemChange(idx, "description", e.target.value)}
                          className="bg-transparent border-none text-xs font-bold p-0 h-auto focus-visible:ring-0 placeholder:text-[#475569]"
                        />
                      </div>
                      <div className="flex-1">
                        <Input 
                          type="number" 
                          placeholder="Qtà" 
                          value={item.qty} 
                          onChange={(e) => handleItemChange(idx, "qty", Number(e.target.value))}
                          className="bg-background/50 border-border text-xs font-bold h-9 text-center"
                        />
                      </div>
                      <div className="flex-[2]">
                        <div className="relative">
                          <Euro className="absolute left-2 top-1/2 -translate-y-1/2 h-3 w-3 text-[#475569]" />
                          <Input 
                            type="number" 
                            placeholder="Prezzo" 
                            value={item.price} 
                            onChange={(e) => handleItemChange(idx, "price", Number(e.target.value))}
                            className="bg-background/50 border-border text-xs font-bold h-9 pl-7"
                          />
                        </div>
                      </div>
                      <div className="flex-[2] text-right font-black text-xs text-white tabular-nums">
                        {new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(item.amount || 0)}
                      </div>
                      <Button type="button" size="icon" variant="ghost" className="h-8 w-8 text-rose-500 hover:bg-rose-500/10" onClick={() => handleRemoveItem(idx)}>
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                  ))}
                  {formData.items.length === 0 && (
                    <div className="py-12 border-2 border-dashed border-border/50 rounded-2xl flex flex-col items-center justify-center text-center opacity-30">
                       <Receipt className="h-8 w-8 mb-2" />
                       <p className="text-[10px] font-black uppercase tracking-widest">Nessun dettaglio riga aggiunto</p>
                    </div>
                  )}
               </div>
            </div>
          </div>

          <DialogFooter className="p-8 bg-card border-t border-border flex gap-4">
             <Button type="button" variant="outline" onClick={() => onOpenChange(false)} className="rounded-xl border-border text-[10px] font-black uppercase px-8">
                Annulla
             </Button>
             <Button type="submit" className="rounded-xl bg-primary hover:bg-primary/90 text-white text-[10px] font-black uppercase px-8 shadow-xl shadow-primary/20">
                {isEdit ? "Salva Modifiche" : "Crea Fattura"}
             </Button>
          </DialogFooter>
        </form>
      </DialogContent>
  );
}

