  budget: z.coerce.number().min(1, "Il budget deve essere maggiore di zero"),
  note: z.string().optional().default(""),
  stato: z.enum(["PENDING", "ACCEPTED", "CONVERTED"]).default("PENDING"),
  lavorazioni: z.array(z.object({
    tipo_lavorazione: z.string().min(1, "Obbligatorio"),
    user_id: z.string().min(1, "Obbligatorio"),
    ore_previste: z.coerce.number().min(0.5, "Min 0.5h"),
  })).default([]),
});

type PlanningFormValues = z.infer<typeof planningSchema>;

interface PlanningDialogProps {
  plan?: Pianificazione | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function PlanningDialog({
  plan,
  open,
  onOpenChange,
}: PlanningDialogProps) {
  const { data: clienti } = useClienti();
  const { data: users = [] } = useUsers(true);
  const createPlan = useCreatePianificazione();
  const updatePlan = useUpdatePianificazione();
  const isEditing = !!plan;

  const form = useForm<PlanningFormValues>({
    resolver: zodResolver(planningSchema) as any,
    defaultValues: {
      cliente_id: "",
      budget: 0,
      note: "",
      stato: "PENDING",
      lavorazioni: [],
    },
  });

  const { fields, append, remove } = useFieldArray({
    control: form.control,
    name: "lavorazioni"
  });

  // Keep form in sync when 'plan' prop changes
  React.useEffect(() => {
    if (plan) {
      form.reset({
        cliente_id: plan.cliente_id,
        budget: plan.budget,
        note: plan.note || "",
        stato: plan.stato,
        lavorazioni: plan.lavorazioni.map(l => ({
          tipo_lavorazione: l.tipo_lavorazione,
          user_id: l.user_id,
          ore_previste: l.ore_previste,
        })),
      });
    } else {
      form.reset({
        cliente_id: "",
        budget: 0,
        note: "",
        stato: "PENDING",
        lavorazioni: [],
      });
    }
  }, [plan, form]);

  // Live Calculation Logic
  const watchedValues = useWatch({ control: form.control });
  const budget = watchedValues.budget || 0;
  const lavorazioni = watchedValues.lavorazioni || [];

  const metrics = useMemo(() => {
    let totCosti = 0;
    lavorazioni.forEach(lav => {
      if (!lav || !lav.user_id) return;
      const user = users.find(u => u.id === lav.user_id);
      const rate = user?.costo_orario || 0;
      totCosti += (lav.ore_previste || 0) * rate;
    });

    const margineEuro = budget - totCosti;
    const marginePct = budget > 0 ? (margineEuro / budget) * 100 : 0;

    return {
      totCosti,
      margineEuro,
      marginePct
    };
  }, [budget, lavorazioni, users]);

  const onSubmit = async (values: PlanningFormValues) => {
    try {
      if (isEditing && plan) {
        await updatePlan.mutateAsync({ id: plan.id, data: values });
      } else {
        await createPlan.mutateAsync(values);
      }
      onOpenChange(false);
    } catch (error) {
      // toast is handled in hooks
    }
  };

  const isPending = createPlan.isPending || updatePlan.isPending;

  // UI Helpers
  const getMarginColor = (pct: number) => {
    if (pct >= 50) return "text-emerald-400";
    if (pct >= 30) return "text-amber-400";
    return "text-red-400";
  };

  const getMarginBg = (pct: number) => {
    if (pct >= 50) return "bg-emerald-500";
    if (pct >= 30) return "bg-amber-500";
    return "bg-red-500";
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[700px] bg-card border-border text-white overflow-hidden p-0">
        {/* Animated Background Header Blur */}
        <div className="absolute top-0 inset-x-0 h-32 bg-gradient-to-b from-purple-500/10 to-transparent pointer-events-none" />

        <div className="p-6 space-y-6 relative">
          <DialogHeader className="flex flex-row items-center justify-between space-y-0">
            <div>
              <DialogTitle className="text-2xl font-black text-foreground flex items-center gap-2">
                <Calculator className="w-6 h-6 text-purple-400" />
                {isEditing ? "Modifica Pianificazione" : "Preventivatore Studio OS"}
              </DialogTitle>
              <p className="text-xs text-muted-foreground mt-1 uppercase tracking-widest font-bold">Analisi Finanziaria Preventiva</p>
            </div>
            
            <div className="text-right">
               <div className={`text-3xl font-black tracking-tighter ${getMarginColor(metrics.marginePct)} transition-colors duration-500`}>
                 {metrics.marginePct.toFixed(1)}%
               </div>
               <div className="text-[9px] text-muted-foreground uppercase font-black">Margine Stimato</div>
            </div>
          </DialogHeader>

          {/* Real-time Dashboard */}
          <div className="grid grid-cols-3 gap-4 p-4 rounded-2xl bg-muted/30 border border-white/5 shadow-inner">
             <div className="space-y-1">
                <div className="text-[10px] text-muted-foreground flex items-center gap-1.5 font-bold uppercase">
                  <Euro className="w-3 h-3" /> Budget
                </div>
                <div className="text-xl font-bold text-white">€{budget.toLocaleString()}</div>
             </div>
             <div className="space-y-1">
                <div className="text-[10px] text-muted-foreground flex items-center gap-1.5 font-bold uppercase">
                  <TrendingDown className="w-3 h-3" /> Costi Personale
                </div>
                <div className="text-xl font-bold text-red-100/80">€{metrics.totCosti.toLocaleString()}</div>
             </div>
             <div className="space-y-1">
                <div className="text-[10px] text-muted-foreground flex items-center gap-1.5 font-bold uppercase">
                  <Target className="w-3 h-3" /> Margine Netto
                </div>
                <div className={`text-xl font-bold ${getMarginColor(metrics.marginePct)}`}>€{metrics.margineEuro.toLocaleString()}</div>
             </div>
             
             <div className="col-span-3 pt-2">
                <Progress value={Math.min(100, Math.max(0, metrics.marginePct))} className={`h-1.5 ${getMarginBg(metrics.marginePct)} bg-muted`} />
             </div>
          </div>

          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
              <div className="grid grid-cols-2 gap-6">
                <FormField
                  control={form.control as any}
                  name="cliente_id"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-xs font-black uppercase text-muted-foreground">Cliente</FormLabel>
                      <Select onValueChange={field.onChange} value={field.value}>
                        <FormControl>
                          <SelectTrigger className="bg-muted border-border text-white h-11 rounded-xl">
                            <SelectValue placeholder="Seleziona un cliente" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent className="bg-card border-border text-white">
                          {clienti?.map((c) => (
                            <SelectItem key={c.id} value={c.id}>
                              {c.ragione_sociale}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control as any}
                  name="budget"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-xs font-black uppercase text-muted-foreground">Valore Preventivo (€)</FormLabel>
                      <FormControl>
                        <Input 
                          type="number" 
                          {...field} 
                          className="bg-muted border-border text-white h-11 rounded-xl font-bold text-lg" 
                          placeholder="es. 1500"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              {/* Lavorazioni Section */}
              <div className="space-y-4">
                 <div className="flex items-center justify-between border-b border-border pb-2">
                   <h3 className="text-sm font-black text-foreground uppercase tracking-wider flex items-center gap-2">
                     <Clock className="w-4 h-4 text-purple-400" />
                     Task & Figure Coinvolte
                   </h3>
                   <Button 
                    type="button" 
                    variant="outline" 
                    size="sm" 
                    onClick={() => append({ tipo_lavorazione: "", user_id: "", ore_previste: 1 })}
                    className="h-8 border-purple-500/30 text-purple-400 hover:bg-purple-500/10 hover:text-white rounded-lg font-bold"
                  >
                    <Plus className="w-3.5 h-3.5 mr-1.5" />
                    Aggiungi Figura
                  </Button>
                 </div>

                 <div className="space-y-4 max-h-[250px] overflow-y-auto pr-2 scrollbar-thin scrollbar-thumb-muted">
                    {fields.map((field, index) => {
                      const selectedUserId = lavorazioni[index]?.user_id;
                      const user = users.find(u => u.id === selectedUserId);
                      const costSnapshot = user?.costo_orario || 0;
                      const lineCost = (lavorazioni[index]?.ore_previste || 0) * costSnapshot;

                      return (
                        <div key={field.id} className="p-4 rounded-2xl bg-muted/40 border border-white/5 grid grid-cols-12 gap-4 items-end relative group hover:bg-muted/60 transition-colors">
                           <div className="col-span-4">
                              <label className="text-[9px] uppercase font-black text-muted-foreground mb-1.5 block">Tipo Lavorazione</label>
                              <Select 
                                onValueChange={(val) => form.setValue(`lavorazioni.${index}.tipo_lavorazione` as any, val)} 
                                value={lavorazioni[index]?.tipo_lavorazione || ""}
                              >
                                <SelectTrigger className="h-9 bg-card border-border text-xs rounded-lg">
                                   <SelectValue placeholder="Tipo di task..." />
                                </SelectTrigger>
                                <SelectContent className="bg-card border-border text-white">
                                  <SelectItem value="Scripting">Scripting</SelectItem>
                                  <SelectItem value="Montaggio Video">Montaggio Video</SelectItem>
                                  <SelectItem value="Copywriting">Copywriting</SelectItem>
                                  <SelectItem value="Strategia">Strategia</SelectItem>
                                  <SelectItem value="Gestione Social">Gestione Social</SelectItem>
                                  <SelectItem value="Graphic Design">Graphic Design</SelectItem>
                                  <SelectItem value="Altro">Altro...</SelectItem>
                                </SelectContent>
                              </Select>
                           </div>
                           
                           <div className="col-span-4">
                             <label className="text-[9px] uppercase font-black text-muted-foreground mb-1.5 block">Collaboratore</label>
                             <Select 
                              onValueChange={(val) => form.setValue(`lavorazioni.${index}.user_id` as any, val)} 
                              value={lavorazioni[index]?.user_id || ""}
                             >
                                <SelectTrigger className="h-9 bg-card border-border text-xs rounded-lg">
                                   <SelectValue placeholder="Chi farà il lavoro?" />
                                </SelectTrigger>
                                <SelectContent className="bg-card border-border text-white">
                                  {users.map(u => (
                                    <SelectItem key={u.id} value={u.id}>{u.nome} {u.cognome}</SelectItem>
                                  ))}
                                </SelectContent>
                             </Select>
                           </div>

                           <div className="col-span-2">
                              <label className="text-[9px] uppercase font-black text-muted-foreground mb-1.5 block">Ore</label>
                              <Input 
                                type="number"
                                step="0.5"
                                {...form.register(`lavorazioni.${index}.ore_previste` as const)}
                                className="h-9 bg-card border-border text-xs rounded-lg text-center font-bold"
                              />
                           </div>

                           <div className="col-span-2 text-right">
                              <div className="text-[9px] uppercase font-black text-muted-foreground mb-1.5">Costo</div>
                              <div className="h-9 flex items-center justify-end font-bold text-red-200/50 text-xs">
                                €{lineCost.toLocaleString()}
                              </div>
                           </div>

                           <Button 
                              type="button" 
                              variant="ghost" 
                              size="icon" 
                              onClick={() => remove(index)}
                              className="absolute -right-2 top-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 transition-opacity text-red-400 hover:bg-red-500/10"
                            >
                              <Trash2 className="w-4 h-4" />
                           </Button>
                        </div>
                      );
                    })}

                    {fields.length === 0 && (
                      <div className="py-10 text-center border border-dashed border-border rounded-2xl">
                         <Info className="w-6 h-6 text-muted-foreground/30 mx-auto mb-2" />
                         <p className="text-[10px] uppercase font-black tracking-widest text-muted-foreground/50">Inserisci le figure per calcolare i costi</p>
                      </div>
                    )}
                 </div>
              </div>

              <FormField
                control={form.control as any}
                name="note"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-xs font-black uppercase text-muted-foreground">Brief / Note Interne</FormLabel>
                    <FormControl>
                      <Textarea 
                        {...field} 
                        className="bg-muted border-border text-white min-h-[80px] rounded-xl resize-none" 
                        placeholder="Dettagli sulla negoziazione o vincoli particolari..." 
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <DialogFooter className="pt-2">
                <Button type="button" variant="ghost" onClick={() => onOpenChange(false)} className="text-muted-foreground hover:text-white">
                  Chiudi
                </Button>
                <Button 
                  type="submit" 
                  disabled={isPending} 
                  className="bg-purple-600 hover:bg-purple-700 text-white font-black uppercase tracking-widest text-xs px-8 shadow-[0_0_20px_hsl(var(--purple-600)/0.3)]"
                >
                  {isPending ? <Loader2 className="w-4 h-4 animate-spin" /> : (isEditing ? "Salva Aggiornamenti" : "Salva Pianificazione")}
                </Button>
              </DialogFooter>
            </form>
          </Form>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import React, { useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { useCreateTask, useUpdateTask } from "@/hooks/useTasks";
import { useProgetti } from "@/hooks/useProgetti";
import { Loader2, Plus, Pencil } from "lucide-react";

const taskSchema = z.object({
  titolo: z.string().min(3, "Il titolo deve avere almeno 3 caratteri"),
  progetto_id: z.string().optional(),
  stima_minuti: z.coerce.number().min(0).default(0),
  descrizione: z.string().optional(),
});

type TaskFormValues = z.infer<typeof taskSchema>;

interface TaskPlanningDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  task?: any; // Added task prop for editing
}

export function TaskPlanningDialog({ open, onOpenChange, task }: TaskPlanningDialogProps) {
  const { data: progetti } = useProgetti();
  const createTask = useCreateTask();
  const updateTask = useUpdateTask();
  const isEdit = !!task;

  const form = useForm<TaskFormValues>({
    resolver: zodResolver(taskSchema) as any,
    defaultValues: {
      titolo: "",
      progetto_id: undefined,
      stima_minuti: 60,
      descrizione: "",
    },
  });

  useEffect(() => {
    if (task) {
      form.reset({
        titolo: task.titolo || task.title || "",
        progetto_id: task.progetto_id || undefined,
        stima_minuti: task.stima_minuti || 60,
        descrizione: task.descrizione || task.desc || "",
      });
    } else {
      form.reset({
        titolo: "",
        progetto_id: undefined,
        stima_minuti: 60,
        descrizione: "",
      });
    }
  }, [task, open, form]);

  const onSubmit = async (data: TaskFormValues) => {
    const values = data as TaskFormValues;
    try {
      if (isEdit) {
        await updateTask.mutateAsync({ id: task.id, data: values });
      } else {
        await createTask.mutateAsync(values);
      }
      form.reset();
      onOpenChange(false);
    } catch (error) {
      console.error("Errore durante il salvataggio del task:", error);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[425px] bg-card border-border text-white">
        <DialogHeader>
          <DialogTitle className="text-xl font-black flex items-center gap-2">
            {isEdit ? <Pencil className="h-5 w-5 text-primary" /> : <Plus className="h-5 w-5 text-primary" />}
            {isEdit ? "Modifica Task" : "Nuova Task Backlog"}
          </DialogTitle>
        </DialogHeader>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 pt-4">
            <FormField
              control={form.control}
              name="titolo"
              render={({ field }) => (
                <FormItem>
                  <FormLabel className="text-[10px] font-black uppercase tracking-widest text-slate-500">Titolo Task</FormLabel>
                  <FormControl>
                    <Input {...field} className="bg-muted border-border font-medium" placeholder="Es: Design Homepage" />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <div className="grid grid-cols-2 gap-4">
              <FormField
                control={form.control}
                name="progetto_id"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-[10px] font-black uppercase tracking-widest text-slate-500">Progetto</FormLabel>
                    <Select onValueChange={field.onChange} value={field.value}>
                      <FormControl>
                        <SelectTrigger className="bg-muted border-border">
                          <SelectValue placeholder="Opzionale" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent className="bg-card border-border text-white">
                        {progetti?.map((p) => (
                          <SelectItem key={p.id} value={p.id}>
                            {p.nome}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="stima_minuti"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-[10px] font-black uppercase tracking-widest text-slate-500">Stima (Minuti)</FormLabel>
                    <FormControl>
                      <Input type="number" {...field} className="bg-muted border-border" />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            <DialogFooter className="pt-4 gap-2">
              <Button type="button" variant="ghost" onClick={() => onOpenChange(false)} className="text-slate-400">
                Annulla
              </Button>
              <Button type="submit" disabled={createTask.isPending || updateTask.isPending} className="bg-primary hover:bg-primary/90 text-white font-black uppercase tracking-widest text-[10px]">
                {(createTask.isPending || updateTask.isPending) ? <Loader2 className="h-4 w-4 animate-spin" /> : (isEdit ? "Salva Modifiche" : "Aggiungi al Backlog")}
              </Button>
            </DialogFooter>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

import React, { useState, useMemo } from "react";
import { useNavigate } from "react-router-dom";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { ScrollArea } from "@/components/ui/scroll-area";
import { format } from "date-fns";
import { it } from "date-fns/locale";
import { useProgetti } from "@/hooks/useProgetti";
import { useCommesse, useCreateCommessa, useUpdateCommessa } from "@/hooks/useCommesse";
import { Loader2, Plus, Info, CheckCircle2, AlertCircle, Euro } from "lucide-react";
import { toast } from "sonner";
import type { Progetto } from "@/types";

interface CommessaSelectionDialogProps {
  progetto: Progetto;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess?: () => void;
}

export function CommessaSelectionDialog({ progetto, open, onOpenChange, onSuccess }: CommessaSelectionDialogProps) {
  const navigate = useNavigate();
  const [meseCompetenza, setMeseCompetenza] = useState(format(new Date(), "yyyy-MM-01"));
  const [selectedProjectIds, setSelectedProjectIds] = useState<string[]>([]);
  const [note, setNote] = useState("");

  const monthName = useMemo(() => {
    try {
      return format(new Date(meseCompetenza), "MMMM yyyy", { locale: it });
    } catch (e) {
      return "Mese non valido";
    }
  }, [meseCompetenza]);

  // 1. Cerca se esiste già una commessa per questo cliente e questo mese
  const { data: commesseMese, isLoading: isLoadingCommesse } = useCommesse({
    cliente_id: progetto.cliente_id,
    mese: meseCompetenza
  }, open);

  // 2. Recupera tutti i progetti attivi del cliente
  const { data: progettiCliente, isLoading: isLoadingProgetti } = useProgetti(progetto.cliente_id, "ATTIVO");
  const createCommessa = useCreateCommessa();
  const updateCommessa = useUpdateCommessa();

  const existingCommessa = commesseMese?.[0];

  // Filtra i progetti che non sono ancora in una commessa per questo mese
  const availableProjects = useMemo(() => {
    if (!progettiCliente) return [];

    // Se la commessa esiste già, escludiamo quelli già collegati
    const alreadyLinkedIds = existingCommessa?.righe_progetto?.map(r => r.progetto_id) || [];

    return progettiCliente.filter(p => 
      p.id !== progetto.id && // Escludiamo il progetto corrente che è sempre selezionato
      !alreadyLinkedIds.includes(p.id)
    );
  }, [progettiCliente, existingCommessa, progetto.id]);

  // Resetta lo stato quando apre
  React.useEffect(() => {
    if (open) {
      setSelectedProjectIds([progetto.id]);
      setNote("");
    }
  }, [open, progetto.id]);

  const isPending = createCommessa.isPending || updateCommessa.isPending;
  const isLoading = isLoadingCommesse || isLoadingProgetti;

  const handleConfirm = async () => {
    if (isPending) return;
    try {
      if (existingCommessa) {
        // AGGIUNTA A COMMESSA ESISTENTE
        const currentRows = existingCommessa.righe_progetto.map(r => ({
          progetto_id: r.progetto_id,
          importo_fisso: r.importo_fisso,
          importo_variabile: r.importo_variabile,
          delivery_attesa: r.delivery_attesa,
          delivery_consuntiva: r.delivery_consuntiva
        }));

        // Aggiungiamo solo i nuovi selezionati
        const newProjects = selectedProjectIds
          .filter(id => !existingCommessa.righe_progetto.some(r => r.progetto_id === id))
          .map(id => {
            const p = progettiCliente?.find(pc => pc.id === id);
            return {
              progetto_id: id,
              importo_fisso: p?.importo_fisso || 0,
              importo_variabile: p?.importo_variabile || 0,
              delivery_attesa: p?.delivery_attesa || 0,
              delivery_consuntiva: 0
            };
          });

        const res = await updateCommessa.mutateAsync({
          id: existingCommessa.id,
          data: {
            righe_progetto: [...currentRows, ...newProjects],
            ...(note && { note: existingCommessa.note ? `${existingCommessa.note}\n${note}` : note })
          }
        });
        toast.success("Progetti aggiunti", {
          description: "La commessa esistente è stata aggiornata.",
          action: {
            label: "Apri Commessa",
            onClick: () => navigate(`/commesse/${existingCommessa.id}`)
          }
        });
      } else {
        // CREAZIONE NUOVA COMMESSA
        const righe = selectedProjectIds.map(id => {
          const p = progettiCliente?.find(pc => pc.id === id) || (id === progetto.id ? progetto : null);
          return {
            progetto_id: id,
            importo_fisso: p?.importo_fisso || 0,
            importo_variabile: p?.importo_variabile || 0,
            delivery_attesa: p?.delivery_attesa || 0
          };
        });

        const res = await createCommessa.mutateAsync({
          cliente_id: progetto.cliente_id,
          mese_competenza: meseCompetenza,
          note: note,
          righe_progetto: righe
        });
        toast.success("Commessa creata", {
          description: `Nuova commessa per ${monthName} generata.`,
          action: {
            label: "Apri Commessa",
            onClick: () => navigate(`/commesse/${res.id}`)
          }
        });
      }

      onOpenChange(false);
      if (onSuccess) onSuccess();
    } catch (err) {
      // Errore gestito dal hook
    }
  };

  const financialImpact = useMemo(() => {
    const allAvailable = [progetto, ...(progettiCliente || [])];
    const uniqueIds = Array.from(new Set(selectedProjectIds));
    const selected = uniqueIds.map(id => allAvailable.find(p => p.id === id)).filter(Boolean);

    const totalRevenue = selected.reduce((acc, p) => acc + ((p?.importo_fisso || 0) + (p?.importo_variabile || 0)), 0);
    const totalHours = selected.reduce((acc, p) => acc + (p?.delivery_attesa || 0), 0);

    return { totalRevenue, totalHours };
  }, [selectedProjectIds, progettiCliente, progetto]);

  const toggleProject = (id: string) => {
    setSelectedProjectIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[500px] bg-card border-border text-white rounded-3xl overflow-hidden shadow-2xl">
        <DialogHeader>
          <DialogTitle className="text-xl font-bold tracking-tighter flex items-center gap-2">
            {existingCommessa ? (
              <>
                <CheckCircle2 className="w-5 h-5 text-emerald-400" />
                Commessa Esistente Trovata
              </>
            ) : (
              <>
                <Plus className="w-5 h-5 text-primary" />
                Crea Nuova Commessa
              </>
            )}
          </DialogTitle>
          <DialogDescription className="text-slate-400 text-xs">
            {existingCommessa 
              ? `È già presente una commessa per ${progetto.cliente?.ragione_sociale} nel mese di ${monthName}. Vuoi aggiungere questo progetto?`
              : `Non esiste ancora una commessa per questo cliente in ${monthName}. Creiamone una ora.`
            }
          </DialogDescription>
        </DialogHeader>

        {isLoading ? (
          <div className="py-12 flex flex-col items-center justify-center space-y-4">
            <Loader2 className="w-8 h-8 animate-spin text-primary" />
            <p className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Analisi dati in corso...</p>
          </div>
        ) : (
          <div className="space-y-6 pt-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">
                  Mese Competenza
                </Label>
                <Input 
                  type="date"
                  value={meseCompetenza}
                  onChange={(e) => setMeseCompetenza(e.target.value)}
                  className="bg-muted border-border text-xs rounded-xl h-10"
                />
              </div>
              <div className="space-y-2">
                <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">
                  Titolo / Riferimento
                </Label>
                <Input 
                  value={note}
                  onChange={(e) => setNote(e.target.value)}
                  placeholder="Es. Sviluppo Q2, Landing Pages..."
                  className="bg-muted border-border text-xs rounded-xl h-10"
                />
              </div>
            </div>
            {/* Sezione Altri Progetti */}
            {availableProjects.length > 0 && (
              <div className="space-y-3">
                <div className="flex items-center gap-2 px-1">
                  <Info className="w-3.5 h-3.5 text-blue-400" />
                  <Label className="text-[10px] font-black uppercase tracking-widest text-blue-400">
                    Altri progetti disponibili per questo cliente
                  </Label>
                </div>
                <ScrollArea className="max-h-[150px] rounded-2xl border border-border/50 bg-muted/20 p-2">
                  <div className="space-y-1">
                    {availableProjects.map(p => (
                      <div 
                        key={p.id} 
                        className="flex items-center justify-between p-2 rounded-xl hover:bg-white/5 transition-colors group cursor-pointer"
                        onClick={() => toggleProject(p.id)}
                      >
                        <div className="flex items-center gap-3">
                          <Checkbox 
                            id={`proj-${p.id}`} 
                            checked={selectedProjectIds.includes(p.id)}
                            onCheckedChange={() => toggleProject(p.id)}
                            className="border-border data-[state=checked]:bg-primary data-[state=checked]:border-primary"
                          />
                          <div>
                            <p className="text-xs font-bold text-white leading-none">{p.nome}</p>
                            <p className="text-[9px] text-muted-foreground uppercase font-medium mt-1">{p.tipo}</p>
                          </div>
                        </div>
                        <p className="text-[10px] font-black text-emerald-400">€{(p.importo_fisso + p.importo_variabile).toLocaleString()}</p>
                      </div>
                    ))}
                  </div>
                </ScrollArea>
                <p className="text-[9px] text-muted-foreground italic px-1">
                  Puoi selezionare altri progetti da fatturare insieme in questa commessa mensile.
                </p>
              </div>
            )}


            {existingCommessa && (
              <div className="p-3 rounded-2xl bg-emerald-500/5 border border-emerald-500/10 flex items-start gap-3">
                <AlertCircle className="w-4 h-4 text-emerald-400 shrink-0 mt-0.5" />
                <div>
                   <p className="text-[11px] font-bold text-emerald-400 uppercase tracking-tight">Consiglio</p>
                   <p className="text-[10px] text-slate-300 leading-relaxed">
                     L'uso di una singola commessa mensile per cliente è la strada consigliata per una fatturazione pulita e un monitoraggio dei costi centralizzato.
                   </p>
                </div>
              </div>
            )}

            <div className="p-4 rounded-3xl bg-primary/5 border border-primary/20 flex items-center justify-between">
              <div className="flex items-center gap-3">
                 <div className="p-2 bg-primary/10 rounded-xl">
                    <Euro className="w-4 h-4 text-primary" />
                 </div>
                 <div>
                    <p className="text-[10px] font-black text-muted-foreground uppercase tracking-widest leading-none">Impatto Valore</p>
                    <p className="text-lg font-black text-white mt-1">€{financialImpact.totalRevenue.toLocaleString()}</p>
                 </div>
              </div>
              <div className="text-right">
                 <p className="text-[10px] font-black text-muted-foreground uppercase tracking-widest leading-none">Ore Totali</p>
                 <p className="text-lg font-black text-primary mt-1">{financialImpact.totalHours}h</p>
              </div>
            </div>
          </div>
        )}

        <DialogFooter className="pt-6">
          <Button variant="ghost" onClick={() => onOpenChange(false)} className="text-muted-foreground hover:text-white rounded-xl">
            Annulla
          </Button>
          <Button 
            onClick={handleConfirm} 
            disabled={isLoading || createCommessa.isPending || updateCommessa.isPending}
            className="bg-primary hover:bg-primary/90 text-white rounded-xl px-8 font-bold"
          >
            {(createCommessa.isPending || updateCommessa.isPending) ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              existingCommessa ? "Conferma e Aggiungi" : "Crea Commessa"
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import React from "react";
import { useForm } from "react-hook-form";
import { useNavigate } from "react-router-dom";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from "@/components/ui/command";
import { Check, ChevronsUpDown } from "lucide-react";
import { cn } from "@/lib/utils";
import { useCreateProgetto, useUpdateProgetto, type ProgettoPayload } from "@/hooks/useProgetti";
import { useClienti } from "@/hooks/useClienti";
import { useUsers } from "@/hooks/useUsers";
import type { Progetto } from "@/types";
import { Loader2, Plus, Trash2 } from "lucide-react";
import { useFieldArray } from "react-hook-form";

const progettoSchema = z.object({
  cliente_id: z.string().min(1, "Cliente obbligatorio"),
  nome: z.string().min(2, "Nome obbligatorio"),
  tipo: z.enum(["RETAINER", "ONE_OFF"]),
  stato: z.enum(["ATTIVO", "CHIUSO"]),
  importo_fisso: z.coerce.number().min(0).default(0),
  importo_variabile: z.coerce.number().min(0).default(0),
  delivery_attesa: z.coerce.number().min(0).default(0),
  note: z.string().optional().default(""),
  data_inizio: z.string().optional().nullable(),
  data_fine: z.string().optional().nullable(),
  team: z.array(z.object({
    user_id: z.string().min(1, "Collaboratore obbligatorio"),
    ruolo_progetto: z.string().optional().default(""),
    ore_previste: z.coerce.number().min(0).default(0),
    note: z.string().optional().default(""),
  })).default([]),
});

type ProgettoFormValues = z.infer<typeof progettoSchema>;

interface ProgettoDialogProps {
  progetto?: Progetto | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess?: (progetto: Progetto) => void;
}

export function ProgettoDialog({ progetto, open, onOpenChange, onSuccess }: ProgettoDialogProps) {
  const { data: clienti } = useClienti();
  const { data: collaborators } = useUsers();
  const createProgetto = useCreateProgetto();
  const updateProgetto = useUpdateProgetto();
  const isEditing = !!(progetto && progetto.id);

  const form = useForm<ProgettoFormValues>({
    resolver: zodResolver(progettoSchema) as any,
    defaultValues: {
      cliente_id: "",
      nome: "",
      tipo: "ONE_OFF",
      stato: "ATTIVO",
      importo_fisso: 0,
      importo_variabile: 0,
      delivery_attesa: 0,
      note: "",
      data_inizio: null,
      data_fine: null,
      team: [],
    },
  });

  const { fields, append, remove } = useFieldArray({
    control: form.control,
    name: "team"
  });

  React.useEffect(() => {
    if (progetto) {
      form.reset({
        cliente_id: progetto.cliente_id,
        nome: progetto.nome,
        tipo: progetto.tipo,
        stato: progetto.stato,
        importo_fisso: progetto.importo_fisso,
        importo_variabile: progetto.importo_variabile,
        delivery_attesa: progetto.delivery_attesa,
        note: progetto.note || "",
        data_inizio: progetto.data_inizio || null,
        data_fine: progetto.data_fine || null,
        team: progetto.team?.map(t => ({
          user_id: t.user_id,
          ruolo_progetto: t.ruolo_progetto || "",
          ore_previste: t.ore_previste || 0,
          note: t.note || "",
        })) || [],
      });
    } else {
      form.reset({
        cliente_id: "",
        nome: "",
        tipo: "ONE_OFF",
        stato: "ATTIVO",
        importo_fisso: 0,
        importo_variabile: 0,
        delivery_attesa: 0,
        note: "",
        data_inizio: null,
        data_fine: null,
        team: [],
      });
    }
  }, [progetto, form]);

  const navigate = useNavigate();
  const onSubmit = async (values: ProgettoFormValues) => {
    if (isPending) return;

    const payload: ProgettoPayload = {
      ...values,
      data_inizio: values.data_inizio ?? undefined,
      data_fine: values.data_fine ?? undefined,
    };

    try {
      let result;
      if (isEditing && progetto) {
        result = await updateProgetto.mutateAsync({ id: progetto.id, data: payload });
      } else {
        result = await createProgetto.mutateAsync(payload);
        // Navigate to the new project detail page
        if (result?.id) {
          navigate(`/progetti/${result.id}`);
        }
      }
      if (onSuccess) onSuccess(result);
      onOpenChange(false);
    } catch (error) {
      console.error("Errore durante il salvataggio del progetto:", error);
    }
  };

  const isPending = createProgetto.isPending || updateProgetto.isPending;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[600px] bg-card border-border text-white">
        <DialogHeader>
          <DialogTitle className="text-xl font-bold text-foreground">
            {isEditing ? "Modifica Progetto" : "Nuovo Progetto"}
          </DialogTitle>
          <DialogDescription className="sr-only">
            Configura i dettagli del progetto, il cliente associato e il budget previsto.
          </DialogDescription>
        </DialogHeader>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 pt-4">
            <div className="grid grid-cols-2 gap-4">
              <FormField
                control={form.control as any}
                name="nome"
                render={({ field }) => (
                  <FormItem className="col-span-2">
                    <FormLabel className="text-muted-foreground">Nome Progetto</FormLabel>
                    <FormControl>
                      <Input {...field} className="bg-muted border-border text-white" placeholder="Es. Digital Marketing 2024" />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control as any}
                name="cliente_id"
                render={({ field }) => (
                  <FormItem className="col-span-2">
                    <FormLabel className="text-muted-foreground">Cliente</FormLabel>
                    <Popover>
                      <PopoverTrigger asChild>
                        <FormControl>
                          <Button
                            variant="outline"
                            role="combobox"
                            className={cn(
                              "w-full justify-between bg-muted border-border text-white hover:bg-muted/80",
                              !field.value && "text-muted-foreground"
                            )}
                          >
                            {field.value
                              ? clienti?.find((c) => c.id === field.value)?.ragione_sociale
                              : "Seleziona un cliente..."}
                            <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                          </Button>
                        </FormControl>
                      </PopoverTrigger>
                      <PopoverContent className="w-[400px] p-0 bg-card border-border text-white">
                        <Command>
                          <CommandInput placeholder="Cerca cliente..." className="text-white" />
                          <CommandList>
                            <CommandEmpty>Nessun cliente trovato.</CommandEmpty>
                            <CommandGroup>
                              {clienti?.map((c) => (
                                <CommandItem
                                  value={c.ragione_sociale}
                                  key={c.id}
                                  onSelect={() => {
                                    form.setValue("cliente_id", c.id);
                                  }}
                                  className="text-white hover:bg-muted cursor-pointer"
                                >
                                  <Check
                                    className={cn(
                                      "mr-2 h-4 w-4",
                                      c.id === field.value ? "opacity-100" : "opacity-0"
                                    )}
                                  />
                                  {c.ragione_sociale}
                                </CommandItem>
                              ))}
                            </CommandGroup>
                          </CommandList>
                        </Command>
                      </PopoverContent>
                    </Popover>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control as any}
                name="tipo"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-muted-foreground">Tipo</FormLabel>
                    <Select onValueChange={field.onChange} value={field.value}>
                      <FormControl>
                        <SelectTrigger className="bg-muted border-border text-white">
                          <SelectValue placeholder="Tipo progetto" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent className="bg-card border-border text-white">
                        <SelectItem value="RETAINER">RETAINER</SelectItem>
                        <SelectItem value="ONE_OFF">ONE_OFF</SelectItem>
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control as any}
                name="stato"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-muted-foreground">Stato</FormLabel>
                    <Select onValueChange={field.onChange} value={field.value}>
                      <FormControl>
                        <SelectTrigger className="bg-muted border-border text-white">
                          <SelectValue placeholder="Stato progetto" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent className="bg-card border-border text-white">
                        <SelectItem value="ATTIVO">ATTIVO</SelectItem>
                        <SelectItem value="CHIUSO">CHIUSO</SelectItem>
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control as any}
                name="data_inizio"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-muted-foreground">Data Inizio</FormLabel>
                    <FormControl>
                      <Input type="date" {...field} value={field.value || ""} className="bg-muted border-border text-white" />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control as any}
                name="data_fine"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-muted-foreground">Data Fine</FormLabel>
                    <FormControl>
                      <Input type="date" {...field} value={field.value || ""} className="bg-muted border-border text-white" />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control as any}
                name="importo_fisso"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-muted-foreground text-[10px] font-black uppercase tracking-widest">Valore Fisso (Ricavo)</FormLabel>
                    <FormControl>
                      <div className="relative">
                        <Input type="number" {...field} className="bg-muted border-border text-white pl-7" placeholder="0" />
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-xs text-muted-foreground">€</span>
                      </div>
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control as any}
                name="importo_variabile"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-muted-foreground text-[10px] font-black uppercase tracking-widest">Valore Variabile (Extra)</FormLabel>
                    <FormControl>
                      <div className="relative">
                        <Input type="number" {...field} className="bg-muted border-border text-white pl-7" placeholder="0" />
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-xs text-muted-foreground">€</span>
                      </div>
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>
            
            <FormField
              control={form.control as any}
              name="note"
              render={({ field }) => (
                <FormItem>
                  <FormLabel className="text-muted-foreground text-[10px] font-black uppercase tracking-widest">Note Operative</FormLabel>
                  <FormControl>
                    <Textarea 
                      {...field} 
                      className="bg-muted border-border text-white min-h-[80px] rounded-xl text-xs" 
                      placeholder="Descrivi gli obiettivi o i dettagli del progetto..." 
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <h3 className="text-sm font-medium text-muted-foreground">Team Assegnato</h3>
                <Button 
                  type="button" 
                  variant="outline" 
                  size="sm" 
                  onClick={() => append({ user_id: "", ruolo_progetto: "", ore_previste: 0, note: "" })}
                  className="h-8 border-dashed"
                >
                  <Plus className="w-4 h-4 mr-1" /> Aggiungi Membro
                </Button>
              </div>

              {fields.map((field, index) => (
                <div key={field.id} className="space-y-2 bg-muted/20 p-3 rounded-2xl border border-border/30 relative group transition-all hover:bg-muted/40">
                  <div className="grid grid-cols-12 gap-2">
                    <div className="col-span-5">
                      <FormField
                        control={form.control as any}
                        name={`team.${index}.user_id`}
                        render={({ field }) => (
                          <FormItem>
                            <Select 
                              onValueChange={(val) => {
                                field.onChange(val);
                                const user = collaborators?.find(u => u.id === val);
                                if (user) {
                                  form.setValue(`team.${index}.ruolo_progetto`, user.ruolo || "");
                                }
                              }} 
                              value={field.value}
                            >
                              <FormControl>
                                <SelectTrigger className="bg-muted border-border text-[11px] font-bold h-9 rounded-xl">
                                  <SelectValue placeholder="Seleziona..." />
                                </SelectTrigger>
                              </FormControl>
                              <SelectContent className="bg-card border-border">
                                {collaborators?.map(u => (
                                  <SelectItem key={u.id} value={u.id} className="text-xs">
                                    <div className="flex items-center justify-between w-full gap-8">
                                      <span>{u.nome} {u.cognome}</span>
                                      <span className="text-[10px] opacity-50 font-black">€{u.costo_orario || 0}/h</span>
                                    </div>
                                  </SelectItem>
                                ))}
                              </SelectContent>
                            </Select>
                          </FormItem>
                        )}
                      />
                    </div>
                    <div className="col-span-4">
                      <FormField
                        control={form.control as any}
                        name={`team.${index}.ruolo_progetto`}
                        render={({ field }) => (
                          <FormItem>
                            <FormControl>
                              <div className="space-y-1">
                                <Input {...field} placeholder="Ruolo" className="bg-muted border-border text-[11px] h-9 rounded-xl font-medium" />
                                {(() => {
                                  const userId = form.getValues(`team.${index}.user_id`);
                                  const user = collaborators?.find(u => u.id === userId);
                                  if (user) {
                                    return <p className="text-[9px] text-muted-foreground ml-1 font-bold">COSTO: €{user.costo_orario || 0}/h</p>
                                  }
                                  return null;
                                })()}
                              </div>
                            </FormControl>
                          </FormItem>
                        )}
                      />
                    </div>
                    <div className="col-span-3">
                      <FormField
                        control={form.control as any}
                        name={`team.${index}.ore_previste`}
                        render={({ field }) => (
                          <FormItem>
                            <FormControl>
                              <div className="relative">
                                <Input type="number" {...field} placeholder="0" className="bg-muted border-border text-[11px] h-9 rounded-xl font-bold pr-7" />
                                <span className="absolute right-2 top-1/2 -translate-y-1/2 text-[9px] font-black text-muted-foreground uppercase pointer-events-none">h</span>
                              </div>
                            </FormControl>
                          </FormItem>
                        )}
                      />
                    </div>
                  </div>
                  
                  <div className="flex items-center gap-2">
                    <div className="flex-1">
                      <FormField
                        control={form.control as any}
                        name={`team.${index}.note`}
                        render={({ field }) => (
                          <FormItem>
                            <FormControl>
                              <Input {...field} placeholder="Compiti specifici o note per il collaboratore..." className="bg-muted/50 border-border/50 text-[10px] h-8 rounded-lg italic" />
                            </FormControl>
                          </FormItem>
                        )}
                      />
                    </div>
                    <Button 
                      type="button" 
                      variant="ghost" 
                      size="icon" 
                      onClick={() => remove(index)}
                      className="h-8 w-8 text-red-400 hover:text-red-300 hover:bg-red-900/20 rounded-lg shrink-0"
                    >
                      <Trash2 className="w-3.5 h-3.5" />
                    </Button>
                  </div>
                </div>
              ))}
              {fields.length === 0 && (
                <div className="text-center py-4 border border-dashed border-border rounded-lg text-xs text-muted-foreground">
                  Nessun membro del team assegnato.
                </div>
              )}
            </div>

            <DialogFooter className="pt-4">
              <Button type="button" variant="ghost" onClick={() => onOpenChange(false)} className="text-muted-foreground hover:text-white">
                Annulla
              </Button>
              <Button type="submit" disabled={isPending} className="bg-primary hover:bg-primary/90 text-white">
                {isPending ? <Loader2 className="w-4 h-4 animate-spin" /> : (isEditing ? "Salva Modifiche" : "Crea Progetto")}
              </Button>
            </DialogFooter>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

