const PRIORITY_COLORS: Record<string, { bg: string; text: string; label: string }> = {
  alta:    { bg: "bg-red-500/15",    text: "text-red-400",    label: "Alta" },
  media:   { bg: "bg-yellow-500/15", text: "text-yellow-400", label: "Media" },
  bassa:   { bg: "bg-slate-500/15",  text: "text-slate-400",  label: "Bassa" },
};

function formatTime(ms: number): string {
  const totalSeconds = Math.floor(ms / 1000);
  const h = Math.floor(totalSeconds / 3600);
  const m = Math.floor((totalSeconds % 3600) / 60);
  const s = totalSeconds % 60;
  return `${h.toString().padStart(2, "0")}:${m.toString().padStart(2, "0")}:${s.toString().padStart(2, "0")}`;
}

// Deterministic color per user initials
function avatarColor(id: string): string {
  const colors = [
    "bg-violet-500/20 text-violet-300",
    "bg-blue-500/20 text-blue-300",
    "bg-emerald-500/20 text-emerald-300",
    "bg-pink-500/20 text-pink-300",
    "bg-amber-500/20 text-amber-300",
    "bg-cyan-500/20 text-cyan-300",
  ];
  const idx = id.charCodeAt(0) % colors.length;
  return colors[idx];
}

type SortKey = "title" | "due_date" | "stato" | "assegnatario";
type SortDir = "asc" | "desc";

export function StudioListView() {
  const { nav, openNewTask } = useStudio();
  const { data } = useTasks();
  const { data: utenti = [] } = useUsers();
  const { createTask } = useTaskMutations();
  const [quickAddActive, setQuickAddActive] = useState(false);
  const [quickAddTitle, setQuickAddTitle] = useState("");
  const quickAddRef = useRef<HTMLInputElement>(null);

  const handleQuickAdd = async () => {
    const title = quickAddTitle.trim();
    if (!title) { setQuickAddActive(false); return; }
    try {
      await createTask.mutateAsync({
        titolo: title,
        progetto_id: nav.selectedListId || undefined,
        stato: "DA_FARE",
      });
      setQuickAddTitle("");
      // keep input open for rapid entry
      quickAddRef.current?.focus();
    } catch {
      toast.error("Errore nella creazione della task");
    }
  };

  const [sortKey, setSortKey] = useState<SortKey>("title");
  const [sortDir, setSortDir] = useState<SortDir>("asc");
  const [filterAssignee, setFilterAssignee] = useState<string | null>(null);
  const [filterStatus, setFilterStatus] = useState<string | null>(null);
  const [filterPriority, setFilterPriority] = useState<string | null>(null);

  const getUserInitials = (id?: string | null) => {
    if (!id) return null;
    const u = (utenti as any[]).find((u) => u.id === id);
    return u ? `${u.nome[0]}${u.cognome[0]}`.toUpperCase() : null;
  };

  const getUserName = (id?: string | null) => {
    if (!id) return null;
    const u = (utenti as any[]).find((u) => u.id === id);
    return u ? `${u.nome} ${u.cognome}` : null;
  };

  const tasks = useMemo(() => {
    if (!data) return [];
    let filtered = [...data];

    if (nav.selectedListId) {
      filtered = filtered.filter((t) => t.progetto_id === nav.selectedListId);
    } else if (nav.selectedFolderId) {
      filtered = filtered.filter((t) => t.commessa_id === nav.selectedFolderId);
    }

    if (filterAssignee) filtered = filtered.filter((t) => t.assegnatario_id === filterAssignee);
    if (filterStatus)   filtered = filtered.filter((t) => t.state_id === filterStatus);
    if (filterPriority) filtered = filtered.filter((t) => (t.priorita || "media") === filterPriority);

    filtered.sort((a, b) => {
      let cmp = 0;
      if (sortKey === "title")       cmp = a.title.localeCompare(b.title);
      if (sortKey === "due_date")    cmp = (a.due_date || "").localeCompare(b.due_date || "");
      if (sortKey === "stato")       cmp = a.state_id.localeCompare(b.state_id);
      if (sortKey === "assegnatario") {
        cmp = (getUserName(a.assegnatario_id) || "").localeCompare(getUserName(b.assegnatario_id) || "");
      }
      return sortDir === "asc" ? cmp : -cmp;
    });

    return filtered;
  }, [data, nav.selectedFolderId, nav.selectedListId, filterAssignee, filterStatus, filterPriority, sortKey, sortDir]);

  const toggleSort = (key: SortKey) => {
    if (sortKey === key) setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    else { setSortKey(key); setSortDir("asc"); }
  };

  // Virtualization
  const parentRef = useRef<HTMLDivElement>(null);

  // Flatten tasks for virtualization (subtasks are handled separately if not using a flat tree)
  // For now, virtualization will apply to the top-level tasks.
  const virtualizer = useVirtualizer({
    count: tasks.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => 48, // Estimated height of a row
    overscan: 10,
  });

  const activeFilters = [filterAssignee, filterStatus, filterPriority].filter(Boolean).length;

  return (
    <div className="flex flex-col flex-1 overflow-hidden bg-background/50">
      {/* Filter bar */}
      {(activeFilters > 0 || true) && (
        <div className="flex items-center gap-2 px-6 py-2.5 border-b border-border/20 bg-card/20 shrink-0 flex-wrap">
          <span className="text-[9px] font-black uppercase tracking-[0.2em] text-muted-foreground/40 flex items-center gap-1.5 mr-1">
            <Filter className="h-3 w-3" /> Filtri
          </span>

          {/* Assignee filter */}
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                variant="ghost"
                size="sm"
                className={cn(
                  "h-7 px-3 rounded-lg text-[10px] font-black uppercase tracking-wider border transition-all",
                  filterAssignee
                    ? "bg-primary/10 border-primary/30 text-primary"
                    : "border-border/30 text-muted-foreground/60 hover:border-border/60"
                )}
              >
                {filterAssignee ? getUserName(filterAssignee) : "Assegnatario"}
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent className="bg-card border-border rounded-xl shadow-2xl w-48">
              <DropdownMenuItem
                className="text-[11px] font-bold cursor-pointer"
                onClick={() => setFilterAssignee(null)}
              >
                Tutti
              </DropdownMenuItem>
              {(utenti as any[]).map((u) => (
                <DropdownMenuItem
                  key={u.id}
                  className="text-[11px] font-bold cursor-pointer"
                  onClick={() => setFilterAssignee(u.id)}
                >
                  {u.nome} {u.cognome}
                </DropdownMenuItem>
              ))}
            </DropdownMenuContent>
          </DropdownMenu>

          {/* Status filter */}
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                variant="ghost"
                size="sm"
                className={cn(
                  "h-7 px-3 rounded-lg text-[10px] font-black uppercase tracking-wider border transition-all",
                  filterStatus
                    ? "bg-primary/10 border-primary/30 text-primary"
                    : "border-border/30 text-muted-foreground/60 hover:border-border/60"
                )}
              >
                {filterStatus
                  ? DEFAULT_STATES.find((s) => s.id === filterStatus)?.name || filterStatus
                  : "Stato"}
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent className="bg-card border-border rounded-xl shadow-2xl w-44">
              <DropdownMenuItem
                className="text-[11px] font-bold cursor-pointer"
                onClick={() => setFilterStatus(null)}
              >
                Tutti
              </DropdownMenuItem>
              {DEFAULT_STATES.map((s) => (
                <DropdownMenuItem
                  key={s.id}
                  className="text-[11px] font-bold cursor-pointer"
                  onClick={() => setFilterStatus(s.id)}
                >
                  <div className="h-2 w-2 rounded-full mr-2" style={{ backgroundColor: s.color }} />
                  {s.name}
                </DropdownMenuItem>
              ))}
            </DropdownMenuContent>
          </DropdownMenu>

          {/* Priority filter */}
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                variant="ghost"
                size="sm"
                className={cn(
                  "h-7 px-3 rounded-lg text-[10px] font-black uppercase tracking-wider border transition-all",
                  filterPriority
                    ? "bg-primary/10 border-primary/30 text-primary"
                    : "border-border/30 text-muted-foreground/60 hover:border-border/60"
                )}
              >
                <Flag className="h-3 w-3 mr-1" />
                {filterPriority ? PRIORITIES.find(p => p.id === filterPriority)?.label : "Priorità"}
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent className="bg-card border-border rounded-xl shadow-2xl w-36">
              <DropdownMenuItem className="text-[11px] font-bold cursor-pointer" onClick={() => setFilterPriority(null)}>Tutte</DropdownMenuItem>
              {PRIORITIES.map((p) => (
                <DropdownMenuItem key={p.id} className={`text-[11px] font-bold cursor-pointer ${p.color}`} onClick={() => setFilterPriority(p.id)}>
                  <Flag className="h-3 w-3 mr-2" fill="currentColor" />{p.label}
                </DropdownMenuItem>
              ))}
            </DropdownMenuContent>
          </DropdownMenu>

          {activeFilters > 0 && (
            <Button
              variant="ghost"
              size="sm"
              className="h-7 px-2 rounded-lg text-[10px] font-black text-muted-foreground/50 hover:text-red-400 gap-1"
              onClick={() => { setFilterAssignee(null); setFilterStatus(null); setFilterPriority(null); }}
            >
              <X className="h-3 w-3" /> Reset
            </Button>
          )}

          <span className="ml-auto text-[9px] font-black text-muted-foreground/30 uppercase tracking-widest">
            {tasks.length} task
          </span>
        </div>
      )}

      {/* Quick Add Bar - Moved to Top for better UX in large lists */}
      <div className="px-6 py-2 border-b border-border/5 bg-card/5 shrink-0">
        {quickAddActive ? (
          <div className="flex items-center gap-3 h-9 bg-primary/5 rounded-lg px-3 animate-in fade-in slide-in-from-top-1 duration-150">
            <Plus className="h-3.5 w-3.5 text-primary" />
            <input
              ref={quickAddRef}
              autoFocus
              className="flex-1 bg-transparent border-none outline-none text-[12px] font-bold text-white placeholder:text-muted-foreground/40"
              placeholder="Cosa devi fare? (Invio per creare)"
              value={quickAddTitle}
              onChange={e => setQuickAddTitle(e.target.value)}
              onKeyDown={e => {
                if (e.key === "Enter") handleQuickAdd();
                if (e.key === "Escape") { setQuickAddActive(false); setQuickAddTitle(""); }
              }}
              onBlur={() => { if (!quickAddTitle.trim()) setQuickAddActive(false); }}
            />
          </div>
        ) : (
          <Button
            variant="ghost"
            size="sm"
            className="h-8 w-full justify-start text-[10px] font-black uppercase tracking-widest text-muted-foreground/30 hover:text-primary hover:bg-primary/5 group rounded-lg"
            onClick={() => { setQuickAddActive(true); setQuickAddTitle(""); }}
          >
            <Plus className="h-3.5 w-3.5 mr-2 group-hover:scale-125 transition-transform" />
            Nuova Task
          </Button>
        )}
      </div>

      <div className="flex-1 overflow-auto scrollbar-thin scrollbar-thumb-primary/20 hover:scrollbar-thumb-primary/40 scrollbar-track-transparent" ref={parentRef}>
        <Table className="border-collapse">
          <TableHeader className="sticky top-0 bg-background/95 backdrop-blur-md z-10 border-b border-border/10">
            <TableRow className="hover:bg-transparent border-none h-10">
              <TableHead className="w-10 h-10 px-4" />
              <TableHead className="h-10 px-0">
                <button
                  onClick={() => toggleSort("title")}
                  className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest text-muted-foreground/50 hover:text-white transition-colors"
                >
                  Task <ArrowUpDown className="h-2.5 w-2.5 opacity-50" />
                </button>
              </TableHead>
              <TableHead className="h-10 px-4">
                <button
                  onClick={() => toggleSort("assegnatario")}
                  className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest text-muted-foreground/50 hover:text-white transition-colors"
                >
                  Proprietario <ArrowUpDown className="h-2.5 w-2.5 opacity-50" />
                </button>
              </TableHead>
              <TableHead className="h-10 px-4">
                <button
                  onClick={() => toggleSort("stato")}
                  className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest text-muted-foreground/50 hover:text-white transition-colors"
                >
                  Stato <ArrowUpDown className="h-2.5 w-2.5 opacity-50" />
                </button>
              </TableHead>
              <TableHead className="h-10 px-4 w-[120px]">
                 <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground/50">Tempo</span>
              </TableHead>
              <TableHead className="h-10 px-4">
                <button
                  onClick={() => toggleSort("due_date")}
                  className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest text-muted-foreground/50 hover:text-white transition-colors"
                >
                  Scadenza <ArrowUpDown className="h-2.5 w-2.5 opacity-50" />
                </button>
              </TableHead>
              <TableHead className="w-16 h-10 px-2" />
            </TableRow>
          </TableHeader>
          <TableBody style={{ height: `${virtualizer.getTotalSize()}px`, position: "relative" }}>
            {tasks.length === 0 ? (
              <TableRow>
                <TableCell colSpan={7} className="h-48 text-center">
                  <p className="text-[11px] font-black uppercase tracking-[0.2em] text-muted-foreground/30 italic">
                    Nessuna task trovata
                  </p>
                </TableCell>
              </TableRow>
            ) : (
              virtualizer.getVirtualItems().map((virtualRow) => {
                const task = tasks[virtualRow.index];
                return (
                  <TaskRow
                    key={task.id}
                    task={task}
                    depth={0}
                    utenti={utenti as any[]}
                    getUserInitials={getUserInitials}
                    getUserName={getUserName}
                    style={{
                      position: 'absolute',
                      top: 0,
                      left: 0,
                      width: '100%',
                      height: `${virtualRow.size}px`,
                      transform: `translateY(${virtualRow.start}px)`,
                    }}
                  />
                );
              })
            )}
          </TableBody>
        </Table>
      </div>
    </div>
  );
}

interface TaskRowProps {
  task: TaskSO | SubtaskSO;
  depth: number;
  utenti: any[];
  getUserInitials: (id?: string | null) => string | null;
  getUserName: (id?: string | null) => string | null;
  style?: React.CSSProperties;
}

function TaskRow({ task, depth, utenti, getUserInitials, getUserName, style }: TaskRowProps) {
  const [expanded, setExpanded] = useState(false);
  const { timer, selectTask, openTab } = useStudio();
  const { updateTask } = useTaskMutations();

  const subtasks = "subtasks" in task ? task.subtasks : [];
  const hasSubtasks = subtasks && subtasks.length > 0;
  const isTimerActive = timer.active_session?.task_id === task.id;

  const completedSubtasks = subtasks.filter(
    (st) => st.stateId === "done" || st.stateId === "COMPLETATO"
  ).length;
  const totalSubtasks = subtasks.length;

  const handleStatusChange = async (newStatus: string) => {
    try {
      await updateTask.mutateAsync({ id: task.id, data: { stato: newStatus } });
      toast.success("Stato aggiornato");
    } catch {
      toast.error("Errore aggiornamento stato");
    }
  };

  const currentStatus =
    DEFAULT_STATES.find(
      (s) => s.id === ((task as any).state_id || (task as any).stateId)
    ) || DEFAULT_STATES[0];

  // Due date display
  const dueDate = (task as any).due_date;
  const dueDateEl = dueDate ? (() => {
    const d = parseISO(dueDate);
    const overdue = isBefore(d, new Date()) && !isToday(d);
    const today  = isToday(d);
    return (
      <span
        className={cn(
          "text-[11px] font-bold",
          overdue ? "text-red-400" : today ? "text-yellow-400" : "text-muted-foreground/60"
        )}
      >
        {overdue && "⚠ "}
        {format(d, "d MMM", { locale: it })}
        {today && " · Oggi"}
      </span>
    );
  })() : <span className="text-muted-foreground/20 text-[11px]">—</span>;

  // Assignee
  const initials = getUserInitials((task as any).assegnatario_id);
  const fullName = getUserName((task as any).assegnatario_id);

  const handleRowClick = () => {
    openTab({ type: "TASK", title: task.title, linkedId: task.id });
  };

  return (
    <>
      <tr
      className={cn(
        "group border-b border-border/5 hover:bg-white/5 transition-all cursor-pointer select-none",
        isTimerActive && "bg-primary/5 border-primary/20"
      )}
      onClick={handleRowClick}
      style={style}
    >
        {/* Name */}
        <TableCell className="py-0 px-4 h-12 w-full">
          <div
            className="flex items-center gap-2.5"
            style={{ paddingLeft: `${depth * 20}px` }}
          >
            {hasSubtasks ? (
              <button
                onClick={(e) => { e.stopPropagation(); setExpanded(!expanded); }}
                className="p-1 rounded-md hover:bg-white/10 text-muted-foreground/40 hover:text-white transition-colors shrink-0"
              >
                {expanded ? (
                  <ChevronDown className="h-3.5 w-3.5" />
                ) : (
                  <ChevronRight className="h-3.5 w-3.5" />
                )}
              </button>
            ) : (
              <div className="w-[22px] shrink-0" />
            )}

            <div
              className={cn(
                "h-2 w-2 rounded-full shrink-0 transition-all",
                isTimerActive
                  ? "bg-primary animate-pulse shadow-[0_0_12px_hsl(var(--primary))]"
                  : "bg-muted-foreground/30 group-hover:bg-muted-foreground/50"
              )}
            />

            {/* Priority flag */}
            {(() => {
              const p = PRIORITIES.find(p => p.id === ((task as any).priorita || "media"));
              return p ? (
                <Flag
                  className={cn("h-3 w-3 shrink-0 opacity-70 group-hover:opacity-100 transition-opacity", p.color)}
                  fill="currentColor"
                />
              ) : null;
            })()}

            <span
              className={cn(
                "text-[12px] font-black uppercase tracking-tight italic transition-colors duration-200",
                isTimerActive ? "text-primary" : "text-foreground group-hover:text-primary"
              )}
            >
              {task.title}
            </span>

            {isTimerActive && (
              <Badge className="ml-1 bg-primary/20 text-primary border-primary/30 text-[9px] font-black tracking-widest h-[18px] uppercase shrink-0 shadow-[0_0_10px_hsl(var(--primary)/0.2)]">
                Live
              </Badge>
            )}

            {totalSubtasks > 0 && (
              <Badge
                variant="outline"
                className="ml-2 bg-transparent border-border/30 text-muted-foreground group-hover:border-border text-[9px] font-black h-[18px] gap-1 shrink-0 transition-colors"
                title={`${completedSubtasks} completate su ${totalSubtasks}`}
              >
                <CheckCircle2 className={cn("h-2.5 w-2.5", completedSubtasks === totalSubtasks ? "text-emerald-400" : "text-primary")} />
                {completedSubtasks}/{totalSubtasks}
              </Badge>
            )}

            {(task.tempo_trascorso_minuti || 0) > 0 && !isTimerActive && (
              <Badge
                variant="outline"
                className="ml-1 bg-transparent border-transparent group-hover:border-border/30 text-muted-foreground/50 group-hover:text-muted-foreground text-[9px] font-black h-[18px] gap-1 shrink-0 transition-colors"
              >
                <Clock3 className="h-2.5 w-2.5" />
                {(task.tempo_trascorso_minuti || 0) >= 60
                  ? `${Math.floor((task.tempo_trascorso_minuti || 0) / 60)}h ${(task.tempo_trascorso_minuti || 0) % 60}m`
                  : `${task.tempo_trascorso_minuti}m`}
              </Badge>
            )}
          </div>
        </TableCell>

        {/* Assignee */}
        <TableCell className="py-0 px-4">
          {initials ? (
            <div
              className={cn(
                "h-7 w-7 rounded-lg flex items-center justify-center text-[10px] font-black border border-white/5",
                avatarColor((task as any).assegnatario_id || "x")
              )}
              title={fullName || ""}
            >
              {initials}
            </div>
          ) : (
            <div className="h-7 w-7 rounded-lg bg-muted/20 border border-border/20 flex items-center justify-center">
              <span className="text-[9px] text-muted-foreground/20">—</span>
            </div>
          )}
        </TableCell>

        {/* Status */}
        <TableCell className="py-0 px-4 w-[140px]">
          <DropdownMenu>
            <DropdownMenuTrigger asChild onClick={(e) => e.stopPropagation()}>
              <button
                className="flex items-center gap-1.5 px-2.5 h-[22px] rounded-full text-[10px] font-black uppercase tracking-wider cursor-pointer transition-all border group-hover:shadow-sm"
                style={{
                  borderColor: currentStatus.color + "40",
                  color: currentStatus.color,
                  backgroundColor: currentStatus.color + "10",
                }}
              >
                <div className="h-1.5 w-1.5 rounded-full" style={{ backgroundColor: currentStatus.color }} />
                <span className="truncate">{currentStatus.name}</span>
              </button>
            </DropdownMenuTrigger>
            <DropdownMenuContent
              align="start"
              className="bg-card border-border rounded-xl shadow-2xl w-44"
            >
              {DEFAULT_STATES.map((state) => (
                <DropdownMenuItem
                  key={state.id}
                  onClick={(e) => { e.stopPropagation(); handleStatusChange(state.id); }}
                  className="text-[10px] font-black uppercase tracking-widest py-2 focus:bg-primary/10 cursor-pointer"
                >
                  <div
                    className="h-2 w-2 rounded-full mr-2"
                    style={{ backgroundColor: state.color }}
                  />
                  {state.name}
                </DropdownMenuItem>
              ))}
            </DropdownMenuContent>
          </DropdownMenu>
        </TableCell>

        {/* Time */}
        <TableCell className="py-0 px-4 w-[120px]">
          <div className="flex items-center gap-2 tabular-nums">
            <Clock
              className={cn("h-3.5 w-3.5 shrink-0 transition-colors", isTimerActive ? "text-primary animate-pulse" : "text-muted-foreground/30 group-hover:text-muted-foreground")}
            />
            <div className="flex flex-col leading-tight">
              <span
                className={cn(
                  "text-[12px] font-bold tracking-tighter",
                  isTimerActive ? "text-primary drop-shadow-[0_0_8px_hsl(var(--primary)/0.6)]" : "text-muted-foreground group-hover:text-white"
                )}
              >
                {formatTime(timer.getElapsed(task.id))}
              </span>
              {"stima_minuti" in task &&
                task.stima_minuti &&
                task.stima_minuti > 0 && (
                  <span
                    className={cn(
                      "text-[9px] font-bold tracking-tight",
                      timer.getElapsed(task.id) / 60000 > task.stima_minuti * 1.2
                        ? "text-red-400"
                        : timer.getElapsed(task.id) / 60000 > task.stima_minuti
                        ? "text-orange-400"
                        : "text-muted-foreground/40 group-hover:text-muted-foreground/70"
                    )}
                  >
                    Est: {task.stima_minuti}m
                  </span>
                )}
            </div>
          </div>
        </TableCell>

        {/* Due date */}
        <TableCell className="py-0 px-4">{dueDateEl}</TableCell>

        {/* Actions */}
        <TableCell className="py-0 px-2 text-center">
          <div className="flex items-center justify-center gap-0.5">
            {!isTimerActive ? (
              <Button
                variant="ghost"
                size="icon"
                className="h-8 w-8 text-emerald-500 hover:text-emerald-400 hover:bg-emerald-500/15 rounded-lg opacity-0 group-hover:opacity-100 transition-all scale-95 group-hover:scale-100 bg-emerald-500/5 shadow-sm"
                onClick={(e) => { e.stopPropagation(); timer.start(task.id); }}
                title="Avvia timer"
              >
                <Play className="h-3.5 w-3.5 fill-current" />
              </Button>
            ) : (
              <Button
                variant="ghost"
                size="icon"
                className="h-7 w-7 text-red-400 hover:text-red-300 hover:bg-red-500/10 rounded-lg"
                onClick={(e) => { e.stopPropagation(); timer.stop(timer.active_session!.id); }}
                title="Ferma timer"
              >
                <StopCircle className="h-3.5 w-3.5 fill-current" />
              </Button>
            )}
            <DropdownMenu>
              <DropdownMenuTrigger asChild onClick={(e) => e.stopPropagation()}>
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-7 w-7 text-muted-foreground/20 hover:text-foreground/70 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <MoreVertical className="h-3.5 w-3.5" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end" className="bg-card border-border rounded-xl shadow-2xl w-40">
                <DropdownMenuItem
                  className="text-[11px] font-bold cursor-pointer"
                  onClick={(e) => { e.stopPropagation(); handleRowClick(); }}
                >
                  Apri dettaglio
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        </TableCell>
      </tr>

      {expanded &&
        hasSubtasks &&
        subtasks.map((sub) => (
          <TaskRow
            key={sub.id}
            task={sub}
            depth={depth + 1}
            utenti={utenti}
            getUserInitials={getUserInitials}
            getUserName={getUserName}
          />
        ))}
    </>
  );
}

import { useEffect, useMemo, useRef, useState } from "react";
import { 
  Plus, 
  Play, 
  CheckCircle2, 
  Trash2, 
  Save,
  Briefcase,
  History,
  StopCircle,
  AlertCircle,
  Clock3
} from "lucide-react";
import { 
  Dialog, 
  DialogContent, 
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { useStudio } from "@/hooks/useStudio";
import { useTasks, useTaskMutations } from "@/hooks/useTasks";
import { useCommesse } from "@/hooks/useCommesse";
import { useTimerSessions, useSaveTimerToTimesheet } from "@/hooks/useTimer";
import { useUsers } from "@/hooks/useUsers";
import { useTimeEstimate, useUserCapacity, type TimeEstimate, type UserCapacity } from "@/hooks/useML";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import type { User } from "@/types";

import { 
  Select, 
  SelectContent, 
  SelectItem, 
  SelectTrigger, 
  SelectValue 
} from "@/components/ui/select";
import { format } from "date-fns";
import { toast } from "sonner";

type StudioTaskRecord = NonNullable<ReturnType<typeof useTasks>["data"]>[number];

type TaskFormData = {
  titolo: string;
  descrizione: string;
  commessa_id: string;
  stato: string;
  data_inizio: string;
  data_scadenza: string;
  assegnatario_id: string;
  stima_minuti: number | null;
};

function createEmptyTaskFormData(): TaskFormData {
  return {
    titolo: "",
    descrizione: "",
    commessa_id: "none",
    stato: "DA_FARE",
    data_inizio: "",
    data_scadenza: "",
    assegnatario_id: "none",
    stima_minuti: null,
  };
}

function createTaskFormData(task: StudioTaskRecord | null): TaskFormData {
  if (!task) {
    return createEmptyTaskFormData();
  }

  return {
    titolo: task.title,
    descrizione: task.desc || "",
    commessa_id: task.commessa_id || "none",
    stato: task.state_id,
    data_inizio: task.data_inizio || "",
    data_scadenza: task.due_date || "",
    assegnatario_id: task.assegnatario_id || "none",
    stima_minuti: task.stima_minuti ?? null,
  };
}

export function StudioTaskModal() {
  const { nav, selectTask, timer } = useStudio();
  const { data: tasks } = useTasks({ parent_only: false });
  const { data: commesse } = useCommesse();
  const { data: utenti } = useUsers();
  const { createTask, updateTask, deleteTask } = useTaskMutations();

  const isNew = nav.selectedTaskId === "new";

  const task = useMemo(() => {
    if (isNew || !nav.selectedTaskId) return null;
    return tasks?.find(t => t.id === nav.selectedTaskId) || null;
  }, [tasks, nav.selectedTaskId, isNew]);

  const { data: sessions = [] } = useTimerSessions(task?.id || null);
  const saveToTimesheetMutation = useSaveTimerToTimesheet();

  const formSourceId = task?.id ?? `new:${nav.selectedListId ?? "none"}`;
  const baseFormData = useMemo(() => createTaskFormData(task), [task]);
  const [formDraft, setFormDraft] = useState<{ sourceId: string; data: TaskFormData } | null>(null);
  const formData = formDraft?.sourceId === formSourceId ? formDraft.data : baseFormData;
  const setFormData = (updater: TaskFormData | ((current: TaskFormData) => TaskFormData)) => {
    setFormDraft((current) => {
      const currentData = current?.sourceId === formSourceId ? current.data : baseFormData;
      return {
        sourceId: formSourceId,
        data: typeof updater === "function"
          ? (updater as (current: TaskFormData) => TaskFormData)(currentData)
          : updater,
      };
    });
  };

  const [isAddingSubtask, setIsAddingSubtask] = useState(false);
  const [newSubtaskTitle, setNewSubtaskTitle] = useState("");

  const [debouncedTitolo, setDebouncedTitolo] = useState("");

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedTitolo(formData.titolo);
    }, 500);
    return () => clearTimeout(handler);
  }, [formData.titolo]);

  const { data: estimate } = useTimeEstimate(
    formData.assegnatario_id !== "none" ? formData.assegnatario_id : null,
    debouncedTitolo
  ) as { data: TimeEstimate | undefined };

  const { data: capacity } = useUserCapacity(
    formData.assegnatario_id !== "none" ? formData.assegnatario_id : null
  ) as { data: UserCapacity | undefined };
  const effectiveStimaMinuti =
    formData.stima_minuti ?? (isNew ? estimate?.stima_minuti ?? null : null);
  const lastActiveSessionIdRef = useRef<string | null>(null);

  useEffect(() => {
    if (timer.active_session && timer.active_session.task_id === task?.id) {
      lastActiveSessionIdRef.current = timer.active_session.id;
    } else if (!timer.active_session && lastActiveSessionIdRef.current && task) {
      // Timer appena stoppato! Mostriamo il toast per il salvataggio
      const sessionIdToSave = lastActiveSessionIdRef.current;
      toast("Sessione terminata", {
        description: "Vuoi salvare il tempo nel timesheet?",
        action: {
          label: "SÌ, SALVA",
          onClick: () => {
            saveToTimesheetMutation.mutate({ 
              session_ids: [sessionIdToSave], 
              commessa_id: task.commessa_id === "none" ? undefined : task.commessa_id 
            });
          }
        },
        duration: 10000,
      });
      lastActiveSessionIdRef.current = null;
    }
  }, [timer.active_session, task, saveToTimesheetMutation]);

  if (!nav.selectedTaskId) return null;

  const isTimerActive = !isNew && task && timer.active_session?.task_id === task.id;

  const handleSave = async () => {
    if (formData.data_inizio && formData.data_scadenza) {
      if (new Date(formData.data_scadenza) < new Date(formData.data_inizio)) {
        return toast.error("La data di scadenza non può essere antecedente alla data di inizio");
      }
    }

    const payload = {
      ...formData,
      commessa_id: formData.commessa_id === "none" ? null : formData.commessa_id,
      assegnatario_id: formData.assegnatario_id === "none" ? null : formData.assegnatario_id,
      progetto_id: nav.selectedListId,
    };

    const cleanPayload = {
      ...payload,
      data_inizio: payload.data_inizio || null,
      data_scadenza: payload.data_scadenza || null,
      stima_minuti: effectiveStimaMinuti,
      assegnatario_id: payload.assegnatario_id || null,
      commessa_id: payload.commessa_id || null,
    };

    try {
      if (isNew) {
        await createTask.mutateAsync(cleanPayload);
        toast.success("Task creata con successo");
      } else {
        await updateTask.mutateAsync({ id: task!.id, data: cleanPayload });
        toast.success("Task aggiornata");
      }
      selectTask(null);
    } catch (err) {
      toast.error("Errore durante il salvataggio");
    }
  };

  const handleCreateSubtask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newSubtaskTitle.trim() || !task) return;

    try {
      await createTask.mutateAsync({
        titolo: newSubtaskTitle.trim(),
        parent_id: task.id,
        progetto_id: task.progetto_id,
        commessa_id: task.commessa_id,
        stato: "DA_FARE"
      });
      setNewSubtaskTitle("");
      setIsAddingSubtask(false);
      toast.success("Subtask creata");
    } catch (err) {
      toast.error("Errore nella creazione della subtask");
    }
  };

  const handleToggleSubtask = async (sub: any) => {
    const newStatus = (sub.stateId === "COMPLETATO" || sub.stateId === "done") ? "DA_FARE" : "COMPLETATO";
    try {
      await updateTask.mutateAsync({ id: sub.id, data: { stato: newStatus } });
    } catch (err) {
      toast.error("Errore nell'aggiornamento della subtask");
    }
  };

  const handleDeleteSubtask = async (id: string) => {
    if (!window.confirm("Sei sicuro di voler eliminare questa subtask?")) return;
    try {
      await deleteTask.mutateAsync(id);
      toast.success("Subtask eliminata");
    } catch (err) {
      toast.error("Errore nell'eliminazione della subtask");
    }
  };

  const handleDelete = async () => {
    if (window.confirm("Sei sicuro di voler eliminare questa task?")) {
      try {
        await deleteTask.mutateAsync(task!.id);
        toast.success("Task eliminata");
        selectTask(null);
