        </div>
      </div>
    </div>
  );
}

import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import axios from '@/lib/api';
import { useAuth } from '@/hooks/useAuth';

interface ChatContextType {
  channels: any[];
  users: any[];
  messages: any[];
  isLoading: boolean;
  activeChannelId: string | null;
  setActiveChannelId: (id: string | null) => void;
  hasMore: boolean;
  typingUsers: string[];
  onlineUsers: Set<string>;
  channelSeenStatus: Record<string, Record<string, string>>;
  unreadCounts: Record<string, number>;
  loadMoreMessages: () => Promise<void>;
  sendMessage: (content: string, type?: string, replyToId?: string) => Promise<void>;
  uploadFile: (file: File) => Promise<any>;
  startDirectChat: (userId: string) => Promise<any>;
  editMessage: (id: string, content: string) => Promise<void>;
  deleteMessage: (id: string) => Promise<void>;
  addReaction: (messageId: string, emoji: string) => Promise<void>;
  removeReaction: (messageId: string, emoji: string) => Promise<void>;
  setTypingStatus: (isTyping: boolean) => void;
  markAsSeen: (channelId: string) => void;
}

const ChatContext = createContext<ChatContextType | undefined>(undefined);

export function ChatProvider({ children }: { children: React.ReactNode }) {
  const { user, isLoading: isAuthLoading } = useAuth();
  const queryClient = useQueryClient();

  const [activeChannelId, setActiveChannelId] = useState<string | null>(() => {
    return new URLSearchParams(window.location.search).get('channel');
  });
  const [typingUsers, setTypingUsers] = useState<string[]>([]);
  const [onlineUsers, setOnlineUsers] = useState<Set<string>>(new Set());
  const [hasMore, setHasMore] = useState(true);
  const [offset, setOffset] = useState(0);
  const [channelSeenStatus, setChannelSeenStatus] = useState<Record<string, Record<string, string>>>({});
  const [unreadCounts, setUnreadCounts] = useState<Record<string, number>>({});

  const ws = useRef<WebSocket | null>(null);
  const activeChannelIdRef = useRef<string | null>(activeChannelId);
  const connectWSRef = useRef<() => Promise<void>>(async () => {});
  const reconnectAttemptsRef = useRef(0);
  const reconnectTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const isUnmountedRef = useRef(false);
  const LIMIT = 50;

  useEffect(() => {
    activeChannelIdRef.current = activeChannelId;
  }, [activeChannelId]);

  // Data Fetching
  const { data: channels, isLoading: isChannelsLoading } = useQuery({
    queryKey: ['chat-channels'],
    queryFn: async () => {
      const res = await axios.get('/chat/channels');
      return res.data;
    },
    enabled: !!user,
    refetchInterval: 60000,
  });

  const { data: users = [] } = useQuery({
    queryKey: ['chat-users'],
    queryFn: async () => {
      const res = await axios.get('/chat/users');
      return res.data;
    },
    enabled: !!user,
  });

  const { data: messages = [], isLoading: isMessagesLoading } = useQuery({
    queryKey: ['chat-messages', activeChannelId],
    queryFn: async () => {
      if (!activeChannelId) return [];
      const res = await axios.get(`/chat/channels/${activeChannelId}/messages?limit=${LIMIT}&offset=0`);
      if (res.data.length < LIMIT) setHasMore(false);
      else setHasMore(true);
      setOffset(res.data.length);
      return res.data;
    },
    enabled: !!activeChannelId,
    staleTime: Infinity,
  });

  const loadMoreMessages = useCallback(async () => {
    if (!activeChannelId || !hasMore) return;
    try {
      const res = await axios.get(`/chat/channels/${activeChannelId}/messages?limit=${LIMIT}&offset=${offset}`);
      if (res.data.length < LIMIT) setHasMore(false);
      queryClient.setQueryData(['chat-messages', activeChannelId], (prev: any) => {
        return [...res.data, ...(prev || [])];
      });
      setOffset(prev => prev + res.data.length);
    } catch (err) {
      console.error("Load more failed", err);
    }
  }, [activeChannelId, offset, hasMore, queryClient]);

  // WebSocket
  const connectWS = useCallback(async () => {
    if (!user || isUnmountedRef.current) return;
    if (
      ws.current &&
      (ws.current.readyState === WebSocket.OPEN || ws.current.readyState === WebSocket.CONNECTING)
    ) return;

    const scheduleReconnect = () => {
      if (isUnmountedRef.current) return;
      if (reconnectTimeoutRef.current) clearTimeout(reconnectTimeoutRef.current);
      const delay = Math.min(1000 * Math.pow(2, reconnectAttemptsRef.current), 30000);
      reconnectAttemptsRef.current += 1;
      reconnectTimeoutRef.current = setTimeout(() => {
        void connectWSRef.current();
      }, delay);
    };

    try {
      const ticketResponse = await axios.post('/chat/ws-ticket');
      if (isUnmountedRef.current) return;

      const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
      const wsUrl = `${protocol}//${window.location.host}/api/v1/chat/ws?ticket=${encodeURIComponent(ticketResponse.data.ticket)}`;
      const socket = new WebSocket(wsUrl);
      ws.current = socket;

      socket.onopen = () => {
        reconnectAttemptsRef.current = 0;
      };

      socket.onmessage = (event) => {
        const data = JSON.parse(event.data);
        const currentChannelId = activeChannelIdRef.current;

        switch (data.type) {
          case 'new_message': {
            queryClient.setQueryData(['chat-channels'], (old: any) => {
              return old?.map((c: any) => c.id === data.message.canale_id ? {
                ...c,
                last_message: data.message.tipo !== 'testo' ? '[Allegato]' : data.message.contenuto,
                last_message_at: data.message.created_at
              } : c);
            });
            if (data.message.canale_id === currentChannelId) {
              queryClient.setQueryData(['chat-messages', currentChannelId], (prev: any) => {
                // Dedup: se il messaggio è già presente non aggiungerlo di nuovo
                const existing = (prev || []) as any[];
                if (existing.some((m: any) => m.id === data.message.id)) return existing;
                return [...existing, data.message];
              });
            } else {
              setUnreadCounts(prev => ({
                ...prev,
                [data.message.canale_id]: (prev[data.message.canale_id] || 0) + 1
              }));
            }
            break;
          }
          case 'message_edited': {
            const targetChannel = data.canale_id || currentChannelId;
            if (targetChannel) {
              queryClient.setQueryData(['chat-messages', targetChannel], (prev: any) =>
                prev?.map((m: any) =>
                  m.id === data.message_id
                    ? { ...m, contenuto: data.contenuto, updated_at: new Date().toISOString(), modificato: true }
                    : m
                )
              );
            }
            break;
          }
          case 'delete_message': {
            const targetChannel = data.canale_id || currentChannelId;
            if (targetChannel) {
              queryClient.setQueryData(['chat-messages', targetChannel], (prev: any) =>
                prev?.filter((m: any) => m.id !== data.message_id)
              );
            }
            break;
          }
          case 'reaction_added': {
            const targetChannel = data.canale_id || currentChannelId;
            if (targetChannel) {
              queryClient.setQueryData(['chat-messages', targetChannel], (prev: any) =>
                prev?.map((m: any) => {
                  if (m.id !== data.message_id) return m;
                  const alreadyHas = m.reazioni?.some((r: any) => r.user_id === data.user_id && r.emoji === data.emoji);
                  if (alreadyHas) return m;
                  return {
                    ...m,
                    reazioni: [...(m.reazioni || []), { id: crypto.randomUUID(), emoji: data.emoji, user_id: data.user_id, user_nome: data.user_nome, created_at: new Date().toISOString() }]
                  };
                })
              );
            }
            break;
          }
          case 'reaction_removed': {
            const targetChannel = data.canale_id || currentChannelId;
            if (targetChannel) {
              queryClient.setQueryData(['chat-messages', targetChannel], (prev: any) =>
                prev?.map((m: any) => {
                  if (m.id !== data.message_id) return m;
                  return {
                    ...m,
                    reazioni: (m.reazioni || []).filter(
                      (reaction: any) => !(reaction.user_id === data.user_id && reaction.emoji === data.emoji)
                    )
                  };
                })
              );
            }
            break;
          }
          case 'user_typing':
            if (data.channel_id === currentChannelId) {
              setTypingUsers(prev => data.is_typing ? [...new Set([...prev, data.user_nome])] : prev.filter(n => n !== data.user_nome));
            }
            break;
          case 'user_presence':
            setOnlineUsers(prev => {
              const next = new Set(prev);
              if (data.status === 'online') next.add(data.user_id);
              else next.delete(data.user_id);
              return next;
            });
            break;
          case 'message_seen':
            setChannelSeenStatus((prev) => ({
              ...prev,
              [data.channel_id]: {
                ...(prev[data.channel_id] || {}),
                [data.user_id]: data.last_seen_at,
              },
            }));
            break;
        }
      };

      socket.onclose = () => {
        if (ws.current === socket) {
          ws.current = null;
        }
        scheduleReconnect();
      };

      socket.onerror = () => socket.close();
    } catch (err) {
      console.error("WS bootstrap failed", err);
      scheduleReconnect();
    }
  }, [user, queryClient]);

  useEffect(() => {
    connectWSRef.current = connectWS;
  }, [connectWS]);

  useEffect(() => {
    isUnmountedRef.current = false;
    // Don't connect if loading auth, or no token, or no user (e.g. on login page)
    if (isAuthLoading || !user) return;
    
    void connectWS();
    return () => {
      isUnmountedRef.current = true;
      if (reconnectTimeoutRef.current) clearTimeout(reconnectTimeoutRef.current);
      
      if (ws.current) {
        // Remove listeners before closing to avoid "closed before established" console noise 
        // and prevent any further logic from firing during unmount
        const socket = ws.current;
        socket.onopen = null;
        socket.onmessage = null;
        socket.onerror = null;
        socket.onclose = null;
        
        // Only close if fully open to avoid "closed before established" warning.
        // We already cleared listeners, so it won't trigger any logic if it's connecting.
        if (socket.readyState === WebSocket.OPEN) {
          socket.close();
        }
        ws.current = null;
      }
    };
  }, [user, isAuthLoading, connectWS]);

  // Actions
  const sendMessage = useCallback(async (content: string, type: string = 'testo', replyToId?: string) => {
    if (!activeChannelId) return;
    const activeChannel = channels?.find((c: any) => c.id === activeChannelId);
    await axios.post('/chat/messages', {
      canale_id: activeChannelId,
      progetto_id: activeChannel?.progetto_id,
      contenuto: content,
      tipo: type,
      risposta_a: replyToId
    });
  }, [activeChannelId, channels]);

  const uploadFile = useCallback(async (file: File) => {
    const formData = new FormData();
    formData.append('file', file);
    const res = await axios.post('/uploads', formData, { headers: { 'Content-Type': 'multipart/form-data' } });
    return res.data;
  }, []);

  const editMessage = useCallback(async (id: string, content: string) => {
    await axios.patch(`/chat/messages/${id}`, { contenuto: content });
  }, []);

  const deleteMessage = useCallback(async (id: string) => {
    await axios.delete(`/chat/messages/${id}`);
  }, []);

  const addReaction = useCallback(async (messageId: string, emoji: string) => {
    await axios.post(`/chat/messages/${messageId}/reactions`, { emoji });
  }, []);

  const removeReaction = useCallback(async (messageId: string, emoji: string) => {
    await axios.delete(`/chat/messages/${messageId}/reactions/${encodeURIComponent(emoji)}`);
  }, []);

  const setTypingStatus = useCallback((isTyping: boolean) => {
    if (ws.current?.readyState === WebSocket.OPEN && activeChannelId) {
      ws.current.send(JSON.stringify({ type: 'typing', channel_id: activeChannelId, is_typing: isTyping }));
    }
  }, [activeChannelId]);

  const markAsSeen = useCallback((channelId: string) => {
    setUnreadCounts(prev => prev[channelId] === 0 ? prev : { ...prev, [channelId]: 0 });
    if (ws.current?.readyState === WebSocket.OPEN) {
      ws.current.send(JSON.stringify({ type: 'message_seen', channel_id: channelId }));
    }
  }, []);

  const startDirectChat = useCallback(async (userId: string) => {
    try {
      const res = await axios.post('/chat/channels/direct', { other_user_id: userId });
      const newChannel = res.data;
      queryClient.setQueryData(['chat-channels'], (old: any) => {
        if (!old?.find((c: any) => c.id === newChannel.id)) return [newChannel, ...(old || [])];
        return old;
      });
      setActiveChannelId(newChannel.id);
      return newChannel;
    } catch (err) {
      console.error("Failed to start DM", err);
    }
  }, [queryClient]);

  const value = {
    channels: channels || [],
    users,
    messages,
    isLoading: isAuthLoading || isChannelsLoading || isMessagesLoading,
    activeChannelId,
    setActiveChannelId,
    hasMore,
    typingUsers,
    onlineUsers,
    channelSeenStatus,
    unreadCounts,
    loadMoreMessages,
    sendMessage,
    uploadFile,
    startDirectChat,
    editMessage,
    deleteMessage,
    addReaction,
    removeReaction,
    setTypingStatus,
    markAsSeen
  };

  return <ChatContext.Provider value={value}>{children}</ChatContext.Provider>;
}

export function useChatContext() {
  const context = useContext(ChatContext);
  if (context === undefined) {
    throw new Error('useChatContext must be used within a ChatProvider');
  }
  return context;
}

import React, { createContext, useState, useEffect, useCallback, useMemo } from "react";
import type { StudioState, StudioView, StudioTimer, SpaceSO } from "@/types/studio";
import { useClienti } from "@/hooks/useClienti";
import { useProgetti } from "@/hooks/useProgetti";
import { useActiveTimer, useStartTimer, useStopTimer, useSaveTimerToTimesheet } from "@/hooks/useTimer";
import type { Cliente, Progetto } from "@/types";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import api from "@/lib/api";
import type { StudioNode, TabItem } from "@/types/studio";
import { toast } from "sonner";

interface StudioContextType {
  nav: StudioState;
  setView: (view: StudioView) => void;
  selectFolder: (id: string | null) => void;
  selectList: (id: string | null, folderId?: string | null) => void;
  selectTask: (id: string | null) => void;
  isLoading: boolean;
  hierarchy: StudioNode[];
  tabs: TabItem[];
  activeTabId: string | null;
  selectTab: (id: string) => void;
  closeTab: (id: string) => void;
  openTab: (item: Omit<TabItem, "id"> & { id?: string }) => void;
  spaces: SpaceSO[];
  currentFolder: Cliente | null;
  currentList: Progetto | null;
  allProgetti: Progetto[];
  allClienti: Cliente[];
  getFolderProjects: (folderId: string) => Progetto[];
  folderProjects: Progetto[];
  openNewTask: (folderId?: string | null, listId?: string | null) => void;
  splitTabId: string | null;
  openSplit: (tabId: string) => void;
  closeSplit: () => void;
  timer: StudioTimer & {
    start: (taskId: string) => void;
    stop: (sessionId: string, note?: string) => void;
    getElapsed: (taskId: string) => number;
  };
}

export const StudioContext = createContext<StudioContextType | undefined>(undefined);

const STUDIO_NAV_KEY = "studio_os_nav";

export function StudioProvider({ children }: { children: React.ReactNode }) {
  const queryClient = useQueryClient();
  const { data: clienti = [], isLoading: isLoadingClienti } = useClienti();
  const { data: progetti = [], isLoading: isLoadingProgetti } = useProgetti();

  // Navigation State
  const [nav, setNav] = useState<StudioState>(() => {
    const saved = localStorage.getItem(STUDIO_NAV_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        return {
          view: parsed.view || "home",
          selectedFolderId: parsed.selectedFolderId || null,
          selectedListId: parsed.selectedListId || null,
          selectedTaskId: parsed.selectedTaskId || null,
          openTabs: parsed.openTabs || [],
          activeTabId: parsed.activeTabId || null,
          splitTabId: null,
        };
      } catch (e) {
        return { view: "home", selectedFolderId: null, selectedListId: null, selectedTaskId: null, openTabs: [], activeTabId: null, splitTabId: null };
      }
    }
    return { view: "home", selectedFolderId: null, selectedListId: null, selectedTaskId: null, openTabs: [], activeTabId: null, splitTabId: null };
  });

  useEffect(() => {
    localStorage.setItem(STUDIO_NAV_KEY, JSON.stringify(nav));
  }, [nav]);

  // Fetch Hierarchy
  const { data: hierarchy = [], isLoading: isLoadingHierarchy } = useQuery<StudioNode[]>({
    queryKey: ["studio-hierarchy"],
    queryFn: async () => {
      const res = await api.get("/studio/hierarchy");
      return res.data;
    }
  });

  // Tab Actions
  const openTab = useCallback((item: Omit<TabItem, "id"> & { id?: string }) => {
    const tabId = item.id || `${item.type}-${item.linkedId}`;
    setNav(prev => {
      const exists = prev.openTabs.find(t => t.id === tabId);
      const newTabs = exists ? prev.openTabs : [...prev.openTabs, { ...item, id: tabId, view: item.view || (item.type === "PROJECT" ? "list" : "dash") }];
      const currentTab = newTabs.find(t => t.id === tabId);

      return {
        ...prev,
        openTabs: newTabs,
        activeTabId: tabId,
        view: currentTab?.view || (item.type === "PROJECT" ? "list" : prev.view),
        selectedListId: item.type === "PROJECT" ? item.linkedId || null : prev.selectedListId,
        selectedTaskId: item.type === "TASK" ? item.linkedId || null : prev.selectedTaskId,
      };
    });
  }, []);

  const closeTab = useCallback((id: string) => {
    setNav(prev => {
      const newTabs = prev.openTabs.filter(t => t.id !== id);
      const newActiveId = prev.activeTabId === id 
        ? (newTabs.length > 0 ? newTabs[newTabs.length - 1].id : null)
        : prev.activeTabId;
      
      return {
        ...prev,
        openTabs: newTabs,
        activeTabId: newActiveId
      };
    });
  }, []);

  const selectTab = useCallback((id: string) => {
    setNav(prev => {
      const tab = prev.openTabs.find(t => t.id === id);
      if (!tab) return prev;
      return {
        ...prev,
        activeTabId: id,
        view: tab.view || (tab.type === "PROJECT" ? "list" : prev.view),
        selectedListId: tab.type === "PROJECT" ? tab.linkedId || null : prev.selectedListId,
        selectedTaskId: tab.type === "TASK" ? tab.linkedId || null : prev.selectedTaskId,
      };
    });
  }, []);

  // Timer State (Backend Synced)
  const { data: activeSession } = useActiveTimer();
  const startTimerMutation = useStartTimer();
  const stopTimerMutation = useStopTimer();
  const saveToTimesheetMutation = useSaveTimerToTimesheet();

  const [tick, setTick] = useState(0);

  useEffect(() => {
    if (!activeSession) return;
    const interval = setInterval(() => {
      setTick((t) => t + 1);
    }, 1000);
    return () => clearInterval(interval);
  }, [activeSession]);

  // Actions
  const setView = useCallback((view: StudioView) => {
    setNav((prev) => {
      const newTabs = prev.openTabs.map(t => 
        t.id === prev.activeTabId ? { ...t, view } : t
      );
      
      return { 
        ...prev, 
        view,
        openTabs: newTabs,
        // Clear selections when returning to non-project views
        selectedFolderId: (view === "home" || view === "chat") ? null : prev.selectedFolderId,
        selectedListId: (view === "home" || view === "chat") ? null : prev.selectedListId,
        selectedTaskId: (view === "home" || view === "chat") ? null : prev.selectedTaskId,
        activeTabId: (view === "home" || view === "chat") ? null : prev.activeTabId
      };
    });
  }, []);

  const selectFolder = useCallback((id: string | null) => {
    setNav((prev) => ({ 
      ...prev, 
      selectedFolderId: id, 
      selectedListId: null, 
      selectedTaskId: null, 
      view: id ? "overview" : "home" 
    }));
  }, []);

  const selectList = useCallback((id: string | null, folderId?: string | null) => {
    setNav((prev) => ({ 
      ...prev, 
      selectedListId: id, 
      selectedFolderId: folderId ?? prev.selectedFolderId,
      selectedTaskId: null, 
      view: id ? "overview" : "dash" 
    }));
  }, []);

  const selectTask = useCallback((id: string | null) => {
    setNav((prev) => ({ ...prev, selectedTaskId: id }));
  }, []);

  const startTimer = useCallback((taskId: string) => {
    startTimerMutation.mutate(taskId);
  }, [startTimerMutation]);

  const stopTimer = useCallback((sessionId: string, note?: string) => {
    stopTimerMutation.mutate({ sessionId, note }, {
      onSuccess: (stoppedSession) => {
        toast("Timer fermato", {
          description: stoppedSession.durata_minuti
            ? `Sessione di ${stoppedSession.durata_minuti} min registrata`
            : "Sessione registrata",
          action: {
            label: "Salva Timesheet",
            onClick: () => {
              saveToTimesheetMutation.mutate({ session_ids: [stoppedSession.id] });
            },
          },
          duration: 8000,
        });
        queryClient.invalidateQueries({ queryKey: ["timer"] });
      },
    });
  }, [stopTimerMutation, saveToTimesheetMutation, queryClient]);

  const getElapsedTime = useCallback((taskId: string) => {
    if (activeSession?.task_id === taskId && activeSession.started_at) {
      const start = new Date(activeSession.started_at).getTime();
      return Math.max(0, Date.now() - start);
    }
    return 0;
  }, [activeSession, tick]);

  // Hierarchy Data
  const spaces = useMemo<SpaceSO[]>(() => {
    if (!clienti.length) return [];
    const activeClients = clienti.filter(c => c.attivo);
    return [
      {
        id: "main-space",
        name: "Progetti Attivi",
        folders: activeClients
      }
    ];
  }, [clienti]);

  const currentList = useMemo(() => 
    progetti.find(p => p.id === nav.selectedListId) || null
  , [progetti, nav.selectedListId]);

  const currentFolder = useMemo(() => {
    if (nav.selectedFolderId) {
      return clienti.find(c => c.id === nav.selectedFolderId) || null;
    }
    if (currentList?.cliente_id) {
      return clienti.find(c => c.id === currentList.cliente_id) || null;
    }
    return null;
  }, [clienti, nav.selectedFolderId, currentList]);

  const folderProjects = useMemo(() => 
    progetti.filter(p => p.cliente_id === nav.selectedFolderId)
  , [progetti, nav.selectedFolderId]);

  const getFolderProjects = useCallback((folderId: string) => {
    return progetti.filter(p => p.cliente_id === folderId);
  }, [progetti]);

  const openNewTask = useCallback((folderId?: string | null, listId?: string | null) => {
    setNav(prev => ({
      ...prev,
      selectedFolderId: folderId ?? prev.selectedFolderId,
      selectedListId: listId ?? prev.selectedListId,
      selectedTaskId: "new",
      view: listId ? "list" : (folderId ? "dash" : prev.view)
    }));
  }, []);

  const openSplit = useCallback((tabId: string) => {
    setNav(prev => ({ ...prev, splitTabId: tabId }));
  }, []);

  const closeSplit = useCallback(() => {
    setNav(prev => ({ ...prev, splitTabId: null }));
  }, []);

  const value = {
    nav,
    setView,
    selectFolder,
    selectList,
    selectTask,
    openNewTask,
    splitTabId: nav.splitTabId,
    openSplit,
    closeSplit,
    isLoading: isLoadingClienti || isLoadingProgetti || isLoadingHierarchy,
    hierarchy,
    tabs: nav.openTabs,
    activeTabId: nav.activeTabId,
    selectTab,
    closeTab,
    openTab,
    spaces,
    currentFolder,
    currentList,
    allProgetti: progetti,
    allClienti: clienti,
    getFolderProjects,
    folderProjects,
    timer: {
      active_session: activeSession || null,
      start: startTimer,
      stop: stopTimer,
      getElapsed: getElapsedTime
    }
  };

  return <StudioContext.Provider value={value}>{children}</StudioContext.Provider>;
}

import React, { createContext, useContext, useEffect, useState } from "react";

export type ThemeMode = "dark" | "light";
export type ThemeAccent = "violet" | "blue" | "green" | "orange" | "pink" | "slate";
export type ThemeDensity = "compact" | "normal" | "comfortable";
export type ThemeFontSize = "sm" | "md" | "lg";

interface ThemeSettings {
  mode: ThemeMode;
  accent: ThemeAccent;
  density: ThemeDensity;
  fontSize: ThemeFontSize;
}

interface ThemeContextType extends ThemeSettings {
  setMode: (mode: ThemeMode) => void;
  setAccent: (accent: ThemeAccent) => void;
  setDensity: (density: ThemeDensity) => void;
  setFontSize: (fontSize: ThemeFontSize) => void;
  isThemePanelOpen: boolean;
  setIsThemePanelOpen: (open: boolean) => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

const ACCENT_COLORS: Record<ThemeAccent, string> = {
  violet: "262.1 83.3% 57.8%", // Adjusted for consistency
  blue: "217.2 91.2% 59.8%",
  green: "158 64% 52%",
  orange: "25 95% 53%",
  pink: "330 81% 60%",
  slate: "215 25% 45%",
};

const FONT_SIZES: Record<ThemeFontSize, string> = {
  sm: "14px",
  md: "16px",
  lg: "18px",
};

const STORAGE_KEY = "bite_erp_preferences";

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [settings, setSettings] = useState<ThemeSettings>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        console.error("Failed to parse theme settings", e);
      }
    }
    return {
      mode: "dark",
      accent: "violet",
      density: "normal",
      fontSize: "md",
    };
  });

  const [isThemePanelOpen, setIsThemePanelOpen] = useState(false);

  const updateSetting = <K extends keyof ThemeSettings>(key: K, value: ThemeSettings[K]) => {
    setSettings((prev) => {
      const newSettings = { ...prev, [key]: value };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(newSettings));
      return newSettings;
    });
  };

  useEffect(() => {
    const root = document.documentElement;
    
    // Theme Mode
    if (settings.mode === "light") {
      root.classList.add("light");
    } else {
      root.classList.remove("light");
    }
    root.style.colorScheme = settings.mode;

    // Accent Color
    root.style.setProperty("--primary", ACCENT_COLORS[settings.accent]);
    root.style.setProperty("--ring", ACCENT_COLORS[settings.accent]);

    // Density
    root.setAttribute("data-density", settings.density);

    // Font Size
    root.style.fontSize = FONT_SIZES[settings.fontSize];
  }, [settings]);

  const value = {
    ...settings,
    setMode: (mode: ThemeMode) => updateSetting("mode", mode),
    setAccent: (accent: ThemeAccent) => updateSetting("accent", accent),
    setDensity: (density: ThemeDensity) => updateSetting("density", density),
    setFontSize: (fontSize: ThemeFontSize) => updateSetting("fontSize", fontSize),
    isThemePanelOpen,
    setIsThemePanelOpen,
  };

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error("useTheme must be used within a ThemeProvider");
  }
  return context;
};

import { useMutation } from "@tanstack/react-query";
import { api } from "@/lib/api";
import { toast } from "sonner";
import { useAnalytics } from "./useAnalytics";

export interface ChatMessage {
  role: "user" | "assistant";
  content: string;
  timestamp: Date;
}

export function useAI() {
  const { data: analytics } = useAnalytics();

  return useMutation({
    mutationFn: async (message: string) => {
      // Gather context before sending
      const context = {
        kpis: analytics?.kpis || {},
        alerts: (analytics?.alerts || []).slice(0, 10), // Limit alerts for token space
        topClienti: analytics?.clientStats || [],
        recentTrends: (analytics?.revenueTrend || []).slice(-6) // Last 6 months
      };

      const { data } = await api.post("/ai/chat", {
        message,
        context
      });

      return data.response as string;
    },
    onError: (err: any) => {
      toast.error(err?.response?.data?.detail ?? "Errore nella risposta AI");
    },
  });
}

