const formatError = (err: any, defaultMsg: string) => {
  const detail = err?.response?.data?.detail;
  if (typeof detail === "string") return detail;
  if (Array.isArray(detail)) {
    return detail.map(d => `${d.loc.join('.')}: ${d.msg}`).join(", ");
  }
  return defaultMsg;
};

