                    </Button>
                    <Button variant="ghost" onClick={() => setIsAddingProject(false)} className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Chiudi</Button>
                  </DialogFooter>
                </DialogContent>
              </Dialog>
              <ProgettoDialog 
