import React from "react";
import { 
  Tabs, 
  TabsContent, 
  TabsList, 
  TabsTrigger 
} from "@/components/ui/tabs";
import { 
  Card, 
  CardContent, 
  CardHeader, 
  CardTitle 
} from "@/components/ui/card";
import { 
  TrendingUp, 
  TrendingDown, 
  Clock, 
  Filter,
  Download,
  Plus
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { useFattureAttive, useFatturePassive, useDeleteFattura } from "@/hooks/useFatture";
import { FattureTable } from "@/components/finance/FattureTable";
import { Skeleton } from "@/components/ui/skeleton";
import { FatturaDetailDialog } from "@/components/finance/FatturaDetailDialog";
import { FatturaModal } from "@/components/finance/FatturaModal";
import { toast } from "sonner";
import { ImputazioneCostiDrawer } from "@/components/finance/ImputazioneCostiDrawer";

export default function Fatture() {
  const { data: attive, isLoading: loadingA } = useFattureAttive();
  const { data: passive, isLoading: loadingP } = useFatturePassive();
  const deleteFattura = useDeleteFattura();

  const [selectedFattura, setSelectedFattura] = React.useState<any>(null);
  const [detailOpen, setDetailOpen] = React.useState(false);
  const [editOpen, setEditOpen] = React.useState(false);
  const [activeTab, setActiveTab] = React.useState<"attive" | "passive">("attive");
  const [imputaFattura, setImputaFattura] = React.useState<any>(null);

  const handleAction = async (fattura: any, action: "view" | "edit" | "delete" | "imputa", type: "attive" | "passive") => {
    if (action === "imputa") {
      setImputaFattura(fattura);
      return;
    }
    switch (action) {
      case "view":
        setSelectedFattura(fattura);
        setActiveTab(type);
        setDetailOpen(true);
        break;
      case "edit":
        setSelectedFattura(fattura);
        setActiveTab(type);
        setEditOpen(true);
        break;
      case "delete":
        if (confirm(`Sei sicuro di voler eliminare la fattura ${fattura.numero}? L'operazione non può essere annullata.`)) {
          try {
            await deleteFattura.mutateAsync({ id: fattura.id, type });
            toast.success("Fattura eliminata con successo");
          } catch (e) {
            toast.error("Errore durante l'eliminazione");
          }
        }
        break;
    }
  };

  const stats = React.useMemo(() => {
    const totalA = attive?.reduce((acc, f) => acc + Number(f.importo_totale), 0) || 0;
    const unpaidA = attive?.filter(f => f.stato_pagamento.toLowerCase() === "attesa")
                           .reduce((acc, f) => acc + Number(f.importo_residuo), 0) || 0;
    const totalP = passive?.reduce((acc, f) => acc + Number(f.importo_totale), 0) || 0;

    return { totalA, unpaidA, totalP };
  }, [attive, passive]);

  if (loadingA || loadingP) {
    return (
      <div className="p-8 space-y-8 animate-in fade-in duration-500">
        <div className="flex items-center justify-between">
          <Skeleton className="h-10 w-48 rounded-xl bg-muted/20" />
          <Skeleton className="h-10 w-32 rounded-xl bg-muted/20" />
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {[1, 2, 3].map(i => <Skeleton key={i} className="h-32 rounded-3xl bg-muted/10" />)}
        </div>
        <Skeleton className="h-[400px] rounded-3xl bg-muted/5" />
      </div>
    );
  }

  return (
    <div className="p-8 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-black text-white tracking-tighter uppercase italic">
            Amministrazione <span className="text-primary not-italic">&</span> Finanza
          </h1>
          <p className="text-[#475569] text-xs font-bold uppercase tracking-[0.2em] mt-1">Gestione flussi di cassa e fatturazione</p>
        </div>
        <div className="flex items-center gap-3">
          <Button variant="outline" className="h-10 bg-card/50 border-border text-muted-foreground hover:text-white rounded-xl gap-2 font-bold uppercase text-[10px] tracking-widest">
            <Download className="h-4 w-4" />
            Esporta
          </Button>
          <Button 
            className="h-10 bg-primary hover:bg-primary/90 text-white rounded-xl gap-2 font-black uppercase text-[10px] tracking-widest shadow-[0_0_20px_hsl(var(--primary)/0.2)]"
            onClick={() => {
              setSelectedFattura(null);
              setEditOpen(true);
            }}
          >
            <Plus className="h-4 w-4" />
            Nuova Fattura
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <Card className="bg-card/40 border-border/50 rounded-3xl overflow-hidden relative group">
          <div className="absolute top-0 left-0 w-full h-[2px] bg-gradient-to-r from-emerald-500/50 to-transparent" />
          <CardHeader className="pb-2">
            <CardTitle className="text-[10px] font-black uppercase tracking-[0.2em] text-[#475569] flex items-center gap-2">
              <TrendingUp className="h-3.5 w-3.5 text-emerald-500" />
              Fatturato Attivo
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-black text-white tabular-nums tracking-tighter">
              {new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(stats.totalA)}
            </div>
            <p className="text-[10px] font-bold text-emerald-500 uppercase mt-1">+12% rispetto al mese scorso</p>
          </CardContent>
        </Card>

        <Card className="bg-card/40 border-border/50 rounded-3xl overflow-hidden relative group">
          <div className="absolute top-0 left-0 w-full h-[2px] bg-gradient-to-r from-amber-500/50 to-transparent" />
          <CardHeader className="pb-2">
            <CardTitle className="text-[10px] font-black uppercase tracking-[0.2em] text-[#475569] flex items-center gap-2">
              <Clock className="h-3.5 w-3.5 text-amber-500" />
              Da Incassare
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-black text-white tabular-nums tracking-tighter">
              {new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(stats.unpaidA)}
            </div>
            <p className="text-[10px] font-bold text-[#475569] uppercase mt-1">{attive?.filter(f => f.stato_pagamento.toLowerCase() === 'attesa').length || 0} fatture in attesa</p>
          </CardContent>
        </Card>

        <Card className="bg-card/40 border-border/50 rounded-3xl overflow-hidden relative group">
          <div className="absolute top-0 left-0 w-full h-[2px] bg-gradient-to-r from-red-500/50 to-transparent" />
          <CardHeader className="pb-2">
            <CardTitle className="text-[10px] font-black uppercase tracking-[0.2em] text-[#475569] flex items-center gap-2">
              <TrendingDown className="h-3.5 w-3.5 text-red-500" />
              Fatture Passive
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-black text-white tabular-nums tracking-tighter">
              {new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(stats.totalP)}
            </div>
            <p className="text-[10px] font-bold text-red-500 uppercase mt-1">Costi operativi correnti</p>
          </CardContent>
        </Card>
      </div>

      <Card className="bg-background/50 border-border/50 rounded-3xl overflow-hidden shadow-2xl">
        <Tabs defaultValue="attive" className="w-full">
          <div className="px-8 pt-6 pb-2 border-b border-border/50 bg-card/30 flex flex-col md:flex-row md:items-center justify-between gap-4">
            <TabsList className="bg-background/80 border border-border/50 p-1 h-11 rounded-xl">
              <TabsTrigger 
                value="attive" 
                className="rounded-lg px-6 data-[state=active]:bg-primary data-[state=active]:text-white text-[10px] font-black uppercase tracking-widest transition-all duration-300"
              >
                Fatture Attive
              </TabsTrigger>
              <TabsTrigger 
                value="passive" 
                className="rounded-lg px-6 data-[state=active]:bg-primary data-[state=active]:text-white text-[10px] font-black uppercase tracking-widest transition-all duration-300"
              >
                Fatture Passive
              </TabsTrigger>
            </TabsList>
            
            <div className="flex items-center gap-2">
              <Button variant="ghost" size="sm" className="text-[10px] font-black uppercase tracking-widest text-[#475569] hover:text-white gap-2">
                <Filter className="h-3.5 w-3.5" />
                Filtra per Mese
              </Button>
            </div>
          </div>

          <CardContent className="p-0">
            <TabsContent value="attive" className="m-0 focus-visible:ring-0">
              <FattureTable data={attive || []} type="attive" onAction={(f, a) => handleAction(f, a, "attive")} />
            </TabsContent>
            <TabsContent value="passive" className="m-0 focus-visible:ring-0">
              <FattureTable data={passive || []} type="passive" onAction={(f, a) => handleAction(f, a, "passive")} />
            </TabsContent>
          </CardContent>
        </Tabs>
      </Card>

      <FatturaDetailDialog 
        fattura={selectedFattura}
        open={detailOpen}
        onOpenChange={setDetailOpen}
        type={activeTab}
      />
      <FatturaModal
        open={editOpen}
        onOpenChange={setEditOpen}
        type={activeTab}
        fattura={selectedFattura}
      />
      {imputaFattura && (
        <ImputazioneCostiDrawer
          open={!!imputaFattura}
          onClose={() => setImputaFattura(null)}
          sourceType="fattura_passiva"
          sourceId={imputaFattura.id}
          importoTotale={Number(imputaFattura.importo_totale)}
          sourceLabel={`Fattura ${imputaFattura.numero ?? ""} — ${imputaFattura.fornitore_nome ?? ""}`}
        />
      )}
    </div>
  );
}

import React, { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from "@/components/ui/card";
import { Mail, ArrowLeft, Loader2, CheckCircle2, AlertCircle } from "lucide-react";
import { Link } from "react-router-dom";
import api from "@/lib/api";

export default function ForgotPasswordPage() {
  const [email, setEmail] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    try {
      await api.post("/auth/forgot-password", { email });
      setIsSuccess(true);
    } catch (err: any) {
      setError(err.response?.data?.detail || "Errore durante l'invio dell'email. Riprova più tardi.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-background p-4 relative overflow-hidden">
      {/* Background decoration */}
      <div className="absolute top-[20%] left-[20%] w-[30%] h-[30%] rounded-full bg-primary/10 blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[20%] right-[20%] w-[30%] h-[30%] rounded-full bg-primary/10 blur-[100px] pointer-events-none" />

      <Card className="w-full max-w-md bg-card/50 backdrop-blur-xl border-border/50 shadow-2xl relative animate-in fade-in zoom-in duration-500">
        <CardHeader className="space-y-2 text-center pb-8">
          <div className="mx-auto mb-6 relative group">
            <div className="absolute -inset-4 bg-primary/10 rounded-full blur-3xl opacity-50 group-hover:opacity-100 transition duration-1000" />
            <img 
              src="/logo_bite.jpg" 
              alt="Bite Digital" 
              className="relative max-w-[200px] h-auto mx-auto drop-shadow-[0_10px_20px_rgba(0,0,0,0.5)] group-hover:scale-105 transition-transform duration-700" 
            />
          </div>
          <CardTitle className="text-3xl font-bold tracking-tight">Recupero Password</CardTitle>
          <CardDescription className="text-muted-foreground">
            Inserisci la tua email per ricevere un link di reset.
          </CardDescription>
        </CardHeader>

        {!isSuccess ? (
          <form onSubmit={handleSubmit}>
            <CardContent className="space-y-4">
              {error && (
                <div className="p-3 rounded-lg bg-destructive/10 border border-destructive/20 flex items-center space-x-3 text-destructive animate-in slide-in-from-bottom-2">
                  <AlertCircle className="w-4 h-4 shrink-0" />
                  <p className="text-xs font-medium">{error}</p>
                </div>
              )}
              <div className="space-y-2">
                <div className="relative">
                  <Mail className="absolute left-3 top-3 w-4 h-4 text-muted-foreground" />
                  <Input
                    type="email"
                    placeholder="Email aziendale"
                    className="pl-10 bg-background/50"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    required
                  />
                </div>
              </div>
            </CardContent>
            <CardFooter className="pt-4 flex flex-col space-y-4">
              <Button 
                type="submit" 
                className="w-full shadow-lg shadow-[0_0_20px_hsl(var(--primary)/0.2)]" 
                disabled={isLoading}
              >
                {isLoading ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Invio in corso...
                  </>
                ) : (
                  "Invia link di reset"
                )}
              </Button>
              <Link 
                to="/login" 
                className="flex items-center justify-center gap-2 text-xs text-muted-foreground hover:text-foreground transition-colors"
              >
                <ArrowLeft className="w-3 h-3" />
                Torna al login
              </Link>
            </CardFooter>
          </form>
        ) : (
          <CardContent className="space-y-6 pb-8 text-center animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="mx-auto w-16 h-16 bg-green-500/10 rounded-full flex items-center justify-center text-green-500 mb-4">
              <CheckCircle2 className="w-10 h-10" />
            </div>
            <div className="space-y-2">
              <p className="text-lg font-bold text-foreground">Email inviata!</p>
              <p className="text-sm text-muted-foreground">
                Se l'indirizzo <b>{email}</b> è nel nostro sistema, riceverai a breve un link per reimpostare la tua password.
              </p>
            </div>
            <Button asChild variant="outline" className="w-full mt-4">
              <Link to="/login">Torna al login</Link>
            </Button>
          </CardContent>
        )}
      </Card>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import api from "@/lib/api";
import type { Fornitore, CategoriaFornitore } from "@/types";
import { 
  Phone, Mail, Tag, Filter, MoreHorizontal,
  Building, FileText, Plus, Search, Edit2, Trash2
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { 
  Table, TableBody, TableCell, TableHead, 
  TableHeader, TableRow 
} from "@/components/ui/table";
import {
  Dialog, DialogContent, DialogHeader,
  DialogTitle, DialogDescription, DialogFooter
} from "@/components/ui/dialog";
import {
  DropdownMenu, DropdownMenuContent,
  DropdownMenuItem, DropdownMenuTrigger,
  DropdownMenuSeparator
} from "@/components/ui/dropdown-menu";
import { Label } from "@/components/ui/label";
import { 
  Select, SelectContent, SelectItem, 
  SelectTrigger, SelectValue 
} from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";
import { useNavigate } from "react-router-dom";

export default function Fornitori() {
  const queryClient = useQueryClient();
  const navigate = useNavigate();
  const [search, setSearch] = useState("");
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedFornitore, setSelectedFornitore] = useState<Partial<Fornitore> | null>(null);

  // Queries
  const { data: fornitori = [], isLoading } = useQuery<Fornitore[]>({
    queryKey: ["fornitori"],
    queryFn: async () => {
      const { data } = await api.get("/fornitori-full");
      return data;
    },
  });

  const { data: categorie = [] } = useQuery<CategoriaFornitore[]>({
    queryKey: ["categorie-fornitori"],
    queryFn: async () => {
      const { data } = await api.get("/categorie-fornitori");
      return data;
    },
  });

  // Mutations
  const upsertMutation = useMutation({
    mutationFn: async (data: Partial<Fornitore>) => {
      if (data.id) {
        return api.patch(`/fornitori/${data.id}`, data);
      }
      return api.post("/fornitori", data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["fornitori"] });
      setIsModalOpen(false);
      toast.success(selectedFornitore?.id ? "Fornitore aggiornato" : "Fornitore creato");
    },
    onError: () => {
      toast.error("Errore durante il salvataggio");
    }
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      return api.delete(`/fornitori/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["fornitori"] });
      toast.success("Fornitore eliminato");
    },
    onError: (err: any) => {
      toast.error(err.response?.data?.detail || "Errore durante l'eliminazione");
    }
  });

  const filteredFornitori = fornitori.filter(f => 
    f.ragione_sociale.toLowerCase().includes(search.toLowerCase()) ||
    f.piva?.includes(search) ||
    f.email?.toLowerCase().includes(search.toLowerCase())
  );

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedFornitore) {
      upsertMutation.mutate(selectedFornitore);
    }
  };

  const openEdit = (f: Fornitore) => {
    setSelectedFornitore(f);
    setIsModalOpen(true);
  };

  const openCreate = () => {
    setSelectedFornitore({ ragione_sociale: "", attivo: true });
    setIsModalOpen(true);
  };

  return (
    <div className="p-6 space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight bg-gradient-to-r from-white to-gray-400 bg-clip-text text-transparent">
            Fornitori
          </h1>
          <p className="text-muted-foreground mt-1 text-sm">
            Gestisci l'elenco dei fornitori e le loro categorie.
          </p>
        </div>
        <div className="flex items-center gap-3">
          <Button variant="outline" size="sm" onClick={() => navigate("/admin/categorie-fornitori")}>
            <Tag className="w-4 h-4 mr-2" />
            Gestione Categorie
          </Button>
          <Button onClick={openCreate} className="bg-primary hover:bg-primary/90 shadow-lg shadow-[0_0_20px_hsl(var(--primary)/0.2)]">
            <Plus className="w-4 h-4 mr-2" />
            Nuovo Fornitore
          </Button>
        </div>
      </div>

      <div className="flex items-center gap-4 bg-card/50 p-4 rounded-xl border border-white/5 backdrop-blur-sm">
        <div className="relative flex-1 max-w-sm">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
          <Input 
            placeholder="Cerca fornitore, P.IVA o email..." 
            className="pl-9 bg-background/50 border-white/10"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <Button variant="ghost" size="icon" className="text-muted-foreground">
          <Filter className="w-4 h-4" />
        </Button>
      </div>

      <div className="rounded-xl border border-white/5 bg-card/30 overflow-hidden backdrop-blur-md">
        <Table>
          <TableHeader className="bg-white/5">
            <TableRow>
              <TableHead>Nome Fornitore</TableHead>
              <TableHead>Categoria</TableHead>
              <TableHead>Contatti</TableHead>
              <TableHead>Stato</TableHead>
              <TableHead className="text-right">Spesa Totale</TableHead>
              <TableHead className="w-[80px]"></TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {isLoading ? (
              Array.from({ length: 5 }).map((_, i) => (
                <TableRow key={i}>
                  <TableCell colSpan={6}>
                    <div className="h-12 w-full animate-pulse bg-white/5 rounded" />
                  </TableCell>
                </TableRow>
              ))
            ) : filteredFornitori.length === 0 ? (
              <TableRow>
                <TableCell colSpan={6} className="h-32 text-center text-muted-foreground">
                  Nessun fornitore trovato.
                </TableCell>
              </TableRow>
            ) : (
              filteredFornitori.map((f) => (
                <TableRow key={f.id} className="group hover:bg-white/5 transition-colors">
                  <TableCell>
                    <div className="flex flex-col">
                      <span className="font-medium">{f.ragione_sociale}</span>
                      <span className="text-[10px] text-muted-foreground uppercase tracking-wider">{f.piva || "P.IVA non inserita"}</span>
                    </div>
                  </TableCell>
                  <TableCell>
                    {f.categoria_rel ? (
                      <Badge 
                        variant="outline" 
                        className="font-normal border-opacity-50"
                        style={{ 
                          backgroundColor: `${f.categoria_rel.colore}15`, 
                          borderColor: `${f.categoria_rel.colore}50`,
                          color: f.categoria_rel.colore
                        }}
                      >
                        {f.categoria_rel.nome}
                      </Badge>
                    ) : (
                      <span className="text-muted-foreground text-xs">{f.categoria || "-"}</span>
                    )}
                  </TableCell>
                  <TableCell>
                    <div className="flex flex-col gap-1">
                      {f.email && (
                        <div className="flex items-center text-xs text-muted-foreground">
                          <Mail className="w-3 h-3 mr-1.5 opacity-50" />
                          {f.email}
                        </div>
                      )}
                      {f.telefono && (
                        <div className="flex items-center text-xs text-muted-foreground">
                          <Phone className="w-3 h-3 mr-1.5 opacity-50" />
                          {f.telefono}
                        </div>
                      )}
                    </div>
                  </TableCell>
                  <TableCell>
                    {f.attivo ? (
                      <Badge variant="outline" className="bg-emerald-500/10 text-emerald-500 border-emerald-500/20 font-normal">
                        Attivo
                      </Badge>
                    ) : (
                      <Badge variant="outline" className="bg-gray-500/10 text-gray-500 border-gray-500/20 font-normal">
                        Inattivo
                      </Badge>
                    )}
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex flex-col items-end">
                      <span className="font-semibold text-sm">€{(f.spesa_totale || 0).toLocaleString("it-IT", { minimumFractionDigits: 2 })}</span>
                      <span className="text-[10px] text-muted-foreground">{f.num_fatture} fatture</span>
                    </div>
                  </TableCell>
                  <TableCell>
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button variant="ghost" size="icon" className="opacity-0 group-hover:opacity-100 transition-opacity">
                          <MoreHorizontal className="w-4 h-4" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end" className="w-48">
                        <DropdownMenuItem onClick={() => openEdit(f)}>
                          <Edit2 className="w-4 h-4 mr-2" /> Modifica
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => navigate(`/finanza/fatture?fornitore=${f.id}`)}>
                          <FileText className="w-4 h-4 mr-2" /> Vedi Fatture
                        </DropdownMenuItem>
                        <DropdownMenuSeparator />
                        <DropdownMenuItem 
                          className="text-destructive focus:text-destructive"
                          onClick={() => {
                            if (confirm("Eliminare definitivamente questo fornitore?")) {
                              deleteMutation.mutate(f.id);
                            }
                          }}
                        >
                          <Trash2 className="w-4 h-4 mr-2" /> Elimina
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>

      {/* Modal CRUD */}
      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent className="sm:max-w-[500px] border-white/10 bg-card backdrop-blur-xl">
          <DialogHeader>
            <DialogTitle>
              {selectedFornitore?.id ? "Modifica Fornitore" : "Nuovo Fornitore"}
            </DialogTitle>
            <DialogDescription>
              Inserisci i dati principali del fornitore.
            </DialogDescription>
          </DialogHeader>
          <form onSubmit={handleSubmit} className="space-y-4 py-4">
            <div className="grid gap-4">
              <div className="space-y-2">
                <Label>Ragione Sociale <span className="text-destructive">*</span></Label>
                <div className="relative">
                  <Building className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                  <Input 
                    value={selectedFornitore?.ragione_sociale || ""}
                    onChange={(e) => setSelectedFornitore(prev => ({ ...prev!, ragione_sociale: e.target.value }))}
                    className="pl-10"
                    placeholder="Nome azienda o professionista"
                    required
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>P.IVA / CF</Label>
                  <Input 
                    value={selectedFornitore?.piva || ""}
                    onChange={(e) => setSelectedFornitore(prev => ({ ...prev!, piva: e.target.value }))}
                    placeholder="IT01234567890"
                  />
                </div>
                <div className="space-y-2">
                  <Label>Categoria</Label>
                  <Select 
                    value={selectedFornitore?.categoria_id || "none"}
                    onValueChange={(val) => setSelectedFornitore(prev => ({ ...prev!, categoria_id: val === "none" ? undefined : val }))}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Seleziona..." />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="none">Senza categoria</SelectItem>
                      {categorie.map(c => (
                        <SelectItem key={c.id} value={c.id}>
                          <div className="flex items-center">
                            <div className="w-2 h-2 rounded-full mr-2" style={{ backgroundColor: c.colore }} />
                            {c.nome}
                          </div>
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Email</Label>
                  <div className="relative">
                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                    <Input 
                      type="email"
                      value={selectedFornitore?.email || ""}
                      onChange={(e) => setSelectedFornitore(prev => ({ ...prev!, email: e.target.value }))}
                      className="pl-10"
                      placeholder="info@fornitore.com"
                    />
                  </div>
                </div>
                <div className="space-y-2">
                  <Label>Telefono</Label>
                  <div className="relative">
                    <Phone className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                    <Input 
                      value={selectedFornitore?.telefono || ""}
                      onChange={(e) => setSelectedFornitore(prev => ({ ...prev!, telefono: e.target.value }))}
                      className="pl-10"
                      placeholder="+39 012 345678"
                    />
                  </div>
                </div>
              </div>

              <div className="space-y-2">
                <Label>Note</Label>
                <Input 
                  value={selectedFornitore?.note || ""}
                  onChange={(e) => setSelectedFornitore(prev => ({ ...prev!, note: e.target.value }))}
                  placeholder="Eventuali note interne..."
                />
              </div>
            </div>

            <DialogFooter className="pt-4 gap-2">
              <Button type="button" variant="ghost" onClick={() => setIsModalOpen(false)}>Annulla</Button>
              <Button type="submit" disabled={upsertMutation.isPending}>
                {upsertMutation.isPending ? "Salvataggio..." : (selectedFornitore?.id ? "Salva Modifiche" : "Crea Fornitore")}
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { 
  ChevronLeft, 
  User as UserIcon, 
  Clock,
  Euro,
  FileText,
  ExternalLink,
  MessageSquare,
  Building2,
  CheckCircle2,
  ArrowRightLeft,
  Zap
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useCRM } from "@/hooks/useCRM";
import { format } from "date-fns";
import { toast } from "sonner";

export default function LeadDetailPage() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { leads, stages, updateLead, addActivity, convertLeadToClient, deleteLead } = useCRM();
  
  const lead = leads.find(l => l.id === id);
  const [activeTab, setActiveTab] = useState("timeline");
  const [newActivity, setNewActivity] = useState("");
  const [emailSubject, setEmailSubject] = useState("");
  const [emailBody, setEmailBody] = useState("");
  const [isSending, setIsSending] = useState(false);

  // Edit State
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState<any>(null);

  if (!lead) {
    return (
      <div className="p-8 text-center h-screen flex flex-col items-center justify-center">
        <h2 className="text-xl text-white font-black uppercase italic tracking-tighter mb-4">Lead non trovato</h2>
        <Button onClick={() => navigate("/crm")} variant="link" className="text-primary font-black uppercase tracking-widest text-[10px]">
          Torna alla Pipeline
        </Button>
      </div>
    );
  }

  // HubSpot-style Lead Score Calculation (Mocked for UI)
  const leadScore = lead.lead_score ?? 78;

  const handleStartEdit = () => {
    setFormData({
      nome_azienda: lead.nome_azienda,
      nome_contatto: lead.nome_contatto || "",
      email: lead.email || "",
      telefono: lead.telefono || "",
      sito_web: lead.sito_web || "",
      valore_stimato: lead.valore_stimato,
      settore: lead.settore || "",
      dimensione_azienda: lead.dimensione_azienda || "",
      fonte: lead.fonte || ""
    });
    setIsEditing(true);
  };

  const handleSave = async () => {
    try {
      await updateLead.mutateAsync({ id: lead.id, data: formData });
      setIsEditing(false);
      toast.success("Lead aggiornato con successo");
    } catch (e) {
      toast.error("Errore durante il salvataggio");
    }
  };

  const handleCancelEdit = () => {
    setIsEditing(false);
    setFormData(null);
  };

  const handleSendEmail = async () => {
    if (!emailSubject || !emailBody) {
      toast.error("Oggetto e corpo della mail sono obbligatori");
      return;
    }
    
    setIsSending(true);
    try {
      // Simulate backend delay
      await new Promise(r => setTimeout(r, 1500));
      
      await addActivity.mutateAsync({ 
        lead_id: lead.id, 
        data: { 
          note: `EMAIL INVIATA\nOggetto: ${emailSubject}\n\n${emailBody}`,
          tipo: "EMAIL"
        } 
      });
      
      toast.success("Email inviata e loggata con successo!");
      setEmailSubject("");
      setEmailBody("");
      setActiveTab("timeline");
    } catch (e) {
      toast.error("Errore durante l'invio");
    } finally {
      setIsSending(false);
    }
  };

  const handleAddActivity = async (tipo: string = "NOTA") => {
    if (!newActivity) return;
    try {
      await addActivity.mutateAsync({ 
        lead_id: lead.id, 
        data: { 
          note: newActivity,
          tipo: tipo
        } 
      });
      setNewActivity("");
    } catch (e) {
      toast.error("Errore salvataggio attività");
    }
  };

  const handleDelete = async () => {
    if (confirm(`Sei sicuro di voler eliminare il lead ${lead.nome_azienda}?`)) {
      try {
        await deleteLead.mutateAsync(lead.id);
        navigate("/crm");
      } catch (e) {
        toast.error("Errore durante l'eliminazione");
      }
    }
  };

  return (
    <div className="p-8 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700 h-screen flex flex-col overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between shrink-0">
        <div className="flex items-center gap-4">
          <Button 
            variant="ghost" 
            onClick={() => navigate("/crm")} 
            className="text-muted-foreground hover:text-white hover:bg-muted rounded-xl"
          >
            <ChevronLeft className="w-4 h-4 mr-2" />
            CRM Pipeline
          </Button>
          <div className="h-4 w-px bg-muted" />
          <div className="flex items-center gap-4">
            <div className="h-14 w-14 rounded-2xl bg-primary/10 flex items-center justify-center border border-primary/20 shadow-xl shadow-primary/10">
              <Building2 className="w-7 h-7 text-primary" />
            </div>
            <div>
              {isEditing ? (
                <input 
                  className="bg-white/5 border border-white/10 rounded-lg px-3 py-1 text-2xl font-black text-white focus:ring-1 focus:ring-primary outline-none"
                  value={formData.nome_azienda}
                  onChange={(e) => setFormData({ ...formData, nome_azienda: e.target.value })}
                />
              ) : (
                <h1 className="text-3xl font-black text-white tracking-tighter uppercase italic leading-none">{lead.nome_azienda}</h1>
              )}
              <div className="flex items-center gap-3 mt-1.5">
                <Badge variant="outline" className="bg-white/5 border-white/5 text-[9px] font-black uppercase text-[#64748b]">
                  {lead.fonte || 'Lead Direct'}
                </Badge>
                <div className="flex items-center gap-1.5">
                   <div className="h-1.5 w-1.5 rounded-full" style={{ backgroundColor: lead.stadio?.colore }} />
                   <span className="text-[10px] font-black uppercase text-[#475569] tracking-widest">{lead.stadio?.nome}</span>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-6">
           <div className="flex flex-col items-center">
              <div className="relative h-14 w-14">
                <svg className="h-14 w-14 -rotate-90">
                  <circle cx="28" cy="28" r="24" className="fill-none stroke-white/5 stroke-[4]" />
                  <circle 
                    cx="28" cy="28" r="24" 
                    className="fill-none stroke-primary stroke-[4] transition-all duration-1000"
                    strokeDasharray={150.7}
                    strokeDashoffset={150.7 * (1 - leadScore / 100)}
                    strokeLinecap="round"
                  />
                </svg>
                <div className="absolute inset-0 flex items-center justify-center text-[11px] font-black text-white">
                  {leadScore}
                </div>
              </div>
              <span className="text-[8px] font-black uppercase text-primary tracking-widest mt-1">Lead Score</span>
           </div>

           <div className="flex items-center gap-3">
              {isEditing ? (
                <>
                  <Button variant="ghost" onClick={handleCancelEdit} className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Annulla</Button>
                  <Button onClick={handleSave} className="bg-emerald-500 hover:bg-emerald-600 text-white h-12 px-8 rounded-2xl font-black uppercase tracking-widest text-[10px]">Salva Dati</Button>
                </>
              ) : (
                <>
                  <Button 
                    variant="outline" 
                    className="h-12 px-6 rounded-2xl bg-white/5 border-white/10 text-white font-black uppercase tracking-widest text-[10px] hover:bg-white/10"
                    onClick={handleStartEdit}
                  >
                    Modifica
                  </Button>
                  <Button 
                    variant="outline" 
                    className="h-12 px-6 rounded-2xl bg-white/5 border-white/10 text-white font-black uppercase tracking-widest text-[10px] hover:bg-white/10"
                    onClick={() => convertLeadToClient.mutate(lead.id)}
                  >
                    <ArrowRightLeft className="w-4 h-4 mr-2 text-emerald-400" />
                    Converti
                  </Button>
                  <Button 
                    onClick={() => navigate("/planning")}
                    className="h-12 px-8 bg-primary text-white rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-lg shadow-primary/20"
                  >
                    Pianifica Task
                  </Button>
                </>
              )}
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 flex-1 overflow-hidden">
        {/* Left Sidebar Info */}
        <div className="space-y-6 overflow-y-auto pr-2 scrollbar-none">
           <Card className="bg-card/40 border-white/5 rounded-[32px] overflow-hidden backdrop-blur-xl">
              <CardHeader className="pb-2">
                 <CardTitle className="text-[10px] font-black uppercase tracking-[0.2em] text-[#475569]">Info Generale</CardTitle>
              </CardHeader>
              <CardContent className="space-y-5">
                 <SidebarEditableItem 
                    label="Contatto" 
                    value={lead.nome_contatto || 'N/D'} 
                    isEditing={isEditing}
                    editValue={formData?.nome_contatto}
                    onChange={(v: string) => setFormData({ ...formData, nome_contatto: v })}
                    icon={<UserIcon className="w-3 h-3 text-primary" />} 
                 />
                 <SidebarEditableItem 
                    label="Email" 
                    value={lead.email || 'N/D'} 
                    isEditing={isEditing}
                    editValue={formData?.email}
                    onChange={(v: string) => setFormData({ ...formData, email: v })}
                    icon={<MessageSquare className="w-3 h-3 text-emerald-400" />} 
                 />
                 <SidebarEditableItem 
                    label="Sito Web" 
                    value={lead.sito_web || 'www...'} 
                    isEditing={isEditing}
                    editValue={formData?.sito_web}
                    onChange={(v: string) => setFormData({ ...formData, sito_web: v })}
                    icon={<ExternalLink className="w-3 h-3 text-blue-400" />} 
                    isLink 
                 />
                 <SidebarEditableItem 
                    label="Valore" 
                    value={`€${Number(lead.valore_stimato).toLocaleString()}`} 
                    isEditing={isEditing}
                    editValue={formData?.valore_stimato}
                    onChange={(v: string) => setFormData({ ...formData, valore_stimato: Number(v) })}
                    icon={<Euro className="w-3 h-3 text-amber-400" />} 
                    type="number"
                 />
              </CardContent>
           </Card>

           <Card className="bg-card/40 border-white/5 rounded-[32px] overflow-hidden backdrop-blur-xl">
              <CardHeader className="pb-2">
                 <CardTitle className="text-[10px] font-black uppercase tracking-[0.2em] text-[#475569]">Proprietà HubSpot</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                 <EditableInfoItem 
                    label="Settore" 
                    value={lead.settore || 'Tech & Digital'} 
                    isEditing={isEditing}
                    editValue={formData?.settore}
                    onChange={(v: string) => setFormData({ ...formData, settore: v })}
                 />
                 <EditableInfoItem 
                    label="Team Size" 
                    value={lead.dimensione_azienda || '11-50'} 
                    isEditing={isEditing}
                    editValue={formData?.dimensione_azienda}
                    onChange={(v: string) => setFormData({ ...formData, dimensione_azienda: v })}
                 />
                 <EditableInfoItem 
                    label="Fonte" 
                    value={lead.fonte || 'Direct'} 
                    isEditing={isEditing}
                    editValue={formData?.fonte}
                    onChange={(v: string) => setFormData({ ...formData, fonte: v })}
                 />
              </CardContent>
           </Card>

           <Card className="bg-primary/5 border-primary/20 rounded-[32px] overflow-hidden backdrop-blur-xl border-dashed">
              <CardHeader className="pb-2">
                 <CardTitle className="text-[10px] font-black uppercase tracking-[0.2em] text-primary">Prossima Mossa Suggerita</CardTitle>
              </CardHeader>
              <CardContent>
                 <div className="flex items-start gap-4">
                    <div className="h-10 w-10 rounded-2xl bg-primary flex items-center justify-center shrink-0 shadow-lg shadow-primary/20 animate-pulse">
                       <Zap className="w-5 h-5 text-white" />
                    </div>
                    <div>
                       <p className="text-[11px] font-black text-white leading-tight uppercase tracking-tight">
                          {leadScore > 70 ? 'Invia Proposta Economica' : leadScore > 40 ? 'Pianifica Discovery Call' : 'Continua il Nurturing'}
                       </p>
                       <p className="text-[9px] text-primary/60 font-medium mt-1 uppercase tracking-widest leading-none">
                          Basato su AI & Lead Score
                       </p>
                    </div>
                 </div>
              </CardContent>
           </Card>
        </div>

        {/* Center Main Section */}
        <div className="lg:col-span-2 flex flex-col gap-6 overflow-hidden">
          <Tabs value={activeTab} onValueChange={setActiveTab} className="bg-card/40 border border-white/5 rounded-[32px] overflow-hidden backdrop-blur-xl flex-1 flex flex-col">
            <TabsList className="bg-white/5 p-2 h-16 border-b border-white/5 gap-2 flex justify-start shrink-0">
               <TabsTrigger value="timeline" className="data-[state=active]:bg-primary rounded-2xl px-6 font-black uppercase tracking-widest text-[9px] gap-2">
                  <Clock className="w-3 h-3" /> Timeline
