          </div>
          <div className="flex items-center gap-2">
            <Button variant="outline" size="sm" className="h-10 rounded-xl text-muted-foreground border-border hover:bg-muted">
              <Filter className="w-4 h-4 mr-2" /> Filtri Avanzati
            </Button>
          </div>
        </div>

        {isLoading ? (
          <div className="h-64 flex flex-col items-center justify-center gap-3 text-muted-foreground">
            <Loader2 className="w-10 h-10 animate-spin text-primary" />
            <span className="font-medium">Caricamento preventivi...</span>
          </div>
        ) : (
          <PreventiviTable 
            data={filteredData}
            onEdit={handleEdit}
            onDelete={handleDelete}
            onStatusChange={handleStatusChange}
            onConvert={handleConvert}
          />
        )}
      </div>

      <PreventivoModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)}
        preventivo={selectedPreventivo}
      />
    </div>
  );
};

export default PreventiviPage;

import { useState } from "react";
import {
  Plus, Trash2, Edit2, Play, Eye, ArrowUp, ArrowDown,
  ShieldCheck, Zap, ToggleLeft, ToggleRight, MoreHorizontal
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Switch } from "@/components/ui/switch";
import {
  Table, TableBody, TableCell, TableHead,
  TableHeader, TableRow,
} from "@/components/ui/table";
import {
  Dialog, DialogContent, DialogHeader,
  DialogTitle, DialogFooter,
} from "@/components/ui/dialog";
import {
  Sheet, SheetContent, SheetHeader, SheetTitle,
} from "@/components/ui/sheet";
import {
  Select, SelectContent, SelectItem,
  SelectTrigger, SelectValue,
} from "@/components/ui/select";
import {
  DropdownMenu, DropdownMenuContent,
  DropdownMenuItem, DropdownMenuTrigger,
  DropdownMenuSeparator,
} from "@/components/ui/dropdown-menu";
import { toast } from "sonner";
import {
  useRegoleRiconciliazione, useCreateRegola, useUpdateRegola,
  useDeleteRegola, useApplicaRegole, useDryRunRegole,
  type RegolaRiconciliazione, type DryRunPreviewItem,
} from "@/hooks/useRegoleRiconciliazione";
import { useFornitori } from "@/hooks/useFornitori";

const EMPTY_REGOLA: Omit<RegolaRiconciliazione, "id" | "contatore_match"> = {
  nome: "",
  pattern: "",
  tipo_match: "contains",
  categoria: "",
  fornitore_id: undefined,
  fattura_passiva_id: undefined,
  auto_riconcilia: false,
  priorita: 0,
  attiva: true,
};

const CATEGORIE_PREDEFINITE = [
  "HOSTING", "ADVERTISING", "FREELANCER", "SALARI", "SOFTWARE",
  "FORMAZIONE", "UTENZE", "AFFITTO", "ALTRO",
];

export default function RegoleRiconciliazione() {
  const { data: regole = [], isLoading } = useRegoleRiconciliazione();
  const { data: fornitori = [] } = useFornitori();
  const createMut = useCreateRegola();
  const updateMut = useUpdateRegola();
  const deleteMut = useDeleteRegola();
  const applicaMut = useApplicaRegole();
  const dryRunMut = useDryRunRegole();

  const [dialogOpen, setDialogOpen] = useState(false);
  const [editTarget, setEditTarget] = useState<RegolaRiconciliazione | null>(null);
  const [form, setForm] = useState(EMPTY_REGOLA);
  const [dryRunSheet, setDryRunSheet] = useState(false);
  const [dryRunData, setDryRunData] = useState<DryRunPreviewItem[]>([]);

  function openCreate() {
    setEditTarget(null);
    setForm(EMPTY_REGOLA);
    setDialogOpen(true);
  }

  function openEdit(r: RegolaRiconciliazione) {
    setEditTarget(r);
    setForm({
      nome: r.nome,
      pattern: r.pattern,
      tipo_match: r.tipo_match,
      categoria: r.categoria ?? "",
      fornitore_id: r.fornitore_id,
      fattura_passiva_id: r.fattura_passiva_id,
      auto_riconcilia: r.auto_riconcilia,
      priorita: r.priorita,
      attiva: r.attiva,
    });
    setDialogOpen(true);
  }

  async function handleSave() {
    if (!form.nome || !form.pattern) {
      toast.error("Nome e Pattern sono obbligatori");
      return;
    }
    try {
      if (editTarget) {
        await updateMut.mutateAsync({ id: editTarget.id, ...form });
        toast.success("Regola aggiornata");
      } else {
        await createMut.mutateAsync(form as any);
        toast.success("Regola creata");
      }
      setDialogOpen(false);
    } catch {
      toast.error("Errore durante il salvataggio");
    }
  }

  async function handleDelete(id: string) {
    try {
      await deleteMut.mutateAsync(id);
      toast.success("Regola eliminata");
    } catch {
      toast.error("Errore durante l'eliminazione");
    }
  }

  async function handleApplica() {
    try {
      const res = await applicaMut.mutateAsync();
      toast.success(`${res.match_trovati} movimenti riconciliati su ${res.movimenti_processati}`);
    } catch {
      toast.error("Errore durante l'applicazione");
    }
  }

  async function handleDryRun() {
    try {
      const res = await dryRunMut.mutateAsync();
      setDryRunData(res.preview);
      setDryRunSheet(true);
      if (res.match_previsti === 0) {
        toast.info("Nessun movimento matcha le regole attive");
      }
    } catch {
      toast.error("Errore durante la simulazione");
    }
  }

  async function toggleAttiva(r: RegolaRiconciliazione) {
    await updateMut.mutateAsync({ id: r.id, attiva: !r.attiva });
    toast.success(r.attiva ? "Regola disattivata" : "Regola attivata");
  }

  const sortedRegole = [...regole].sort((a, b) => b.priorita - a.priorita);

  return (
    <div className="space-y-6 p-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-black tracking-tight text-foreground flex items-center gap-2">
            <ShieldCheck className="h-6 w-6 text-primary" />
            Regole Riconciliazione
          </h1>
          <p className="text-sm text-muted-foreground mt-1">
            Automatizza il matching tra movimenti bancari e fatture
          </p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={handleDryRun} disabled={dryRunMut.isPending}>
            <Eye className="h-4 w-4 mr-1.5" />
            {dryRunMut.isPending ? "Simulando..." : "Simula"}
          </Button>
          <Button variant="outline" size="sm" onClick={handleApplica} disabled={applicaMut.isPending}>
            <Play className="h-4 w-4 mr-1.5" />
            {applicaMut.isPending ? "Applicando..." : "Applica Tutte"}
          </Button>
          <Button size="sm" onClick={openCreate}>
            <Plus className="h-4 w-4 mr-1.5" />
            Nuova Regola
          </Button>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-3 gap-4">
        {[
          { label: "Regole Attive", value: regole.filter(r => r.attiva).length, color: "text-emerald-400" },
          { label: "Regole Totali", value: regole.length, color: "text-foreground" },
          { label: "Match Totali", value: regole.reduce((s, r) => s + (r.contatore_match ?? 0), 0), color: "text-primary" },
        ].map(s => (
          <div key={s.label} className="rounded-xl border border-border bg-card/50 p-4">
            <p className="text-xs text-muted-foreground font-bold uppercase tracking-widest">{s.label}</p>
            <p className={`text-2xl font-black mt-1 ${s.color}`}>{s.value}</p>
          </div>
        ))}
      </div>

      {/* Table */}
      <div className="rounded-xl border border-border overflow-hidden">
        <Table>
          <TableHeader>
            <TableRow className="bg-muted/30">
              <TableHead className="text-xs font-black uppercase tracking-widest w-12">#</TableHead>
              <TableHead className="text-xs font-black uppercase tracking-widest">Nome</TableHead>
              <TableHead className="text-xs font-black uppercase tracking-widest">Pattern</TableHead>
              <TableHead className="text-xs font-black uppercase tracking-widest">Tipo Match</TableHead>
              <TableHead className="text-xs font-black uppercase tracking-widest">Categoria</TableHead>
              <TableHead className="text-xs font-black uppercase tracking-widest">Auto</TableHead>
              <TableHead className="text-xs font-black uppercase tracking-widest">Match</TableHead>
              <TableHead className="text-xs font-black uppercase tracking-widest">Stato</TableHead>
              <TableHead className="w-10" />
            </TableRow>
          </TableHeader>
          <TableBody>
            {isLoading ? (
              Array.from({ length: 4 }).map((_, i) => (
                <TableRow key={i}>
                  {Array.from({ length: 9 }).map((_, j) => (
                    <TableCell key={j}><div className="h-4 bg-muted/40 rounded animate-pulse" /></TableCell>
                  ))}
                </TableRow>
              ))
            ) : sortedRegole.length === 0 ? (
              <TableRow>
                <TableCell colSpan={9} className="text-center py-12 text-muted-foreground text-sm">
                  Nessuna regola. Crea la prima con "+ Nuova Regola".
                </TableCell>
              </TableRow>
            ) : (
              sortedRegole.map((r) => (
                <TableRow key={r.id} className={!r.attiva ? "opacity-40" : ""}>
                  <TableCell className="font-mono text-xs text-muted-foreground">{r.priorita}</TableCell>
                  <TableCell className="font-bold text-sm">{r.nome}</TableCell>
                  <TableCell>
                    <code className="text-xs bg-muted px-1.5 py-0.5 rounded font-mono">{r.pattern}</code>
                  </TableCell>
                  <TableCell>
                    <Badge variant="outline" className="text-[10px] uppercase font-black">
                      {r.tipo_match}
                    </Badge>
                  </TableCell>
                  <TableCell className="text-xs font-bold text-muted-foreground">{r.categoria || "—"}</TableCell>
                  <TableCell>
                    {r.auto_riconcilia ? (
                      <Badge className="bg-emerald-500/10 text-emerald-400 border-emerald-500/20 text-[10px] font-black">AUTO</Badge>
                    ) : (
                      <Badge variant="outline" className="text-[10px] font-black text-muted-foreground">SUGGERITO</Badge>
                    )}
                  </TableCell>
                  <TableCell className="font-mono text-sm font-bold">{r.contatore_match ?? 0}</TableCell>
                  <TableCell>
                    <button onClick={() => toggleAttiva(r)} className="text-muted-foreground hover:text-foreground transition-colors">
                      {r.attiva
                        ? <ToggleRight className="h-5 w-5 text-emerald-400" />
                        : <ToggleLeft className="h-5 w-5" />
                      }
                    </button>
                  </TableCell>
                  <TableCell>
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button variant="ghost" size="icon" className="h-7 w-7">
                          <MoreHorizontal className="h-4 w-4" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuItem onClick={() => openEdit(r)}>
                          <Edit2 className="h-3.5 w-3.5 mr-2" /> Modifica
                        </DropdownMenuItem>
                        <DropdownMenuSeparator />
                        <DropdownMenuItem
                          className="text-destructive focus:text-destructive"
                          onClick={() => handleDelete(r.id)}
                        >
                          <Trash2 className="h-3.5 w-3.5 mr-2" /> Elimina
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>

      {/* Dialog Crea/Modifica */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle className="font-black">
              {editTarget ? "Modifica Regola" : "Nuova Regola"}
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div className="grid grid-cols-2 gap-4">
              <div className="col-span-2 space-y-1.5">
                <Label className="text-xs font-black uppercase tracking-widest">Nome *</Label>
                <Input
                  placeholder="Es: Pagamento Aruba hosting"
                  value={form.nome}
                  onChange={e => setForm(f => ({ ...f, nome: e.target.value }))}
                />
              </div>
              <div className="col-span-2 space-y-1.5">
                <Label className="text-xs font-black uppercase tracking-widest">Pattern *</Label>
                <Input
                  placeholder="Es: ARUBA S.P.A."
                  value={form.pattern}
                  onChange={e => setForm(f => ({ ...f, pattern: e.target.value }))}
                  className="font-mono"
                />
              </div>
              <div className="space-y-1.5">
                <Label className="text-xs font-black uppercase tracking-widest">Tipo Match</Label>
                <Select
                  value={form.tipo_match}
                  onValueChange={v => setForm(f => ({ ...f, tipo_match: v as any }))}
                >
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="contains">Contains</SelectItem>
                    <SelectItem value="startswith">Starts With</SelectItem>
                    <SelectItem value="endswith">Ends With</SelectItem>
                    <SelectItem value="regex">Regex</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-1.5">
                <Label className="text-xs font-black uppercase tracking-widest">Categoria</Label>
                <Select
                  value={form.categoria || ""}
                  onValueChange={v => setForm(f => ({ ...f, categoria: v }))}
                >
                  <SelectTrigger><SelectValue placeholder="Seleziona..." /></SelectTrigger>
                  <SelectContent>
                    {CATEGORIE_PREDEFINITE.map(c => (
                      <SelectItem key={c} value={c}>{c}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-1.5">
                <Label className="text-xs font-black uppercase tracking-widest">Priorità</Label>
                <Input
                  type="number"
                  min={0}
                  value={form.priorita}
                  onChange={e => setForm(f => ({ ...f, priorita: Number(e.target.value) }))}
                  placeholder="0 = bassa, 100 = alta"
                />
              </div>
              <div className="space-y-1.5">
                <Label className="text-xs font-black uppercase tracking-widest">Fornitore</Label>
                <Select
                  value={form.fornitore_id || "none"}
                  onValueChange={v => setForm(f => ({ ...f, fornitore_id: v === "none" ? undefined : v }))}
                >
                  <SelectTrigger><SelectValue placeholder="Nessuno" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Nessuno</SelectItem>
                    {(fornitori as any[]).map((f: any) => (
                      <SelectItem key={f.id} value={f.id}>{f.ragione_sociale}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="col-span-2 flex items-center justify-between rounded-lg border border-border p-3">
                <div>
                  <p className="text-sm font-bold">Auto Riconcilia</p>
                  <p className="text-xs text-muted-foreground">Applica automaticamente senza conferma</p>
                </div>
                <Switch
                  checked={form.auto_riconcilia}
                  onCheckedChange={v => setForm(f => ({ ...f, auto_riconcilia: v }))}
                />
              </div>
              <div className="col-span-2 flex items-center justify-between rounded-lg border border-border p-3">
                <div>
                  <p className="text-sm font-bold">Regola Attiva</p>
                  <p className="text-xs text-muted-foreground">Le regole inattive vengono ignorate</p>
                </div>
                <Switch
                  checked={form.attiva}
                  onCheckedChange={v => setForm(f => ({ ...f, attiva: v }))}
                />
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>Annulla</Button>
            <Button onClick={handleSave} disabled={createMut.isPending || updateMut.isPending}>
              {editTarget ? "Salva Modifiche" : "Crea Regola"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Sheet Dry-Run */}
      <Sheet open={dryRunSheet} onOpenChange={setDryRunSheet}>
        <SheetContent className="w-[560px] sm:max-w-[560px]">
          <SheetHeader>
            <SheetTitle className="font-black flex items-center gap-2">
              <Eye className="h-5 w-5 text-primary" />
              Preview — {dryRunData.length} movimenti verranno processati
            </SheetTitle>
          </SheetHeader>
          <div className="mt-4 space-y-2 overflow-y-auto max-h-[calc(100vh-140px)]">
            {dryRunData.length === 0 ? (
              <p className="text-sm text-muted-foreground py-8 text-center">
                Nessun movimento matcha le regole attive al momento.
              </p>
            ) : (
              dryRunData.map((item, i) => (
                <div key={i} className="rounded-xl border border-border p-3 space-y-1.5">
                  <div className="flex items-start justify-between gap-2">
                    <p className="text-sm font-bold truncate">{item.movimento_descrizione || "—"}</p>
                    <Badge
                      className={item.azione === "RICONCILIA_AUTO"
                        ? "bg-emerald-500/10 text-emerald-400 border-emerald-500/20 shrink-0 text-[10px] font-black"
                        : "shrink-0 text-[10px] font-black"
                      }
                    >
                      {item.azione === "RICONCILIA_AUTO" ? "AUTO" : "CATEGORIZZA"}
                    </Badge>
                  </div>
                  <div className="flex items-center gap-3 text-xs text-muted-foreground">
                    <span className="font-mono font-bold">€{item.movimento_importo?.toFixed(2)}</span>
                    <span>→ Regola: <strong className="text-foreground">{item.regola_nome}</strong></span>
                    {item.categoria_prevista && (
                      <Badge variant="outline" className="text-[10px] font-black">{item.categoria_prevista}</Badge>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        </SheetContent>
      </Sheet>
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from "@/components/ui/card";
import { Lock, Loader2, CheckCircle2, AlertCircle, Eye, EyeOff } from "lucide-react";
import { Link, useSearchParams, useNavigate } from "react-router-dom";
import { toast } from "sonner";
import api from "@/lib/api";

export default function ResetPasswordPage() {
  const [searchParams] = useSearchParams();
  const token = searchParams.get("token");
  const navigate = useNavigate();

  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Forza password semplice: min 8 caratteri
  const [strength, setStrength] = useState(0);

  useEffect(() => {
    let s = 0;
    if (password.length >= 8) s += 25;
    if (/[A-Z]/.test(password)) s += 25;
    if (/[0-9]/.test(password)) s += 25;
    if (/[^A-Za-z0-9]/.test(password)) s += 25;
    setStrength(s);
  }, [password]);

  if (!token) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background p-4">
        <Card className="w-full max-w-md bg-card/50 backdrop-blur-xl border-border/50 text-center p-8">
          <AlertCircle className="w-12 h-12 text-destructive mx-auto mb-4" />
          <h2 className="text-xl font-bold mb-2">Token Mancante</h2>
          <p className="text-sm text-muted-foreground mb-6">Il link di reset non è valido o è incompleto.</p>
          <Button asChild className="w-full">
            <Link to="/forgot-password">Richiedi un nuovo link</Link>
          </Button>
        </Card>
      </div>
    );
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (password !== confirmPassword) {
      setError("Le password non coincidono.");
      return;
    }
    if (password.length < 8) {
      setError("La password deve essere di almeno 8 caratteri.");
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      await api.post("/api/v1/auth/reset-password", { token, new_password: password });
      setIsSuccess(true);
      toast.success("Password reimpostata con successo!");
      setTimeout(() => navigate("/login"), 3000);
    } catch (err: any) {
      setError(err.response?.data?.detail || "Token scaduto o non valido. Riprova il recupero.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-background p-4 relative overflow-hidden">
      {/* Background decoration */}
      <div className="absolute top-[20%] left-[20%] w-[30%] h-[30%] rounded-full bg-primary/10 blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[20%] right-[20%] w-[30%] h-[30%] rounded-full bg-primary/10 blur-[100px] pointer-events-none" />

      <Card className="w-full max-w-md bg-card/50 backdrop-blur-xl border-border/50 shadow-2xl relative animate-in fade-in zoom-in duration-500">
        <CardHeader className="space-y-2 text-center pb-8">
          <div className="mx-auto mb-6 relative group">
            <div className="absolute -inset-4 bg-primary/10 rounded-full blur-3xl opacity-50 group-hover:opacity-100 transition duration-1000" />
            <img 
              src="/logo_bite.jpg" 
              alt="Bite Digital" 
              className="relative max-w-[200px] h-auto mx-auto drop-shadow-[0_10px_20px_rgba(0,0,0,0.5)] group-hover:scale-105 transition-transform duration-700" 
            />
          </div>
          <CardTitle className="text-3xl font-bold tracking-tight">Nuova Password</CardTitle>
          <CardDescription className="text-muted-foreground">
            Imposta una password sicura per il tuo account.
          </CardDescription>
        </CardHeader>

        {!isSuccess ? (
          <form onSubmit={handleSubmit}>
            <CardContent className="space-y-4">
              {error && (
                <div className="p-3 rounded-lg bg-destructive/10 border border-destructive/20 flex items-center space-x-3 text-destructive animate-in slide-in-from-bottom-2">
                  <AlertCircle className="w-4 h-4 shrink-0" />
                  <p className="text-xs font-medium">{error}</p>
                </div>
              )}
              <div className="space-y-4">
                <div className="relative">
                  <Lock className="absolute left-3 top-3 w-4 h-4 text-muted-foreground" />
                  <Input
                    type={showPassword ? "text" : "password"}
                    placeholder="Nuova password"
                    className="pl-10 pr-10 bg-background/50"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    required
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-3 top-3 text-muted-foreground hover:text-foreground"
                  >
                    {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                  </button>
                </div>

                <div className="relative">
                  <Lock className="absolute left-3 top-3 w-4 h-4 text-muted-foreground" />
                  <Input
                    type="password"
                    placeholder="Conferma password"
                    className="pl-10 bg-background/50"
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    required
                  />
                </div>

                {/* Password strength bar */}
                <div className="space-y-1.5 pt-2">
                  <div className="flex justify-between text-[10px] uppercase font-black tracking-widest text-muted-foreground">
                    <span>Sicurezza password</span>
                    <span>{strength}%</span>
                  </div>
                  <div className="h-1 w-full bg-muted rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-500 rounded-full ${
                        strength < 50 ? "bg-destructive" : strength < 100 ? "bg-yellow-500" : "bg-green-500"
                      }`}
                      style={{ width: `${strength}%` }}
                    />
                  </div>
                </div>
              </div>
            </CardContent>
            <CardFooter className="pt-4 flex flex-col space-y-4">
              <Button 
                type="submit" 
                className="w-full shadow-lg shadow-[0_0_20px_hsl(var(--primary)/0.2)]" 
                disabled={isLoading || password.length < 8}
              >
                {isLoading ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Reimpostazione in corso...
                  </>
                ) : (
                  "Salva nuova password"
                )}
              </Button>
            </CardFooter>
          </form>
        ) : (
          <CardContent className="space-y-6 pb-8 text-center animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="mx-auto w-16 h-16 bg-green-500/10 rounded-full flex items-center justify-center text-green-500 mb-4">
              <CheckCircle2 className="w-10 h-10" />
            </div>
            <div className="space-y-2">
              <p className="text-lg font-bold text-foreground">Password Aggiornata!</p>
              <p className="text-sm text-muted-foreground">
                La tua password è stata reimpostata correttamente. Verrai reindirizzato al login tra pochi secondi.
              </p>
            </div>
            <Button asChild variant="outline" className="w-full mt-4">
              <Link to="/login">Vai al login ora</Link>
            </Button>
          </CardContent>
        )}
      </Card>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import api from "@/lib/api";
import type { CategoriaFornitore } from "@/types";
import { 
  Plus, Edit2, Trash2, Tag, 
  ChevronLeft
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { 
  Dialog, DialogContent, DialogHeader,
  DialogTitle, DialogDescription, DialogFooter
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";
import { useNavigate } from "react-router-dom";

export default function SupplierCategoryManager() {
  const queryClient = useQueryClient();
  const navigate = useNavigate();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedCat, setSelectedCat] = useState<Partial<CategoriaFornitore> | null>(null);

  // Queries
  const { data: categorie = [], isLoading } = useQuery<CategoriaFornitore[]>({
    queryKey: ["categorie-fornitori"],
    queryFn: async () => {
      const { data } = await api.get("/categorie-fornitori");
      return data;
    },
  });

  // Mutations
  const upsertMutation = useMutation({
    mutationFn: async (data: Partial<CategoriaFornitore>) => {
      if (data.id) {
        return api.patch(`/categorie-fornitori/${data.id}`, data);
      }
      return api.post("/categorie-fornitori", data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["categorie-fornitori"] });
      setIsModalOpen(false);
      toast.success("Categoria salvata");
    },
    onError: () => {
      toast.error("Errore durante il salvataggio");
    }
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      return api.delete(`/categorie-fornitori/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["categorie-fornitori"] });
      toast.success("Categoria eliminata");
    },
    onError: (err: any) => {
      toast.error(err.response?.data?.detail || "Errore durante l'eliminazione");
    }
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedCat) {
      upsertMutation.mutate(selectedCat);
    }
  };

  const openEdit = (c: CategoriaFornitore) => {
    setSelectedCat(c);
    setIsModalOpen(true);
  };

  const openCreate = () => {
    setSelectedCat({ nome: "", colore: "#3b82f6" });
    setIsModalOpen(true);
  };

  return (
    <div className="p-8 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center gap-4 mb-2">
        <Button variant="ghost" size="icon" onClick={() => navigate("/fornitori")}>
          <ChevronLeft className="w-5 h-5" />
        </Button>
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Gestione Categorie Fornitori</h1>
          <p className="text-muted-foreground text-sm">Personalizza le etichette per organizzare i tuoi fornitori.</p>
        </div>
      </div>

      <div className="bg-card/30 border border-white/5 rounded-2xl p-6 backdrop-blur-md">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-2 text-primary">
            <Tag className="w-5 h-5" />
            <span className="font-semibold">{categorie.length} Categorie Configurate</span>
          </div>
          <Button onClick={openCreate} className="bg-primary/20 text-primary border border-primary/30 hover:bg-primary/30">
            <Plus className="w-4 h-4 mr-2" />
            Aggiungi Categoria
          </Button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {isLoading ? (
            Array.from({ length: 4 }).map((_, i) => (
              <div key={i} className="h-20 bg-white/5 rounded-xl animate-pulse" />
            ))
          ) : categorie.map((cat) => (
            <div 
              key={cat.id} 
              className="group relative flex items-center justify-between p-4 bg-white/5 rounded-xl border border-white/5 hover:border-primary/30 transition-all hover:bg-white/10"
            >
              <div className="flex items-center gap-4">
                <div 
                  className="w-10 h-10 rounded-lg flex items-center justify-center shadow-lg"
                  style={{ backgroundColor: `${cat.colore}20`, border: `1px solid ${cat.colore}40` }}
                >
                  <Tag className="w-5 h-5" style={{ color: cat.colore }} />
                </div>
                <div className="flex flex-col">
                  <span className="font-medium text-lg text-white/90">{cat.nome}</span>
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full" style={{ backgroundColor: cat.colore }} />
                    <span className="text-[10px] text-muted-foreground font-mono tracking-tighter uppercase">{cat.colore}</span>
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                <Button variant="ghost" size="icon" className="h-8 w-8 hover:bg-primary/20 hover:text-primary" onClick={() => openEdit(cat)}>
                  <Edit2 className="w-4 h-4" />
                </Button>
                <Button 
                  variant="ghost" 
                  size="icon" 
                  className="h-8 w-8 hover:bg-destructive/20 hover:text-destructive"
                  onClick={() => {
                    if (confirm(`Eliminare la categoria "${cat.nome}"? I fornitori associati resteranno senza categoria.`)) {
                      deleteMutation.mutate(cat.id);
                    }
                  }}
                >
                  <Trash2 className="w-4 h-4" />
                </Button>
              </div>
            </div>
          ))}
        </div>

        {categorie.length === 0 && !isLoading && (
          <div className="text-center py-12 text-muted-foreground border-2 border-dashed border-white/5 rounded-xl">
            Nessuna categoria personalizzata. Aggiungine una per iniziare.
          </div>
        )}
      </div>

      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent className="sm:max-w-[400px] bg-card border-white/10">
          <DialogHeader>
            <DialogTitle>{selectedCat?.id ? "Modifica Categoria" : "Nuova Categoria"}</DialogTitle>
            <DialogDescription>Definisci il nome e il colore identificativo.</DialogDescription>
          </DialogHeader>
          <form onSubmit={handleSubmit} className="space-y-6 py-4">
            <div className="space-y-4">
              <div className="space-y-2">
                <Label>Nome Categoria</Label>
                <Input 
                  value={selectedCat?.nome || ""} 
                  onChange={e => setSelectedCat(prev => ({ ...prev!, nome: e.target.value }))}
                  placeholder="Es: Software, Marketing, Utilities..."
                  required
                />
              </div>
              <div className="space-y-2">
                <Label>Colore</Label>
                <div className="flex items-center gap-4">
                  <div 
                    className="w-12 h-12 rounded-xl shadow-inner border border-white/10"
                    style={{ backgroundColor: selectedCat?.colore }}
                  />
                  <Input 
                    type="color" 
                    className="h-12 flex-1 cursor-pointer bg-transparent border-white/10"
                    value={selectedCat?.colore || "#3b82f6"}
                    onChange={e => setSelectedCat(prev => ({ ...prev!, colore: e.target.value }))}
                  />
                </div>
              </div>
            </div>
            <DialogFooter>
              <Button type="button" variant="ghost" onClick={() => setIsModalOpen(false)}>Annulla</Button>
              <Button type="submit" disabled={upsertMutation.isPending}>
                {upsertMutation.isPending ? "Salvataggio..." : "Salva Categoria"}
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import React, { useState } from "react";
import { useMutation } from "@tanstack/react-query";
import axios from "axios";
import { toast } from "sonner";
import { 
  KeyRound, 
  Globe, 
  Lock, 
  Eye, 
  EyeOff, 
  ShieldCheck, 
  Save,
  Loader2,
  CheckCircle2,
  XCircle
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { cn } from "@/lib/utils";

const passwordRequirements = [
  { id: 'length', label: 'Almeno 8 caratteri', regex: /.{8,}/ },
  { id: 'number', label: 'Almeno un numero', regex: /[0-9]/ },
  { id: 'special', label: 'Almeno un carattere speciale (!@#$%^&*)', regex: /[!@#$%^&*]/ },
];

export default function AccountSettings() {
  const [showPassword, setShowPassword] = useState(false);
  const [passwords, setPasswords] = useState({
    current: "",
    new: "",
    confirm: "",
  });

  const [regional, setRegional] = useState(() => {
    const saved = localStorage.getItem("bite_erp_regional_settings");
    return saved ? JSON.parse(saved) : {
      currency: "EUR",
      dateFormat: "DD/MM/YYYY",
      timeZone: "Europe/Rome"
    };
  });

  const changePasswordMutation = useMutation({
    mutationFn: async (data: any) => {
      // In un backend reale verificheremmo anche la password corrente
      // Per ora usiamo PATCH /users/me
      const response = await axios.patch("/api/v1/users/me", {
        password: data.new
      });
      return response.data;
    },
    onSuccess: () => {
      toast.success("Password aggiornata correttamente");
      setPasswords({ current: "", new: "", confirm: "" });
    },
    onError: (error: any) => {
      toast.error(error.response?.data?.detail || "Errore durante il cambio password");
    },
  });

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwords.new !== passwords.confirm) {
      toast.error("Le password non coincidono");
      return;
    }
    if (!passwordRequirements.every(req => req.regex.test(passwords.new))) {
      toast.error("La password non soddisfa i requisiti di sicurezza");
      return;
    }
    changePasswordMutation.mutate(passwords);
  };

  const handleRegionalSave = () => {
    localStorage.setItem("bite_erp_regional_settings", JSON.stringify(regional));
    toast.success("Impostazioni regionali salvate");
    window.dispatchEvent(new Event('regional-settings-changed'));
  };

  return (
    <div className="space-y-10 pb-10">
      {/* Sezione Sicurezza */}
      <section className="space-y-6">
        <div>
          <h2 className="text-xl font-bold text-white flex items-center gap-2">
            <Lock className="h-5 w-5 text-primary" />
            Sicurezza Account
          </h2>
          <p className="text-sm text-muted-foreground">
            Proteggi il tuo account aggiornando regolarmente la password.
          </p>
        </div>

        <form onSubmit={handlePasswordSubmit} className="space-y-8 p-6 rounded-2xl bg-muted/30 border border-border/50">
          <div className="grid gap-6">
             {/* Password Corrente (Placeholder se serve verifica) */}
            <div className="space-y-2">
              <Label htmlFor="current">Password Corrente</Label>
              <div className="relative">
                <Input
                  id="current"
                  type={showPassword ? "text" : "password"}
                  value={passwords.current}
                  onChange={(e) => setPasswords({ ...passwords, current: e.target.value })}
                  placeholder="••••••••"
                  className="pl-10 pr-10"
                />
                <KeyRound className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-white"
                >
                  {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                </button>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <Label htmlFor="new">Nuova Password</Label>
                <div className="relative">
                  <Input
                    id="new"
                    type={showPassword ? "text" : "password"}
                    value={passwords.new}
                    onChange={(e) => setPasswords({ ...passwords, new: e.target.value })}
                    placeholder="Nuova password"
                    className="pl-10"
                  />
                  <ShieldCheck className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                </div>
              </div>
              <div className="space-y-2">
                <Label htmlFor="confirm">Conferma Password</Label>
                <div className="relative">
                  <Input
                    id="confirm"
                    type={showPassword ? "text" : "password"}
                    value={passwords.confirm}
                    onChange={(e) => setPasswords({ ...passwords, confirm: e.target.value })}
                    placeholder="Conferma password"
                    className="pl-10"
                  />
                  <ShieldCheck className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                </div>
              </div>
            </div>

            {/* Requisiti */}
            <div className="flex flex-wrap gap-4 p-4 rounded-xl bg-background/50 border border-border/50">
              {passwordRequirements.map((req) => {
                const isValid = req.regex.test(passwords.new);
                return (
                  <div key={req.id} className="flex items-center gap-2 text-[11px] font-medium">
                    {isValid ? (
                      <CheckCircle2 className="h-3.5 w-3.5 text-green-500" />
                    ) : (
                      <XCircle className="h-3.5 w-3.5 text-muted-foreground/50" />
                    )}
                    <span className={cn(isValid ? "text-green-500" : "text-muted-foreground")}>
                      {req.label}
                    </span>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="flex justify-end">
            <Button 
              type="submit" 
              disabled={changePasswordMutation.isPending || !passwords.new || passwords.new !== passwords.confirm}
              className="gap-2"
            >
              {changePasswordMutation.isPending ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <Save className="h-4 w-4" />
              )}
              Aggiorna Password
            </Button>
          </div>
        </form>
      </section>

      {/* Sezione Regionali */}
      <section className="space-y-6">
        <div>
          <h2 className="text-xl font-bold text-white flex items-center gap-2">
            <Globe className="h-5 w-5 text-primary" />
            Preferenze Regionali
          </h2>
          <p className="text-sm text-muted-foreground">
            Scegli come visualizzare i dati finanziari e le date nel sistema.
          </p>
        </div>

        <div className="space-y-6 p-6 rounded-2xl bg-muted/30 border border-border/50">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            <div className="space-y-2">
              <Label>Valuta Principale</Label>
              <select 
                className="w-full bg-background border border-input rounded-xl px-3 py-2 text-sm focus:ring-1 focus:ring-primary outline-none"
                value={regional.currency}
                onChange={(e) => setRegional({...regional, currency: e.target.value})}
              >
                <option value="EUR">Euro (€)</option>
                <option value="USD">Dollar (US$)</option>
                <option value="GBP">Pound (£)</option>
              </select>
            </div>
            <div className="space-y-2">
              <Label>Formato Data</Label>
              <select 
                className="w-full bg-background border border-input rounded-xl px-3 py-2 text-sm focus:ring-1 focus:ring-primary outline-none"
                value={regional.dateFormat}
                onChange={(e) => setRegional({...regional, dateFormat: e.target.value})}
              >
                <option value="DD/MM/YYYY">DD/MM/YYYY (Italia)</option>
                <option value="YYYY-MM-DD">YYYY-MM-DD (ISO)</option>
                <option value="MM/DD/YYYY">MM/DD/YYYY (US)</option>
              </select>
            </div>
            <div className="space-y-2">
              <Label>Fuso Orario</Label>
              <select 
                className="w-full bg-background border border-input rounded-xl px-3 py-2 text-sm focus:ring-1 focus:ring-primary outline-none"
                value={regional.timeZone}
                onChange={(e) => setRegional({...regional, timeZone: e.target.value})}
              >
                <option value="Europe/Rome">Europe/Rome (CET)</option>
                <option value="Europe/London">Europe/London (GMT)</option>
                <option value="America/New_York">America/New_York (EST)</option>
              </select>
            </div>
          </div>

          <div className="flex justify-end pt-4 border-t border-border/50">
            <Button onClick={handleRegionalSave} className="gap-2">
              <Save className="h-4 w-4" />
              Salva Preferenze
            </Button>
          </div>
        </div>
      </section>
    </div>
  );
}

