/** Maps both DB enum values AND legacy ClickUp-style IDs to a StudioStatus. */
export function getTaskState(stateId: string): StudioStatus {
  return (
    DEFAULT_STATES.find((s) => s.id === stateId) ??
    DEFAULT_STATES[0]
  );
}

